-- Migration: Seed V3 series — 300 questions (30 series × 10 questions)
-- Batch A: series 01–10 (UUID prefix a3), Batch B: series 01–10 (prefix b3), Batch C: series 01–10 (prefix c3)

ALTER TABLE public.exercises ADD COLUMN IF NOT EXISTS common_mistake text;

INSERT INTO public.exercises (id, subject, subdomain, topic_key, topic_label, level, exercise_type, instruction, support_text, choices, expected_answer, detailed_explanation, common_mistake, validation_status, source, access_tier, is_published) VALUES

-- ─── Batch A — Série 01 : Phrase complexe : coordination et juxtaposition ───
('a3010000-0000-0000-0000-000000000001', 'Francais', 'grammaire', 'phrase_complexe_coord', 'Phrase complexe : coordination et juxtaposition', 'Intermediaire', 'qcm', 'Quelle est la nature du lien entre les deux propositions dans la phrase : « Il pleuvait ; nous sommes restés à l''intérieur » ?', NULL, '[{"id":"a","label":"Coordination par la conjonction ''car''"},{"id":"b","label":"Juxtaposition"},{"id":"c","label":"Subordination"},{"id":"d","label":"Coordination par l''adverbe ''donc''"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'Les deux propositions sont simplement séparées par un point-virgule, sans mot de liaison grammatical. Il s''agit donc d''une juxtaposition. La juxtaposition implique un rapport de sens (ici, une relation de cause à conséquence implicite), mais ce rapport n''est pas marqué par un mot grammatical.', 'Certains candidats confondent la juxtaposition avec la subordination, ou tentent de restituer une conjonction là où il n''y en a pas. Le point-virgule est le signe caractéristique de la juxtaposition entre deux propositions de même niveau.', 'valide', 'CRPE Français V3', 'free', true),

('a3010000-0000-0000-0000-000000000002', 'Francais', 'grammaire', 'phrase_complexe_coord', 'Phrase complexe : coordination et juxtaposition', 'Intermediaire', 'qcm', 'Dans « Elle travaille dur, or elle n''obtient pas les résultats espérés », quelle est la valeur sémantique de la conjonction ''or'' ?', NULL, '[{"id":"a","label":"Addition"},{"id":"b","label":"Cause"},{"id":"c","label":"Opposition ou restriction logique"},{"id":"d","label":"Conséquence"}]'::jsonb, '{"mode":"single_choice","value":"c"}'::jsonb, '''Or'' est une conjonction de coordination qui introduit une restriction ou une nuance logique par rapport à ce qui précède. Elle ne marque pas une simple opposition mais une donnée nouvelle qui contredit ou nuance la première proposition. Elle est souvent utilisée dans un raisonnement de type syllogistique.', 'Les candidats confondent parfois ''or'' avec ''mais'' (opposition directe) ou avec une conjonction de cause. ''Or'' a une valeur logique particulière : il introduit un fait qui vient contredire ou compliquer ce qui a été affirmé.', 'valide', 'CRPE Français V3', 'free', true),

('a3010000-0000-0000-0000-000000000003', 'Francais', 'grammaire', 'phrase_complexe_coord', 'Phrase complexe : coordination et juxtaposition', 'Intermediaire', 'qcm', 'Combien de propositions contient la phrase : « Le vent soufflait, la pluie tombait et les arbres ployaient » ?', NULL, '[{"id":"a","label":"Deux"},{"id":"b","label":"Trois"},{"id":"c","label":"Quatre"},{"id":"d","label":"Une seule"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'La phrase contient trois propositions indépendantes : « Le vent soufflait » (juxtaposée), « la pluie tombait » (juxtaposée), et « les arbres ployaient » (coordonnée par ''et''). Chaque proposition possède son propre sujet et son propre verbe conjugué.', 'Les candidats oublient parfois de compter la première proposition juxtaposée et n''identifient que les deux dernières reliées par ''et''. Il faut repérer chaque groupe sujet + verbe conjugué pour compter les propositions.', 'valide', 'CRPE Français V3', 'free', true),

('a3010000-0000-0000-0000-000000000004', 'Francais', 'grammaire', 'phrase_complexe_coord', 'Phrase complexe : coordination et juxtaposition', 'Intermediaire', 'vrai_faux', 'Dans une phrase complexe par juxtaposition, le lien logique entre les propositions est toujours explicitement marqué par un mot grammatical.', NULL, NULL, '{"mode":"boolean","value":false}'::jsonb, 'C''est faux. La juxtaposition se définit précisément par l''absence de mot de liaison grammatical : les propositions sont reliées uniquement par la ponctuation (virgule, point-virgule, deux-points). Le rapport logique (cause, conséquence, opposition…) est implicite et doit être inféré par le lecteur.', 'Nombreux sont les candidats qui pensent que tout lien logique doit être explicite. Or la juxtaposition repose sur l''implicite : le sens émerge du contexte et de la ponctuation, sans mot de liaison.', 'valide', 'CRPE Français V3', 'free', true),

('a3010000-0000-0000-0000-000000000005', 'Francais', 'grammaire', 'phrase_complexe_coord', 'Phrase complexe : coordination et juxtaposition', 'Intermediaire', 'qcm', 'Dans « Je viendrai, mais je ne resterai pas longtemps », quelle est la valeur de ''mais'' ?', NULL, '[{"id":"a","label":"Addition"},{"id":"b","label":"Opposition ou restriction"},{"id":"c","label":"Cause"},{"id":"d","label":"Alternative"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, '''Mais'' est la conjonction de coordination exprimant l''opposition ou la restriction. Elle relie deux propositions dont la seconde apporte une limitation ou une nuance par rapport à la première. Ici, la venue est confirmée mais assortie d''une réserve (durée limitée).', 'Certains candidats distinguent mal ''mais'' (opposition/restriction) de ''or'' (restriction logique plus formelle). ''Mais'' exprime une opposition directe entre deux faits ou deux volontés.', 'valide', 'CRPE Français V3', 'free', true),

('a3010000-0000-0000-0000-000000000006', 'Francais', 'grammaire', 'phrase_complexe_coord', 'Phrase complexe : coordination et juxtaposition', 'Intermediaire', 'vrai_faux', 'La conjonction ''car'' introduit une proposition qui exprime la conséquence de la proposition précédente.', NULL, NULL, '{"mode":"boolean","value":false}'::jsonb, 'C''est faux. ''Car'' introduit la cause, non la conséquence. Dans « Il est absent, car il est malade », la maladie est la cause de l''absence. La conséquence est exprimée par ''donc'' : « Il est malade, donc il est absent ». Cette confusion est très fréquente.', 'L''erreur classique est d''inverser ''car'' (cause) et ''donc'' (conséquence). Un moyen de vérification : ''car'' peut toujours être remplacé par ''parce que'', qui introduit bien la cause.', 'valide', 'CRPE Français V3', 'free', true),

('a3010000-0000-0000-0000-000000000007', 'Francais', 'grammaire', 'phrase_complexe_coord', 'Phrase complexe : coordination et juxtaposition', 'Intermediaire', 'reponse_courte', 'Quel terme désigne le procédé consistant à relier des propositions par un mot de liaison grammatical (conjonction) plutôt que par la seule ponctuation ?', NULL, NULL, '{"mode":"text","acceptableAnswers":["hypotaxe","parataxe","coordination","hypotaxe ou coordination"]}'::jsonb, 'On parle de parataxe lorsque les propositions sont juxtaposées (liées par la seule ponctuation), et d''hypotaxe lorsqu''elles sont reliées par un mot de liaison (conjonction de coordination ou de subordination). La coordination est un cas particulier d''hypotaxe, où le lien est assuré par une conjonction de coordination.', 'Les candidats confondent souvent parataxe et hypotaxe. Moyen mnémotechnique : ''para'' = à côté (les propositions sont placées côte à côte sans lien grammatical) ; ''hypo'' = sous (une proposition est subordonnée à l''autre, ou liée par un mot grammatical).', 'valide', 'CRPE Français V3', 'free', true),

('a3010000-0000-0000-0000-000000000008', 'Francais', 'grammaire', 'phrase_complexe_coord', 'Phrase complexe : coordination et juxtaposition', 'Intermediaire', 'qcm', 'Laquelle de ces phrases est une phrase SIMPLE (une seule proposition) ?', NULL, '[{"id":"a","label":"Il chante et il danse."},{"id":"b","label":"Malgré la pluie, il est sorti."},{"id":"c","label":"Il pense que tu as raison."},{"id":"d","label":"Il est parti, puis il est revenu."}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, '« Malgré la pluie, il est sorti » est une phrase simple : elle ne contient qu''un seul verbe conjugué (''est sorti''), donc une seule proposition. ''Malgré la pluie'' est un groupe nominal prépositionnel circonstanciel, non une proposition. Les autres phrases contiennent deux verbes conjugués chacune, donc deux propositions.', 'Les candidats identifient parfois un groupe nominal circonstanciel comme une proposition. Une proposition doit contenir un verbe conjugué. Un groupe introduit par une préposition (malgré, avant, après) n''est pas une proposition.', 'valide', 'CRPE Français V3', 'free', true),

('a3010000-0000-0000-0000-000000000009', 'Francais', 'grammaire', 'phrase_complexe_coord', 'Phrase complexe : coordination et juxtaposition', 'Intermediaire', 'vrai_faux', 'Les propositions coordonnées par ''ni'' ont obligatoirement une valeur négative.', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'C''est vrai. ''Ni'' est la conjonction de coordination négative, équivalent négatif de ''et''. Elle coordonne des propositions ou des éléments dans un contexte négatif : « Il ne mange ni ne dort » (il ne fait ni l''un ni l''autre). Elle suppose généralement la présence d''une négation dans la phrase.', 'Certains candidats oublient que ''ni'' appartient au champ négatif et tentent de l''utiliser dans des contextes affirmatifs. ''Ni'' implique toujours une double négation.', 'valide', 'CRPE Français V3', 'free', true),

('a3010000-0000-0000-0000-00000000000a', 'Francais', 'grammaire', 'phrase_complexe_coord', 'Phrase complexe : coordination et juxtaposition', 'Intermediaire', 'reponse_courte', 'Citez les six conjonctions de coordination du français (dans n''importe quel ordre).', NULL, NULL, '{"mode":"text","acceptableAnswers":["mais ou et or ni car","mais, ou, et, or, ni, car"]}'::jsonb, 'Les six conjonctions de coordination (Éduscol 2021) sont : mais, ou, et, or, ni, car. Attention : « donc » est classé comme un ADVERBE de liaison selon la terminologie officielle, pas comme une conjonction de coordination. Le moyen mnémotechnique « Mais où est donc Ornicar ? » reste utile mais « donc » n''y figure pas en tant que conjonction. Chacune exprime une valeur sémantique distincte : opposition (mais), alternative (ou), addition (et), restriction logique (or), négation (ni), cause (car).', 'Citer « donc » parmi les conjonctions de coordination par habitude du moyen mnémotechnique, alors que la terminologie officielle le classe comme adverbe. Les candidats oublient aussi fréquemment ''or'' et ''ni''.', 'valide', 'CRPE Français V3', 'free', true),

-- ─── Batch A — Série 02 : Subordonnées circonstancielles ─────────────────────
('a3020000-0000-0000-0000-000000000001', 'Francais', 'analyse_langue', 'subordonnees_circonstancielles', 'Subordonnées circonstancielles', 'Difficile', 'qcm', 'Quelle est la nature de la proposition soulignée dans : « Il est parti __parce qu''il était fatigué__ » ?', NULL, '[{"id":"a","label":"Subordonnée circonstancielle de but"},{"id":"b","label":"Subordonnée circonstancielle de cause"},{"id":"c","label":"Subordonnée circonstancielle de concession"},{"id":"d","label":"Subordonnée complétive"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, '''Parce que'' est la conjonction de subordination de cause par excellence. Elle introduit une subordonnée circonstancielle de cause qui répond à la question ''Pourquoi est-il parti ?''. Elle est suivie de l''indicatif, car la cause est présentée comme un fait réel et certain.', 'Les candidats confondent parfois cause et but. La cause répond à ''Pourquoi ?'' (raison passée ou présente) ; le but répond à ''Dans quel but ?'' ou ''Pour quoi faire ?'' (action future souhaitée). ''Pour que'' exprime le but et est suivi du subjonctif.', 'valide', 'CRPE Français V3', 'free', true),

('a3020000-0000-0000-0000-000000000002', 'Francais', 'analyse_langue', 'subordonnees_circonstancielles', 'Subordonnées circonstancielles', 'Difficile', 'qcm', 'Quel mode verbal s''impose après la conjonction ''bien que'' ?', NULL, '[{"id":"a","label":"L''indicatif présent"},{"id":"b","label":"Le conditionnel"},{"id":"c","label":"Le subjonctif"},{"id":"d","label":"L''infinitif"}]'::jsonb, '{"mode":"single_choice","value":"c"}'::jsonb, '''Bien que'' est une conjonction de concession qui impose systématiquement le subjonctif : « Bien qu''il soit fatigué, il continue ». Les conjonctions de concession (bien que, quoique, encore que, malgré que) requièrent toutes le subjonctif car elles expriment une opposition qui présente le fait comme envisagé plutôt qu''affirmé.', 'L''erreur fréquente est d''écrire ''bien qu''il est'' au lieu de ''bien qu''il soit''. Le subjonctif est obligatoire après ''bien que'', ''quoique'' et ''encore que''. Seul ''malgré'' (préposition) ne prend pas de subjonctif car il est suivi d''un nom.', 'valide', 'CRPE Français V3', 'free', true),

('a3020000-0000-0000-0000-000000000003', 'Francais', 'analyse_langue', 'subordonnees_circonstancielles', 'Subordonnées circonstancielles', 'Difficile', 'vrai_faux', 'La conjonction ''après que'' doit être suivie du subjonctif, à l''instar de ''avant que''.', NULL, NULL, '{"mode":"boolean","value":false}'::jsonb, 'C''est faux. ''Après que'' est suivi de l''indicatif, car l''action est présentée comme réalisée et certaine : « Il est parti après qu''elle est arrivée ». En revanche, ''avant que'' est suivi du subjonctif, car l''action est envisagée mais non encore accomplie : « Il est parti avant qu''elle arrive ». Cette distinction est une des questions les plus piégées du CRPE.', 'C''est une des erreurs les plus répandues, y compris chez des locuteurs cultivés. L''usage courant (fautif) tend à généraliser le subjonctif après ''après que'' par analogie avec ''avant que''. La règle normative exige l''indicatif après ''après que''.', 'valide', 'CRPE Français V3', 'free', true),

('a3020000-0000-0000-0000-000000000004', 'Francais', 'analyse_langue', 'subordonnees_circonstancielles', 'Subordonnées circonstancielles', 'Difficile', 'qcm', 'Dans « Il a travaillé si bien qu''il a réussi son examen », de quel type est la subordonnée circonstancielle ?', NULL, '[{"id":"a","label":"Cause"},{"id":"b","label":"But"},{"id":"c","label":"Conséquence"},{"id":"d","label":"Concession"}]'::jsonb, '{"mode":"single_choice","value":"c"}'::jsonb, '''Si bien que'' est une locution conjonctive de conséquence. Elle introduit une subordonnée qui exprime le résultat ou l''effet de l''action principale. La conséquence est suivie de l''indicatif car le résultat est présenté comme réel. Autres locutions de conséquence : ''de sorte que'', ''de telle manière que'', ''au point que''.', 'Les candidats confondent but et conséquence. La conséquence décrit un résultat effectif (indicatif) ; le but décrit un résultat recherché, non encore atteint (subjonctif). Comparer : « Il parle fort pour que tout le monde entende » (but, subjonctif) vs « Il a parlé fort si bien que tout le monde a entendu » (conséquence, indicatif).', 'valide', 'CRPE Français V3', 'free', true),

('a3020000-0000-0000-0000-000000000005', 'Francais', 'analyse_langue', 'subordonnees_circonstancielles', 'Subordonnées circonstancielles', 'Difficile', 'qcm', 'Quelle conjonction introduit une subordonnée de condition avec le mode indicatif ?', NULL, '[{"id":"a","label":"Bien que"},{"id":"b","label":"Afin que"},{"id":"c","label":"Si"},{"id":"d","label":"Pour que"}]'::jsonb, '{"mode":"single_choice","value":"c"}'::jsonb, '''Si'' est la conjonction de condition par excellence. Elle est suivie de l''indicatif (jamais du conditionnel dans la subordonnée) : « Si tu viens, je serai content » (indicatif présent dans la subordonnée, futur dans la principale). La règle fondamentale : on ne met jamais le conditionnel après ''si'' conditionnel.', 'L''erreur la plus fréquente est d''écrire ''si tu viendrais'' au lieu de ''si tu venais''. Après ''si'' conditionnel, on utilise : présent de l''indicatif (condition dans le présent/futur) ou imparfait de l''indicatif (condition hypothétique), jamais le conditionnel.', 'valide', 'CRPE Français V3', 'free', true),

('a3020000-0000-0000-0000-000000000006', 'Francais', 'analyse_langue', 'subordonnees_circonstancielles', 'Subordonnées circonstancielles', 'Difficile', 'vrai_faux', 'La subordonnée introduite par ''puisque'' exprime la cause connue du locuteur et de son interlocuteur.', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'C''est vrai. ''Puisque'' introduit une cause présentée comme connue ou évidente pour les deux interlocuteurs, voire comme un argument : « Puisque tu le sais déjà, je n''ai pas besoin d''expliquer ». C''est ce qui la distingue de ''parce que'' (cause factuelle neutre) et de ''comme'' (cause placée en tête de phrase, présentée comme un fait contextuel).', 'Les candidats traitent souvent ''puisque'', ''parce que'' et ''comme'' comme des synonymes parfaits. Ils ont en réalité des nuances : ''parce que'' = cause factuelle, ''puisque'' = cause connue/admise, ''comme'' = cause contextuelle en début de phrase.', 'valide', 'CRPE Français V3', 'free', true),

('a3020000-0000-0000-0000-000000000007', 'Francais', 'analyse_langue', 'subordonnees_circonstancielles', 'Subordonnées circonstancielles', 'Difficile', 'reponse_courte', 'Identifiez le type de la subordonnée circonstancielle dans la phrase : « Il a pris un parapluie de peur qu''il ne pleuve. »', NULL, NULL, '{"mode":"text","acceptableAnswers":["but","subordonnée de but","but (précaution)"]}'::jsonb, '''De peur que'' est une locution conjonctive de but (but préventif ou de précaution). Elle exprime l''intention d''éviter quelque chose et est suivie du subjonctif avec un ''ne'' explétif (obligatoire dans l''usage soigné). On peut la remplacer par ''afin que'' ou ''pour que'' dans une reformulation. Autres locutions de but : ''afin que'', ''pour que'', ''de crainte que'' (+ ne explétif).', 'Les candidats identifient parfois cette structure comme une subordonnée de cause ou de conséquence. Le ''ne'' explétif après ''de peur que'' et ''de crainte que'' est un indice du but. Ne pas confondre avec la négation réelle : ici ''ne'' seul (sans ''pas'') est un simple explétif sans valeur négative.', 'valide', 'CRPE Français V3', 'free', true),

('a3020000-0000-0000-0000-000000000008', 'Francais', 'analyse_langue', 'subordonnees_circonstancielles', 'Subordonnées circonstancielles', 'Difficile', 'qcm', 'Dans « Comme il faisait beau, nous sommes sortis », quelle est la fonction de la proposition ''Comme il faisait beau'' ?', NULL, '[{"id":"a","label":"Subordonnée circonstancielle de temps"},{"id":"b","label":"Subordonnée circonstancielle de cause"},{"id":"c","label":"Subordonnée circonstancielle de comparaison"},{"id":"d","label":"Subordonnée complétive sujet"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, '''Comme'' en début de phrase, suivi de l''imparfait ou du plus-que-parfait de l''indicatif, introduit une subordonnée circonstancielle de cause. C''est une valeur spécifique de ''comme'' : il présente la cause comme un contexte ou une donnée préalable. À ne pas confondre avec ''comme'' de comparaison (« Il court comme un lièvre ») ou ''comme'' de temps simultané (« Comme il entrait, elle sortait »).', 'Le mot ''comme'' est polysémique : il peut introduire une comparaison, une cause ou une simultanéité temporelle. La valeur causale est identifiable à la position en tête de phrase et au sens général (on peut remplacer par ''étant donné que'' ou ''puisque'').', 'valide', 'CRPE Français V3', 'free', true),

('a3020000-0000-0000-0000-000000000009', 'Francais', 'analyse_langue', 'subordonnees_circonstancielles', 'Subordonnées circonstancielles', 'Difficile', 'vrai_faux', 'La subordonnée circonstancielle de concession exprime un obstacle qui empêche la réalisation de l''action principale.', NULL, NULL, '{"mode":"boolean","value":false}'::jsonb, 'C''est faux. La concession exprime au contraire un obstacle qui NE SUFFIT PAS à empêcher la réalisation de l''action principale. L''action se réalise MALGRÉ l''obstacle : « Bien qu''il soit fatigué, il continue à travailler ». Il continue malgré la fatigue. Si l''obstacle empêchait l''action, ce serait une condition non réalisée.', 'La confusion porte sur la direction logique : dans la concession, l''obstacle existe mais est surmonté. Le fait principal se réalise en dépit de l''obstacle. C''est ce paradoxe apparent qui définit la concession.', 'valide', 'CRPE Français V3', 'free', true),

('a3020000-0000-0000-0000-00000000000a', 'Francais', 'analyse_langue', 'subordonnees_circonstancielles', 'Subordonnées circonstancielles', 'Difficile', 'reponse_courte', 'Donnez deux locutions conjonctives de but (autres que ''pour que'') qui imposent le subjonctif.', NULL, NULL, '{"mode":"text","acceptableAnswers":["afin que","de peur que","de crainte que","à condition que","afin que / de peur que","afin que / de crainte que"]}'::jsonb, 'Les principales locutions conjonctives de but imposant le subjonctif sont : ''afin que'', ''de peur que'' (+ ne explétif), ''de crainte que'' (+ ne explétif). À noter que ''de peur que'' et ''de crainte que'' expriment un but préventif (on agit pour éviter quelque chose). D''autres locutions avec subjonctif : ''à moins que'' (condition négative), ''bien que'' et ''quoique'' (concession).', 'Les candidats mémorisent souvent ''pour que'' mais oublient ''afin que'', ''de peur que'', ''de crainte que''. Ces locutions de but avec nuance préventive sont fréquentes dans les textes littéraires et les sujets de CRPE.', 'valide', 'CRPE Français V3', 'free', true),

-- ─── Batch A — Série 03 : Subordonnées complétives ───────────────────────────
('a3030000-0000-0000-0000-000000000001', 'Francais', 'analyse_langue', 'subordonnees_completives', 'Subordonnées complétives', 'Difficile', 'qcm', 'Dans « Je sais qu''il viendra demain », quelle est la fonction de la proposition ''qu''il viendra demain'' ?', NULL, '[{"id":"a","label":"Sujet du verbe ''sais''"},{"id":"b","label":"Complément d''objet direct (COD) du verbe ''sais''"},{"id":"c","label":"Complément circonstanciel de temps"},{"id":"d","label":"Attribut du sujet"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'La proposition ''qu''il viendra demain'' est une subordonnée complétive COD du verbe ''savoir''. On peut la vérifier en la remplaçant par un pronom COD : « Je le sais ». Elle est introduite par la conjonction de subordination ''que''. Le verbe ''savoir'' exprime la certitude et est suivi de l''indicatif.', 'Les candidats confondent parfois complétive COD et complétive sujet. Test simple : peut-on remplacer la proposition par ''le/la/les'' (→ COD) ou par ''cela'' en position sujet (→ sujet) ? Ici : ''Je le sais'' → COD.', 'valide', 'CRPE Français V3', 'free', true),

('a3030000-0000-0000-0000-000000000002', 'Francais', 'analyse_langue', 'subordonnees_completives', 'Subordonnées complétives', 'Difficile', 'qcm', 'Quel mode s''emploie dans la complétive dépendant du verbe ''vouloir'' ?', NULL, '[{"id":"a","label":"L''indicatif"},{"id":"b","label":"Le conditionnel"},{"id":"c","label":"Le subjonctif"},{"id":"d","label":"L''infinitif (sans subordonnée)"}]'::jsonb, '{"mode":"single_choice","value":"c"}'::jsonb, '''Vouloir'' est un verbe de volonté qui impose le subjonctif dans la complétive : « Je veux qu''il parte ». Les verbes de volonté (vouloir, souhaiter, désirer, exiger, ordonner, interdire, permettre) imposent tous le subjonctif car ils expriment un souhait ou une intention dont la réalisation est incertaine au moment de l''énonciation.', 'Attention : quand le sujet de la principale et de la subordonnée est le même, on utilise l''infinitif, non le subjonctif : ''Je veux partir'' (même sujet) et non ''Je veux que je parte''.', 'valide', 'CRPE Français V3', 'free', true),

('a3030000-0000-0000-0000-000000000003', 'Francais', 'analyse_langue', 'subordonnees_completives', 'Subordonnées complétives', 'Difficile', 'vrai_faux', 'Dans « Il ignore si elle est arrivée », la proposition ''si elle est arrivée'' est une interrogative indirecte totale.', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'C''est vrai. L''interrogative indirecte totale porte sur l''ensemble du contenu de la proposition (la réponse possible est ''oui'' ou ''non''). Elle est introduite par ''si'' et correspond à la transformation d''une question totale directe : « Est-elle arrivée ? » → « Il ignore si elle est arrivée ». Le verbe est à l''indicatif.', 'Les candidats confondent parfois ''si'' conditionnel et ''si'' interrogatif indirect. ''Si'' interrogatif indirect peut toujours être remplacé par ''si oui ou non'' : ''Il ignore si oui ou non elle est arrivée'' → interrogative indirecte totale.', 'valide', 'CRPE Français V3', 'free', true),

('a3030000-0000-0000-0000-000000000004', 'Francais', 'analyse_langue', 'subordonnees_completives', 'Subordonnées complétives', 'Difficile', 'qcm', 'Dans « Il demande ce que tu fais », quelle est la nature de ''ce que tu fais'' ?', NULL, '[{"id":"a","label":"Subordonnée relative introduite par ''ce que''"},{"id":"b","label":"Interrogative indirecte partielle"},{"id":"c","label":"Complétive en ''que'' au subjonctif"},{"id":"d","label":"Subordonnée de cause"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, '''Ce que tu fais'' est une interrogative indirecte partielle. Elle correspond à la transformation de la question directe partielle : « Que fais-tu ? » → « Il demande ce que tu fais ». Dans l''interrogation indirecte, ''que'' devient ''ce que'' (pronom composé), le verbe passe à un ordre non inversé et la proposition joue le rôle de COD du verbe ''demander''.', 'La confusion avec la relative est fréquente car les deux peuvent contenir ''ce que''. Distinction : dans la relative, ''ce que'' a un antécédent (''ce'' = pronom démonstratif) ; dans l''interrogative indirecte, la proposition est COD d''un verbe de questionnement ou d''ignorance.', 'valide', 'CRPE Français V3', 'free', true),

('a3030000-0000-0000-0000-000000000005', 'Francais', 'analyse_langue', 'subordonnees_completives', 'Subordonnées complétives', 'Difficile', 'qcm', 'Quel mode faut-il employer dans : « Je crains qu''il ne ___ (partir) trop tôt » ?', NULL, '[{"id":"a","label":"L''indicatif présent : part"},{"id":"b","label":"Le subjonctif présent : parte"},{"id":"c","label":"Le conditionnel présent : partirait"},{"id":"d","label":"L''infinitif : partir"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, '''Craindre'' est un verbe de sentiment négatif (crainte, peur) qui impose le subjonctif dans la complétive. La forme correcte est : « Je crains qu''il ne parte trop tôt ». Le ''ne'' explétif est facultatif mais recommandé dans l''usage soigné après les verbes de crainte. Autres verbes de crainte imposant le subjonctif : avoir peur que, redouter que, appréhender que.', 'L''erreur consiste à mettre l''indicatif (''je crains qu''il part'') par analogie avec les verbes de déclaration. Les verbes de sentiment (craindre, regretter, se réjouir, être surpris) imposent le subjonctif, contrairement aux verbes de déclaration (dire, affirmer, penser au positif) qui imposent l''indicatif.', 'valide', 'CRPE Français V3', 'free', true),

('a3030000-0000-0000-0000-000000000006', 'Francais', 'analyse_langue', 'subordonnees_completives', 'Subordonnées complétives', 'Difficile', 'vrai_faux', 'La proposition ''qu''il réussisse'' dans « Il est possible qu''il réussisse » est une subordonnée complétive sujet.', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'C''est vrai. La proposition ''qu''il réussisse'' est une subordonnée complétive sujet réel du verbe impersonnel ''est possible''. Le sujet grammatical apparent est ''il'' (pronom impersonnel), mais le sujet réel est la complétive. On peut le vérifier : ''Sa réussite est possible'' (nom en position sujet). Le subjonctif s''impose car l''expression ''il est possible que'' exprime la possibilité (non-certitude).', 'Les candidats identifient souvent cette complétive comme COD. Avec les tournures impersonnelles (il est possible que, il faut que, il semble que), la complétive est sujet réel du verbe impersonnel, non COD.', 'valide', 'CRPE Français V3', 'free', true),

('a3030000-0000-0000-0000-000000000007', 'Francais', 'analyse_langue', 'subordonnees_completives', 'Subordonnées complétives', 'Difficile', 'reponse_courte', 'Transformez la question directe suivante en interrogative indirecte dépendant de ''Elle se demande'' : « Quand arrivera-t-il ? »', NULL, NULL, '{"mode":"text","acceptableAnswers":["Elle se demande quand il arrivera.","Elle se demande quand il arrive.","elle se demande quand il arrivera"]}'::jsonb, 'La transformation implique : 1) suppression du point d''interrogation et de l''inversion sujet-verbe ; 2) conservation du mot interrogatif ''quand'' ; 3) ajustement des temps si nécessaire. La phrase correcte est : « Elle se demande quand il arrivera. » Le mot interrogatif ''quand'' est conservé tel quel dans l''interrogative indirecte, contrairement à ''que'' qui devient ''ce que''.', 'L''erreur la plus fréquente est de conserver l''inversion du sujet : ''Elle se demande quand arrivera-t-il'' est incorrect. Dans l''interrogative indirecte, le sujet précède toujours le verbe (ordre déclaratif).', 'valide', 'CRPE Français V3', 'free', true),

('a3030000-0000-0000-0000-000000000008', 'Francais', 'analyse_langue', 'subordonnees_completives', 'Subordonnées complétives', 'Difficile', 'qcm', 'Dans « Je pense qu''il a tort », le mode de ''a tort'' est l''indicatif. Si la principale passe à la forme négative (« Je ne pense pas »), quel mode s''emploie généralement dans la complétive ?', NULL, '[{"id":"a","label":"L''indicatif reste obligatoire"},{"id":"b","label":"Le subjonctif est souvent préféré"},{"id":"c","label":"Le conditionnel s''impose"},{"id":"d","label":"L''infinitif remplace la complétive"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'Quand un verbe d''opinion est à la forme négative ou interrogative, la certitude diminue et la complétive peut prendre le subjonctif : « Je ne pense pas qu''il ait tort » (subjonctif, incertitude) vs « Je pense qu''il a tort » (indicatif, affirmation). Les deux modes sont néanmoins possibles : l''indicatif maintient une certaine affirmation, le subjonctif marque la mise en doute.', 'Les candidats appliquent parfois mécaniquement l''indicatif après ''penser'' sans tenir compte de la polarité de la phrase. La négation ou l''interrogation des verbes d''opinion (penser, croire, trouver) ouvre la voie au subjonctif.', 'valide', 'CRPE Français V3', 'free', true),

('a3030000-0000-0000-0000-000000000009', 'Francais', 'analyse_langue', 'subordonnees_completives', 'Subordonnées complétives', 'Difficile', 'vrai_faux', 'Dans l''interrogative indirecte, le point d''interrogation est maintenu à la fin de la phrase.', NULL, NULL, '{"mode":"boolean","value":false}'::jsonb, 'C''est faux. L''interrogative indirecte est une subordonnée intégrée dans une phrase déclarative. Elle ne conserve pas le point d''interrogation : « Je me demande s''il viendra » (point final, pas d''interrogation). Seule l''interrogation directe (question indépendante) se termine par un point d''interrogation : « Viendra-t-il ? »', 'Les candidats scripteurs oublient parfois de supprimer le point d''interrogation lors de la transformation. L''interrogative indirecte est une proposition subordonnée qui joue le rôle d''un nom ; elle fait partie d''une phrase déclarative.', 'valide', 'CRPE Français V3', 'free', true),

('a3030000-0000-0000-0000-00000000000a', 'Francais', 'analyse_langue', 'subordonnees_completives', 'Subordonnées complétives', 'Difficile', 'reponse_courte', 'Citez deux verbes introducteurs qui imposent le subjonctif dans la subordonnée complétive.', NULL, NULL, '{"mode":"text","acceptableAnswers":["vouloir","souhaiter","craindre","douter","regretter","interdire","exiger","falloir","vouloir et craindre","souhaiter et douter"]}'::jsonb, 'Les verbes imposant le subjonctif dans la complétive appartiennent aux catégories suivantes : volonté (vouloir, souhaiter, désirer, exiger, ordonner, interdire), sentiment (regretter, se réjouir, craindre, être surpris), doute ou possibilité (douter, nier, il est possible que, il faut que). En revanche, les verbes de déclaration ou d''opinion affirmative (dire, affirmer, penser, croire, savoir, voir) imposent l''indicatif.', 'L''erreur courante est de mettre le subjonctif après tous les verbes introducteurs de complétive. Le subjonctif est réservé aux verbes exprimant une réalité non affirmée (volonté, doute, sentiment). Les verbes de déclaration et de perception imposent l''indicatif.', 'valide', 'CRPE Français V3', 'free', true),

-- ─── Batch A — Série 04 : Discours direct et indirect ────────────────────────
('a3040000-0000-0000-0000-000000000001', 'Francais', 'grammaire', 'discours_direct_indirect', 'Discours direct et indirect', 'Intermediaire', 'qcm', 'Quels signes typographiques caractérisent principalement le discours direct ?', NULL, '[{"id":"a","label":"Parenthèses et italique"},{"id":"b","label":"Guillemets et deux-points (ou tiret pour les répliques)"},{"id":"c","label":"Crochets et astérisques"},{"id":"d","label":"Point-virgule et tiret bas"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'Le discours direct est signalé typographiquement par les guillemets (« … ») précédés d''un deux-points et d''un verbe introducteur. Dans un dialogue, chaque réplique peut être introduite par un tiret. Le discours direct conserve les marques d''énonciation originales (personnes, temps, déictiques) de l''énonciateur.', 'Les candidats oublient parfois le rôle du deux-points comme annonceur du discours direct, ou confondent les guillemets du discours direct avec ceux de l''usage distancié d''un mot.', 'valide', 'CRPE Français V3', 'free', true),

('a3040000-0000-0000-0000-000000000002', 'Francais', 'grammaire', 'discours_direct_indirect', 'Discours direct et indirect', 'Intermediaire', 'qcm', 'Transformez au discours indirect : Marie dit : « Je viendrai demain. » → Marie dit que...', NULL, '[{"id":"a","label":"elle viendra demain."},{"id":"b","label":"elle viendrait le lendemain."},{"id":"c","label":"je viendrais le lendemain."},{"id":"d","label":"elle est venue le lendemain."}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'Quand le verbe introducteur est au présent (dit), les temps ne changent pas dans la subordonnée. Mais dans cet exemple, si ''dit'' est au présent historique ou si on considère la transformation standard, le passage au discours indirect entraîne : futur → conditionnel (''viendra'' → ''viendrait''), ''je'' → ''elle'', ''demain'' → ''le lendemain''. La réponse correcte est donc ''elle viendrait le lendemain'' (transformation complète).', 'Les candidats oublient souvent de changer les déictiques temporels. ''Demain'' dans le discours direct devient ''le lendemain'' dans le discours indirect (car le point de référence change). De même ''hier'' → ''la veille'', ''maintenant'' → ''alors''.', 'valide', 'CRPE Français V3', 'free', true),

('a3040000-0000-0000-0000-000000000003', 'Francais', 'grammaire', 'discours_direct_indirect', 'Discours direct et indirect', 'Intermediaire', 'vrai_faux', 'Dans le discours indirect libre, il y a toujours un verbe introducteur explicite suivi de la conjonction ''que''.', NULL, NULL, '{"mode":"boolean","value":false}'::jsonb, 'C''est faux. Le discours indirect libre se définit précisément par l''absence de verbe introducteur et de conjonction ''que''. Il emprunte au discours direct la liberté d''expression tout en adoptant la 3e personne et les temps du récit : « Elle sortit. Comme c''était beau ! Elle n''avait jamais rien vu de tel. » Les deux dernières phrases sont au style indirect libre : pas de ''elle pensa que''.', 'La confusion est fréquente car le style indirect libre peut sembler être du discours direct ou du récit ordinaire. Les indices : présence de la 3e personne (style indirect) mais maintien des marques expressives et d''interrogation rhétorique (style direct). Pas de guillemets ni de verbe introducteur.', 'valide', 'CRPE Français V3', 'free', true),

('a3040000-0000-0000-0000-000000000004', 'Francais', 'grammaire', 'discours_direct_indirect', 'Discours direct et indirect', 'Intermediaire', 'qcm', 'Au discours indirect, quelle transformation subit le déictique spatial ''ici'' ?', NULL, '[{"id":"a","label":"Il reste ''ici''"},{"id":"b","label":"Il devient ''là''"},{"id":"c","label":"Il devient ''là-bas''"},{"id":"d","label":"Il est supprimé"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, '''Ici'' est un déictique spatial ancré dans la situation d''énonciation du locuteur original. Au discours indirect, le point de référence change : ''ici'' (lieu du locuteur) devient ''là'' (lieu perçu de l''extérieur). De même : ''ce'' → ''cet/cette'' ou disparaît, ''ceci'' → ''cela''. Le tableau des transformations déictiques est un classique des sujets CRPE.', 'Les candidats oublient souvent de transformer les déictiques spatiaux, se concentrant uniquement sur les changements de personne et de temps. Tous les repères d''énonciation doivent être adaptés.', 'valide', 'CRPE Français V3', 'free', true),

('a3040000-0000-0000-0000-000000000005', 'Francais', 'grammaire', 'discours_direct_indirect', 'Discours direct et indirect', 'Intermediaire', 'qcm', 'Quel est le verbe introducteur qui convient pour rapporter une question au discours indirect ?', NULL, '[{"id":"a","label":"Il affirme que"},{"id":"b","label":"Il demande si / Il demande ce que"},{"id":"c","label":"Il explique que"},{"id":"d","label":"Il constate que"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'Pour rapporter une question au discours indirect, on utilise des verbes introducteurs interrogatifs : demander, s''interroger, vouloir savoir, se demander. La conjonction introductrice dépend du type de question : ''si'' pour une question totale (oui/non), un mot interrogatif pour une question partielle. Ex. : « Vient-il ? » → « Il demande s''il vient. »', 'Les candidats emploient parfois ''que'' pour introduire une question rapportée : ''Il demande qu''il vient'' est incorrect. Une question rapportée au discours indirect s''introduit par ''si'' (question totale) ou par un mot interrogatif (question partielle).', 'valide', 'CRPE Français V3', 'free', true),

('a3040000-0000-0000-0000-000000000006', 'Francais', 'grammaire', 'discours_direct_indirect', 'Discours direct et indirect', 'Intermediaire', 'vrai_faux', 'Quand le verbe introducteur est au passé, le présent du discours direct se transforme en imparfait au discours indirect.', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'C''est vrai. La concordance des temps impose que, lorsque le verbe introducteur est au passé, les temps de la subordonnée reculent d''un degré : présent → imparfait, passé composé → plus-que-parfait, futur → conditionnel présent, futur antérieur → conditionnel passé. Ex. : « Je suis fatigué » (discours direct) → « Il a dit qu''il était fatigué » (imparfait au discours indirect).', 'L''erreur consiste à ne pas appliquer la concordance des temps. Certains candidats maintiennent le présent après un verbe introducteur au passé : ''Il a dit qu''il est fatigué'' est une erreur dans un contexte formel.', 'valide', 'CRPE Français V3', 'free', true),

('a3040000-0000-0000-0000-000000000007', 'Francais', 'grammaire', 'discours_direct_indirect', 'Discours direct et indirect', 'Intermediaire', 'reponse_courte', 'Transposez au discours indirect la phrase suivante (le verbe introducteur est au passé) : Paul cria : « Je suis en retard ! »', NULL, NULL, '{"mode":"text","acceptableAnswers":["Paul cria qu''il était en retard.","Paul cria qu''il était en retard"]}'::jsonb, 'La transformation exige : 1) le verbe introducteur ''cria'' reste au passé simple ; 2) les guillemets et le deux-points disparaissent ; 3) introduction de la conjonction ''que'' ; 4) ''je'' → ''il'' (changement de personne) ; 5) ''suis'' (présent) → ''était'' (imparfait, concordance des temps) ; 6) suppression du point d''exclamation. Résultat : « Paul cria qu''il était en retard. »', 'L''oubli de la concordance des temps est l''erreur la plus fréquente : écrire ''Paul cria qu''il est en retard'' maintient incorrectement le présent. La ponctuation expressive (point d''exclamation) disparaît aussi au discours indirect.', 'valide', 'CRPE Français V3', 'free', true),

('a3040000-0000-0000-0000-000000000008', 'Francais', 'grammaire', 'discours_direct_indirect', 'Discours direct et indirect', 'Intermediaire', 'qcm', 'Quel terme désigne les mots dont le sens dépend de la situation d''énonciation (je, ici, maintenant, hier, demain) ?', NULL, '[{"id":"a","label":"Anaphores"},{"id":"b","label":"Déictiques (ou embrayeurs)"},{"id":"c","label":"Modalisateurs"},{"id":"d","label":"Connecteurs logiques"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'Les déictiques (aussi appelés embrayeurs ou shifters) sont des unités linguistiques dont la référence varie selon la situation d''énonciation. Ils encodent les coordonnées de l''acte d''énonciation : la personne (je/tu), le lieu (ici/là), le temps (maintenant, hier, demain). C''est pourquoi ils doivent être transformés lors du passage du discours direct au discours indirect.', 'Les candidats confondent parfois déictiques et anaphores. Une anaphore renvoie à un élément déjà présent dans le texte (antécédent), tandis qu''un déictique renvoie à la situation d''énonciation extra-linguistique.', 'valide', 'CRPE Français V3', 'free', true),

('a3040000-0000-0000-0000-000000000009', 'Francais', 'grammaire', 'discours_direct_indirect', 'Discours direct et indirect', 'Intermediaire', 'vrai_faux', 'Le discours indirect libre est typique du roman réaliste du XIXe siècle et permet de rendre les pensées d''un personnage sans verbe introducteur.', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'C''est vrai. Le discours indirect libre, théorisé par le linguiste Charles Bally, est une technique narrative caractéristique du roman réaliste et naturaliste (Flaubert, Zola, Maupassant). Il fond la voix du narrateur et celle du personnage : les pensées ou paroles sont rapportées sans ''il pensa que'' ou guillemets, mais avec les temps du récit (imparfait, plus-que-parfait) et la 3e personne.', 'Les candidats pensent parfois que le discours indirect libre est une simple variante formelle sans importance littéraire. C''est au contraire un procédé stylistique majeur qui crée de l''ambiguïté énonciative et de l''empathie narrative.', 'valide', 'CRPE Français V3', 'free', true),

('a3040000-0000-0000-0000-00000000000a', 'Francais', 'grammaire', 'discours_direct_indirect', 'Discours direct et indirect', 'Intermediaire', 'reponse_courte', 'Quel déictique temporel remplace ''hier'' au discours indirect (quand le verbe introducteur est au passé) ?', NULL, NULL, '{"mode":"text","acceptableAnswers":["la veille","la veille."]}'::jsonb, '''Hier'' est un déictique temporel centré sur le moment de l''énonciation originale. Au discours indirect, le point de référence temporel change : ''hier'' devient ''la veille''. De même : ''demain'' → ''le lendemain'', ''aujourd''hui'' → ''ce jour-là'', ''maintenant'' → ''alors'' ou ''à ce moment-là'', ''la semaine prochaine'' → ''la semaine suivante''. Ce tableau de correspondances est fréquemment évalué au CRPE.', 'Les candidats mémorisent ''hier → la veille'' mais oublient les autres déictiques. Rappel : ''avant-hier'' → ''l''avant-veille'', ''après-demain'' → ''le surlendemain''.', 'valide', 'CRPE Français V3', 'free', true),

-- ─── Batch A — Série 05 : Types et formes de phrases ─────────────────────────
('a3050000-0000-0000-0000-000000000001', 'Francais', 'grammaire', 'types_phrases_grammaire', 'Types et formes de phrases', 'Facile', 'qcm', 'Combien existe-t-il de types de phrases en français ?', NULL, '[{"id":"a","label":"Deux (positive et négative)"},{"id":"b","label":"Trois (déclarative, interrogative, impérative)"},{"id":"c","label":"Quatre (déclarative, interrogative, exclamative, impérative)"},{"id":"d","label":"Cinq (en ajoutant la conditionnelle)"}]'::jsonb, '{"mode":"single_choice","value":"c"}'::jsonb, 'On distingue en français quatre types de phrases : la déclarative (affirmation ou négation d''un fait), l''interrogative (question), l''exclamative (expression d''une émotion intense), et l''impérative (ordre, conseil, interdiction). À chacun de ces types peuvent s''appliquer les deux formes : affirmative et négative.', 'La confusion entre ''type'' et ''forme'' est fréquente. Le type correspond à la visée communicative de la phrase ; la forme correspond à la polarité positive ou négative. Une phrase impérative peut être affirmative (''Viens !'') ou négative (''Ne viens pas !'').', 'valide', 'CRPE Français V3', 'free', true),

('a3050000-0000-0000-0000-000000000002', 'Francais', 'grammaire', 'types_phrases_grammaire', 'Types et formes de phrases', 'Facile', 'qcm', 'Quel est le type de la phrase : « Quelle belle journée nous avons aujourd''hui ! » ?', NULL, '[{"id":"a","label":"Interrogative"},{"id":"b","label":"Déclarative"},{"id":"c","label":"Exclamative"},{"id":"d","label":"Impérative"}]'::jsonb, '{"mode":"single_choice","value":"c"}'::jsonb, 'Cette phrase est exclamative : elle se termine par un point d''exclamation et exprime l''admiration ou l''enthousiasme du locuteur. Elle est introduite par le déterminant exclamatif ''quelle''. Les phrases exclamatives peuvent commencer par ''quel/quelle/quels/quelles'', ''comme'', ''que'', ''combien'' et se terminent par un point d''exclamation.', 'Les candidats confondent parfois exclamative et interrogative car les deux peuvent commencer par ''quel''. Différence : l''interrogative demande une information (''Quelle journée avons-nous ?''), l''exclamative exprime une émotion (''Quelle belle journée !''). La ponctuation et l''intonation les distinguent.', 'valide', 'CRPE Français V3', 'free', true),

('a3050000-0000-0000-0000-000000000003', 'Francais', 'grammaire', 'types_phrases_grammaire', 'Types et formes de phrases', 'Facile', 'vrai_faux', 'La phrase impérative peut se construire sans sujet exprimé.', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'C''est vrai. La phrase impérative se caractérise par l''absence de sujet exprimé : le sujet est sous-entendu (tu, vous, nous). « Viens ! » = (Tu) viens ! — « Partons ! » = (Nous) partons ! Cette absence du sujet est la marque formelle principale du mode impératif. C''est aussi ce qui le distingue de l''indicatif présent à la 2e personne.', 'Certains candidats pensent que l''impérative doit toujours avoir un sujet. L''absence de sujet est justement la caractéristique syntaxique de la phrase impérative. Seules trois personnes existent à l''impératif : 2e personne du singulier, 1re et 2e du pluriel.', 'valide', 'CRPE Français V3', 'free', true),

('a3050000-0000-0000-0000-000000000004', 'Francais', 'grammaire', 'types_phrases_grammaire', 'Types et formes de phrases', 'Facile', 'qcm', 'Parmi les procédés suivants, lequel N''EST PAS un procédé d''interrogation directe ?', NULL, '[{"id":"a","label":"La simple intonation montante"},{"id":"b","label":"L''emploi de ''est-ce que''"},{"id":"c","label":"L''inversion du sujet"},{"id":"d","label":"L''emploi de ''si'' introducteur"}]'::jsonb, '{"mode":"single_choice","value":"d"}'::jsonb, '''Si'' introducteur est un outil de l''interrogation INDIRECTE (subordonnée), non directe : « Je me demande si tu viens » (interrogation indirecte). Les trois procédés de l''interrogation directe totale sont : l''intonation montante (« Tu viens ? »), l''emploi de ''est-ce que'' (« Est-ce que tu viens ? »), et l''inversion du sujet (« Viens-tu ? »).', 'Les candidats mémorisent parfois ''si'' comme marqueur interrogatif direct par analogie avec l''anglais. En français, ''si'' interrogatif n''apparaît qu''en interrogation indirecte. En interrogation directe, on utilise l''intonation, ''est-ce que'' ou l''inversion.', 'valide', 'CRPE Français V3', 'free', true),

('a3050000-0000-0000-0000-000000000005', 'Francais', 'grammaire', 'types_phrases_grammaire', 'Types et formes de phrases', 'Facile', 'qcm', 'Quelle est la différence entre une interrogation totale et une interrogation partielle ?', NULL, '[{"id":"a","label":"L''interrogation totale utilise l''inversion, la partielle utilise est-ce que"},{"id":"b","label":"L''interrogation totale porte sur toute la proposition (réponse oui/non), la partielle porte sur un élément (mot interrogatif)"},{"id":"c","label":"L''interrogation totale est formelle, la partielle est familière"},{"id":"d","label":"L''interrogation totale a plusieurs sous-questions, la partielle n''en a qu''une"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'L''interrogation totale porte sur la vérité de toute la proposition et appelle une réponse ''oui'' ou ''non'' : « Tu viens ? » → Oui/Non. L''interrogation partielle porte sur un élément précis de la phrase et est introduite par un mot interrogatif : « Quand viens-tu ? », « Pourquoi pleures-tu ? ». Les mots interrogatifs partiels sont : qui, que, quoi, où, quand, comment, pourquoi, combien, quel.', 'Les candidats confondent parfois ''totale'' avec ''complète'' (avec sujet exprimé) et ''partielle'' avec ''incomplète''. La distinction est purement sémantique : totale = porte sur l''ensemble ; partielle = porte sur une partie.', 'valide', 'CRPE Français V3', 'free', true),

('a3050000-0000-0000-0000-000000000006', 'Francais', 'grammaire', 'types_phrases_grammaire', 'Types et formes de phrases', 'Facile', 'vrai_faux', 'La phrase « N''est-il pas venu ? » est à la fois de type interrogatif et de forme négative.', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'C''est vrai. Cette phrase cumule le type interrogatif (marqué par l''inversion du sujet et le point d''interrogation) et la forme négative (marquée par la négation ''ne…pas''). Type et forme sont deux catégories indépendantes qui peuvent se combiner : une phrase peut être interrogative-négative, impérative-négative, exclamative-négative, etc.', 'L''erreur consiste à opposer type et forme comme s''ils s''excluaient. Une phrase a TOUJOURS un type ET une forme. La forme négative peut s''appliquer à tous les types.', 'valide', 'CRPE Français V3', 'free', true),

('a3050000-0000-0000-0000-000000000007', 'Francais', 'grammaire', 'types_phrases_grammaire', 'Types et formes de phrases', 'Facile', 'reponse_courte', 'Quel mot interrogatif utilise-t-on pour interroger sur une personne en position de sujet ?', NULL, NULL, '{"mode":"text","acceptableAnswers":["qui","Qui"]}'::jsonb, '''Qui'' est le pronom interrogatif utilisé pour interroger sur une personne en position de sujet : « Qui vient ? » En position de COD, on utilise aussi ''qui'' (ou ''que/quoi'' pour les choses) : « Qui vois-tu ? » La distinction sujet/objet se fait par la position dans la phrase et la construction verbale. Pour les choses en position sujet, on utilise ''qu''est-ce qui'' : « Qu''est-ce qui se passe ? »', 'Les candidats confondent parfois ''qui'' (personne) et ''quoi'' (chose). Rappel : ''qui'' interroge sur une personne, ''que/quoi/qu''est-ce que'' interroge sur une chose.', 'valide', 'CRPE Français V3', 'free', true),

('a3050000-0000-0000-0000-000000000008', 'Francais', 'grammaire', 'types_phrases_grammaire', 'Types et formes de phrases', 'Facile', 'qcm', 'Comment transforme-t-on la phrase déclarative « Vous partez demain » en phrase interrogative avec inversion du sujet ?', NULL, '[{"id":"a","label":"Est-ce que vous partez demain ?"},{"id":"b","label":"Partez-vous demain ?"},{"id":"c","label":"Vous partez demain ?"},{"id":"d","label":"Vous est-ce que partez demain ?"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'L''inversion du sujet est le procédé d''interrogation le plus formel. Pour un sujet pronom, on place le pronom après le verbe avec un trait d''union : « Partez-vous demain ? ». Pour un sujet nominal, on utilise la reprise pronominale : « Les élèves partent-ils demain ? » (sujet nominal + pronom reprise après le verbe). Les réponses a et c sont d''autres procédés valides (est-ce que, intonation) mais pas l''inversion.', 'Les candidats oublient parfois le trait d''union entre le verbe et le pronom sujet inversé. ''Partez vous demain'' est incorrect ; il faut ''Partez-vous demain ?''', 'valide', 'CRPE Français V3', 'free', true),

('a3050000-0000-0000-0000-000000000009', 'Francais', 'grammaire', 'types_phrases_grammaire', 'Types et formes de phrases', 'Facile', 'vrai_faux', 'La phrase impérative ne peut pas être de forme négative.', NULL, NULL, '{"mode":"boolean","value":false}'::jsonb, 'C''est faux. La phrase impérative peut parfaitement être de forme négative : « Ne pars pas ! », « N''oublie pas ton cartable ! », « Ne parlez pas tous à la fois ! ». La négation à l''impératif suit le même schéma qu''à l''indicatif : ne + verbe + pas (ou jamais, plus, rien, personne…).', 'Cette confusion vient de ce que la phrase impérative donne des ordres, que l''on associe spontanément à l''affirmatif. Mais interdire (impératif négatif) est aussi un acte directif. ''Ne fais pas cela'' est bien une phrase impérative de forme négative.', 'valide', 'CRPE Français V3', 'free', true),

('a3050000-0000-0000-0000-00000000000a', 'Francais', 'grammaire', 'types_phrases_grammaire', 'Types et formes de phrases', 'Facile', 'reponse_courte', 'Transformez la phrase impérative en phrase déclarative de même sens : « Fermez la porte ! »', NULL, NULL, '{"mode":"text","acceptableAnswers":["Vous fermez la porte.","Vous devez fermer la porte.","Tu fermes la porte.","Il faut fermer la porte."]}'::jsonb, 'La transformation d''une phrase impérative en déclarative implique d''ajouter le sujet sous-entendu. ''Fermez'' correspond à la 2e personne du pluriel (''vous''). On obtient : « Vous fermez la porte. » ou « Vous devez fermer la porte. » La phrase déclarative perd la valeur d''injonction directe mais conserve le sens général.', 'Les candidats confondent parfois les personnes de l''impératif. ''Fermez'' peut correspondre à ''vous'' (2e pluriel) ou à ''vous'' de politesse. ''Fermons'' serait la 1re personne du pluriel (nous). La personne de l''impératif se déduit de la terminaison.', 'valide', 'CRPE Français V3', 'free', true),

-- ─── Batch A — Série 06 : Participe passé avec avoir ─────────────────────────
('a3060000-0000-0000-0000-000000000001', 'Francais', 'orthographe', 'participe_passe_avoir', 'Participe passé avec avoir', 'Difficile', 'correction_orthographique', 'Corrigez si nécessaire : « Les lettres qu''il a écrit sont arrivées. »', NULL, NULL, '{"mode":"text","acceptableAnswers":["Les lettres qu''il a écrites sont arrivées."]}'::jsonb, '''Qu'' reprend ''les lettres'' (féminin pluriel) et joue le rôle de COD antéposé au verbe ''écrire''. Le PP ''écrit'' doit donc s''accorder au féminin pluriel : ''écrites''. La règle du PP avec avoir : accord avec le COD si celui-ci est placé avant le verbe.', 'L''erreur consiste à ne pas accorder ''écrit''. Il faut identifier l''antécédent du pronom relatif ''que'' pour déterminer le genre et le nombre du COD antéposé.', 'valide', 'CRPE Français V3', 'free', true),

('a3060000-0000-0000-0000-000000000002', 'Francais', 'orthographe', 'participe_passe_avoir', 'Participe passé avec avoir', 'Difficile', 'qcm', 'Dans « Les livres que j''ai lus », pourquoi le participe passé ''lus'' est-il accordé ?', NULL, '[{"id":"a","label":"Parce que le COD est placé après le verbe"},{"id":"b","label":"Parce que le COD ''que'' reprenant ''les livres'' est placé avant le verbe"},{"id":"c","label":"Parce que le sujet ''je'' est pluriel"},{"id":"d","label":"Parce que l''auxiliaire est ''avoir''"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'Le pronom relatif ''que'' reprend ''les livres'' (masculin pluriel) et est COD du verbe ''lire''. Ce COD est antéposé (placé avant le verbe). La règle du PP avec avoir exige l''accord avec le COD antéposé : ''lus'' (masculin pluriel). Si le COD était postposé (« J''ai lu des livres »), il n''y aurait pas d''accord.', 'Les candidats confondent parfois l''accord avec le sujet et l''accord avec le COD. Avec l''auxiliaire avoir, on n''accorde jamais avec le sujet mais uniquement avec le COD antéposé.', 'valide', 'CRPE Français V3', 'free', true),

('a3060000-0000-0000-0000-000000000003', 'Francais', 'orthographe', 'participe_passe_avoir', 'Participe passé avec avoir', 'Difficile', 'vrai_faux', 'Dans « J''en ai mangé », le participe passé ''mangé'' doit s''accorder avec le pronom ''en''.', NULL, NULL, '{"mode":"boolean","value":false}'::jsonb, 'C''est faux. Le pronom ''en'' ne déclenche pas l''accord du participe passé avec l''auxiliaire avoir. ''En'' a une valeur partitive et est considéré comme indéfini : il ne permet pas de déterminer le genre ou le nombre d''un référent précis. La règle est claire : ''en'' COD antéposé → PP invariable.', 'Les candidats tentent parfois d''accorder ''mangé'' avec ''en'' en le traitant comme un COD ordinaire. ''En'' est une exception notoire à la règle d''accord du PP avec avoir.', 'valide', 'CRPE Français V3', 'free', true),

('a3060000-0000-0000-0000-000000000004', 'Francais', 'orthographe', 'participe_passe_avoir', 'Participe passé avec avoir', 'Difficile', 'correction_orthographique', 'Corrigez si nécessaire : « Les enfants que j''ai fait jouer dehors étaient ravis. »', NULL, NULL, '{"mode":"text","acceptableAnswers":["Les enfants que j''ai fait jouer dehors étaient ravis.","Aucune correction nécessaire."]}'::jsonb, 'Aucune correction n''est nécessaire. Lorsque ''faire'' est suivi d''un infinitif, le PP ''fait'' est toujours invariable, quelle que soit la position du COD antéposé. Cette règle est absolue : « les chansons que j''ai fait chanter », « les élèves que j''ai fait travailler ». C''est une exception à la règle générale.', 'Les candidats tendent à accorder ''fait'' avec l''antécédent du pronom relatif, par analogie avec les autres verbes. Mais ''faire + infinitif'' constitue une locution verbale dans laquelle le PP est invariable.', 'valide', 'CRPE Français V3', 'free', true),

('a3060000-0000-0000-0000-000000000005', 'Francais', 'orthographe', 'participe_passe_avoir', 'Participe passé avec avoir', 'Difficile', 'qcm', 'Quelle est la forme correcte : « Les fleurs que tu lui as ___ » ?', NULL, '[{"id":"a","label":"offertes"},{"id":"b","label":"offert"},{"id":"c","label":"offerts"},{"id":"d","label":"offerte"}]'::jsonb, '{"mode":"single_choice","value":"a"}'::jsonb, '''Que'' est le pronom relatif COD reprenant ''les fleurs'' (féminin pluriel). Ce COD est antéposé au verbe ''offrir''. Le PP ''offert'' s''accorde donc avec ''les fleurs'' : ''offertes'' (féminin pluriel). Le pronom ''lui'' est COI (à lui/à elle), il ne déclenche pas l''accord.', 'Les candidats confondent parfois le COD et le COI dans ce type de phrase. Seul le COD antéposé déclenche l''accord. ''Lui'' = COI (à quelqu''un), ne déclenche pas l''accord du PP.', 'valide', 'CRPE Français V3', 'free', true),

('a3060000-0000-0000-0000-000000000006', 'Francais', 'orthographe', 'participe_passe_avoir', 'Participe passé avec avoir', 'Difficile', 'vrai_faux', 'Dans « Elle s''est lavé les mains », le participe passé ''lavé'' reste invariable.', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'C''est vrai. Dans « elle s''est lavé les mains », le COD est ''les mains'', qui est placé APRÈS le verbe. Le pronom réfléchi ''se'' est ici COI (elle a lavé les mains à elle-même → COI). Puisque le COD (''les mains'') est postposé, le PP reste invariable : ''lavé''. En revanche : « Elle se les est lavées » (les mains, COD antéposé par le pronom ''les'' → accord).', 'Cette construction avec les verbes pronominaux est très piégée. Quand un verbe pronominal a un COD distinct du pronom réfléchi et postposé, le PP reste invariable. Il faut analyser la fonction réelle du pronom réfléchi (COD ou COI).', 'valide', 'CRPE Français V3', 'free', true),

('a3060000-0000-0000-0000-000000000007', 'Francais', 'orthographe', 'participe_passe_avoir', 'Participe passé avec avoir', 'Difficile', 'correction_orthographique', 'Corrigez si nécessaire : « Voici les décisions qu''il a pris. »', NULL, NULL, '{"mode":"text","acceptableAnswers":["Voici les décisions qu''il a prises.","Voici les décisions qu''il a prises"]}'::jsonb, '''Qu'' reprend ''les décisions'' (féminin pluriel) et joue le rôle de COD antéposé. Le PP ''pris'' doit donc s''accorder au féminin pluriel : ''prises''. La règle est identique quelle que soit la complexité de la relative ou la distance entre le pronom et le verbe.', 'L''erreur consiste à ne pas accorder ''pris'', soit par oubli de la règle, soit parce que l''antécédent est éloigné. Il faut toujours remonter à l''antécédent du pronom relatif ''que'' pour déterminer le genre et le nombre.', 'valide', 'CRPE Français V3', 'free', true),

('a3060000-0000-0000-0000-000000000008', 'Francais', 'orthographe', 'participe_passe_avoir', 'Participe passé avec avoir', 'Difficile', 'qcm', 'Dans « Je les ai vus partir », quelle est la forme correcte du PP ''voir'' ?', NULL, '[{"id":"a","label":"vu (invariable)"},{"id":"b","label":"vus (accord avec ''les'')"},{"id":"c","label":"vue (accord au féminin)"},{"id":"d","label":"Les deux formes sont acceptées"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'Le pronom ''les'' est COD antéposé. Il déclenche l''accord du PP avec ''voir'' : ''vus''. Contrairement à ''faire + infinitif'' (toujours invariable), les autres verbes de perception (voir, entendre, sentir, regarder, écouter) suivis d''un infinitif peuvent s''accorder avec le COD antéposé si celui-ci est le sujet de l''infinitif. Ici ''les'' est bien sujet logique de ''partir''.', 'Les candidats généralisent parfois l''invariabilité de ''faire + infinitif'' à tous les verbes suivis d''infinitif. Seul ''faire + infinitif'' est systématiquement invariable. Les verbes de perception (voir, entendre, sentir) s''accordent avec le COD antéposé quand celui-ci est sujet de l''infinitif.', 'valide', 'CRPE Français V3', 'free', true),

('a3060000-0000-0000-0000-000000000009', 'Francais', 'orthographe', 'participe_passe_avoir', 'Participe passé avec avoir', 'Difficile', 'vrai_faux', 'Dans « Combien de pages as-tu lues ? », l''accord de ''lues'' est correct.', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'C''est vrai. ''Combien de pages'' est le COD antéposé au verbe ''lire''. Bien que l''accord soit parfois omis dans l''usage courant, la règle exige l''accord avec le COD antéposé : ''pages'' est féminin pluriel, donc ''lues''. Les mots interrogatifs ''combien de'', ''que'', ''quels'' peuvent introduire un COD antéposé déclenchant l''accord.', 'Les candidats oublient fréquemment d''accorder dans ce type de construction interrogative. La position du COD (avant le verbe) est déterminante, quelle que soit la construction syntaxique de la phrase.', 'valide', 'CRPE Français V3', 'free', true),

('a3060000-0000-0000-0000-00000000000a', 'Francais', 'orthographe', 'participe_passe_avoir', 'Participe passé avec avoir', 'Difficile', 'correction_orthographique', 'Corrigez si nécessaire : « La directrice a été félicitée par ses collègues. »', NULL, NULL, '{"mode":"text","acceptableAnswers":["La directrice a été félicitée par ses collègues.","Aucune correction nécessaire."]}'::jsonb, 'La phrase est correcte. Il s''agit d''une construction passive avec l''auxiliaire ''être'' : le PP ''félicitée'' s''accorde avec le sujet ''la directrice'' (féminin singulier). Cela illustre la règle du PP avec être (accord avec le sujet), à ne pas confondre avec la règle du PP avec avoir (accord avec le COD antéposé).', 'Les candidats confondent parfois les règles d''accord avec être et avec avoir. Rappel : PP avec être → accord avec le sujet ; PP avec avoir → accord avec le COD antéposé (s''il existe).', 'valide', 'CRPE Français V3', 'free', true),

-- ─── Batch A — Série 07 : Pluriel des noms composés ──────────────────────────
('a3070000-0000-0000-0000-000000000001', 'Francais', 'orthographe', 'pluriel_noms_composes', 'Pluriel des noms composés', 'Difficile', 'qcm', 'Quel est le pluriel correct de ''un chef-d''œuvre'' ?', NULL, '[{"id":"a","label":"des chef-d''œuvres"},{"id":"b","label":"des chefs-d''œuvres"},{"id":"c","label":"des chefs-d''œuvre"},{"id":"d","label":"des chefs d''œuvres"}]'::jsonb, '{"mode":"single_choice","value":"c"}'::jsonb, '''Chef-d''œuvre'' est composé de nom + préposition + nom. Seul le premier nom (''chef'') prend la marque du pluriel. Le second nom (''œuvre'') reste au singulier car la préposition ''de'' crée un rapport d''appartenance figé. Le pluriel correct est : ''des chefs-d''œuvre''. Le trait d''union est maintenu.', 'L''erreur la plus fréquente est d''accorder les deux noms (''des chefs-d''œuvres'') ou de ne pas accorder le premier. Dans nom + de + nom, seul le premier nom s''accorde généralement.', 'valide', 'CRPE Français V3', 'free', true),

('a3070000-0000-0000-0000-000000000002', 'Francais', 'orthographe', 'pluriel_noms_composes', 'Pluriel des noms composés', 'Difficile', 'correction_orthographique', 'Corrigez si nécessaire : « Elle a acheté plusieurs tire-bouchon. »', NULL, NULL, '{"mode":"text","acceptableAnswers":["Elle a acheté plusieurs tire-bouchons.","Elle a acheté plusieurs tire-bouchons"]}'::jsonb, '''Tire-bouchon'' est composé de verbe (''tire'') + nom (''bouchon''). Le verbe est invariable, mais le nom peut prendre le pluriel si le sens l''autorise. Ici, ''des tire-bouchons'' (plusieurs instruments) : le nom ''bouchon'' prend le pluriel. La forme correcte est : ''des tire-bouchons''.', 'Les candidats laissent parfois ''tire-bouchon'' invariable par crainte de faire une faute. La règle verbe + nom exige d''analyser si le nom est logiquement pluriel.', 'valide', 'CRPE Français V3', 'free', true),

('a3070000-0000-0000-0000-000000000003', 'Francais', 'orthographe', 'pluriel_noms_composes', 'Pluriel des noms composés', 'Difficile', 'vrai_faux', 'Le pluriel de ''un arc-en-ciel'' est ''des arc-en-ciels''.', NULL, NULL, '{"mode":"boolean","value":false}'::jsonb, 'C''est faux. ''Arc-en-ciel'' est composé de nom + préposition + nom. Seul le premier nom (''arc'') prend la marque du pluriel : ''des arcs-en-ciel''. Les mots en seconde position après une préposition restent au singulier. La forme ''des arc-en-ciels'' est doublement incorrecte.', 'Les candidats accordent parfois le dernier mot (''ciels'') par analogie. Dans nom + préposition + nom, seul le premier nom varie.', 'valide', 'CRPE Français V3', 'free', true),

('a3070000-0000-0000-0000-000000000004', 'Francais', 'orthographe', 'pluriel_noms_composes', 'Pluriel des noms composés', 'Difficile', 'qcm', 'Quel est le pluriel de ''un sous-vêtement'' ?', NULL, '[{"id":"a","label":"des sous-vêtements"},{"id":"b","label":"des sous-vêtement"},{"id":"c","label":"des sous vêtements"},{"id":"d","label":"des sou-vêtements"}]'::jsonb, '{"mode":"single_choice","value":"a"}'::jsonb, '''Sous-vêtement'' est composé de préposition (''sous'') + nom (''vêtement''). La préposition est invariable ; seul le nom prend le pluriel : ''des sous-vêtements''. Les mots composés avec ''sous'', ''sur'', ''avant'', ''après'', ''arrière'' suivent cette règle : seul le nom varie.', 'Les candidats laissent parfois le nom invariable (''sous-vêtement'' au pluriel) par crainte de faire une erreur. Rappel : dans préposition + nom, le nom varie normalement.', 'valide', 'CRPE Français V3', 'free', true),

('a3070000-0000-0000-0000-000000000005', 'Francais', 'orthographe', 'pluriel_noms_composes', 'Pluriel des noms composés', 'Difficile', 'qcm', 'Quel est le pluriel de ''un timbre-poste'' ?', NULL, '[{"id":"a","label":"des timbres-postes"},{"id":"b","label":"des timbres-poste"},{"id":"c","label":"des timbre-postes"},{"id":"d","label":"des timbre-poste"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, '''Timbre-poste'' est composé de nom + nom en apposition. ''Poste'' est ici employé adjectivalement (= timbre postal) et reste invariable : ''des timbres-poste''. Cette exception est consacrée par l''usage. De même : ''des timbres-taxe''.', 'La règle nom + nom prévoit l''accord des deux éléments, mais il existe des exceptions consacrées par l''usage où le second nom, employé comme adjectif de catégorie, reste invariable. Ces cas doivent être mémorisés.', 'valide', 'CRPE Français V3', 'free', true),

('a3070000-0000-0000-0000-000000000006', 'Francais', 'orthographe', 'pluriel_noms_composes', 'Pluriel des noms composés', 'Difficile', 'vrai_faux', 'La réforme orthographique de 1990 recommande de supprimer le trait d''union dans la plupart des noms composés.', NULL, NULL, '{"mode":"boolean","value":false}'::jsonb, 'C''est inexact. La réforme de 1990 recommande de souder certains mots composés qui s''écrivaient avec un trait d''union, mais ne supprime pas systématiquement les traits d''union dans les noms composés. Elle concerne surtout la soudure des préfixes et quelques mots spécifiques.', 'Les candidats ont souvent une idée imprécise du contenu de la réforme de 1990. Celle-ci touche principalement les mots avec préfixes, les numéraux, et quelques mots isolés.', 'valide', 'CRPE Français V3', 'free', true),

('a3070000-0000-0000-0000-000000000007', 'Francais', 'orthographe', 'pluriel_noms_composes', 'Pluriel des noms composés', 'Difficile', 'correction_orthographique', 'Corrigez si nécessaire : « Les gardes-fous de la passerelle sont rouillés. »', NULL, NULL, '{"mode":"text","acceptableAnswers":["Les garde-fous de la passerelle sont rouillés.","Les garde-fous de la passerelle sont rouillés"]}'::jsonb, '''Garde-fou'' est composé de verbe (''garde'') + nom (''fou''). Le verbe est invariable ; le nom prend le pluriel : ''des garde-fous''. La forme ''gardes-fous'' (avec le verbe accordé) est incorrecte.', 'Les candidats accordent parfois le premier élément (''gardes'') par analogie avec les noms composés de type nom + nom. Il faut identifier la nature grammaticale de chaque composant : ici ''garde'' est la forme verbale de ''garder'', pas un nom.', 'valide', 'CRPE Français V3', 'free', true),

('a3070000-0000-0000-0000-000000000008', 'Francais', 'orthographe', 'pluriel_noms_composes', 'Pluriel des noms composés', 'Difficile', 'qcm', 'Comment forme-t-on le pluriel de ''un couvre-lit'' ?', NULL, '[{"id":"a","label":"des couvre-lits"},{"id":"b","label":"des couvres-lits"},{"id":"c","label":"des couvre-lit"},{"id":"d","label":"des couvres-lit"}]'::jsonb, '{"mode":"single_choice","value":"a"}'::jsonb, '''Couvre-lit'' = verbe (''couvre'') + nom (''lit''). Le verbe est invariable ; le nom prend le pluriel : ''des couvre-lits''. La règle logique : si un seul objet est impliqué au singulier, le nom reste au singulier ; si plusieurs objets sont impliqués, le nom prend le pluriel.', 'Les candidats hésitent entre ''couvre-lit'' et ''couvre-lits''. La logique sémantique guide : un couvre-lit couvre un lit, donc au pluriel on a des couvre-lits (plusieurs lits couverts).', 'valide', 'CRPE Français V3', 'free', true),

('a3070000-0000-0000-0000-000000000009', 'Francais', 'orthographe', 'pluriel_noms_composes', 'Pluriel des noms composés', 'Difficile', 'vrai_faux', 'Le pluriel de ''un chou-fleur'' est ''des choux-fleurs'' (les deux noms s''accordent).', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'C''est vrai. ''Chou-fleur'' est composé de nom + nom en apposition. Les deux noms ont la même valeur et s''accordent tous les deux : ''des choux-fleurs''. Cette règle s''applique généralement quand les deux éléments sont des noms de même nature. De même : ''des portes-fenêtres''.', 'Les candidats oublient parfois d''accorder le second nom ou n''accordent que le premier. Dans nom + nom (apposition), les deux prennent le pluriel, sauf exceptions consacrées par l''usage.', 'valide', 'CRPE Français V3', 'free', true),

('a3070000-0000-0000-0000-00000000000a', 'Francais', 'orthographe', 'pluriel_noms_composes', 'Pluriel des noms composés', 'Difficile', 'reponse_courte', 'Donnez le pluriel du nom composé : ''un porte-avion''.', NULL, NULL, '{"mode":"text","acceptableAnswers":["des porte-avions","des porte-avions."]}'::jsonb, '''Porte-avion'' est composé de verbe (''porte'') + nom (''avion''). Le verbe est invariable ; le nom prend le pluriel car un porte-avions en porte plusieurs : ''des porte-avions''. Note : l''orthographe ''porte-avions'' (avec s) est la forme standard.', 'Les candidats écrivent parfois ''des portes-avions'' (en accordant le verbe). Rappel : dans verbe + nom, le verbe ne prend jamais la marque du pluriel.', 'valide', 'CRPE Français V3', 'free', true),

-- ─── Batch A — Série 08 : Accord de l'adjectif de couleur ────────────────────
('a3080000-0000-0000-0000-000000000001', 'Francais', 'orthographe', 'accord_adjectif_couleur', 'Accord de l''adjectif de couleur', 'Intermediaire', 'qcm', 'Laquelle de ces formes est correcte pour un groupe nominal féminin pluriel ?', NULL, '[{"id":"a","label":"des robes marrons"},{"id":"b","label":"des robes bordeauxes"},{"id":"c","label":"des robes mauves"},{"id":"d","label":"des robes oranges"}]'::jsonb, '{"mode":"single_choice","value":"c"}'::jsonb, '''Mauve'' fait partie des exceptions : bien qu''il désigne une couleur issue du nom de la fleur de mauve, il est entré dans la langue comme véritable adjectif et s''accorde : ''des robes mauves''. En revanche, ''marron'' (châtaigne), ''bordeaux'' (vin), ''orange'' (fruit) sont des noms employés comme adjectifs et restent invariables.', 'Les candidats accordent parfois ''marron'', ''orange'' ou ''bordeaux'' par analogie avec les adjectifs ordinaires. La règle : adjectif de couleur issu d''un nom commun = invariable. Exceptions qui s''accordent : rose, mauve, fauve, pourpre, écarlate.', 'valide', 'CRPE Français V3', 'free', true),

('a3080000-0000-0000-0000-000000000002', 'Francais', 'orthographe', 'accord_adjectif_couleur', 'Accord de l''adjectif de couleur', 'Intermediaire', 'correction_orthographique', 'Corrigez si nécessaire : « Elle portait des chaussures kaki et une veste kakis. »', NULL, NULL, '{"mode":"text","acceptableAnswers":["Elle portait des chaussures kaki et une veste kaki.","Elle portait des chaussures kaki et une veste kaki"]}'::jsonb, '''Kaki'' est un adjectif de couleur issu d''un nom. Il est invariable : ''des chaussures kaki'', ''une veste kaki''. La forme ''kakis'' est incorrecte. Tous les adjectifs de couleur issus d''un nom commun sont invariables, quel que soit le genre ou le nombre du nom qualifié.', 'L''erreur ''kakis'' vient d''une application trop zélée de la règle d''accord. Il faut distinguer les adjectifs de couleur simples (rouge, vert, bleu → accordent) des adjectifs dérivés de noms (kaki, marron, orange → invariables).', 'valide', 'CRPE Français V3', 'free', true),

('a3080000-0000-0000-0000-000000000003', 'Francais', 'orthographe', 'accord_adjectif_couleur', 'Accord de l''adjectif de couleur', 'Intermediaire', 'vrai_faux', 'L''adjectif ''rose'' est invariable car il est issu du nom de la fleur.', NULL, NULL, '{"mode":"boolean","value":false}'::jsonb, 'C''est faux. ''Rose'' fait partie des exceptions : bien qu''issu du nom de la fleur, il est entré dans la langue comme un véritable adjectif et s''accorde : ''des rubans roses'', ''une robe rose''. Les exceptions qui s''accordent sont : rose, mauve, fauve, pourpre, écarlate, incarnat.', 'Les candidats laissent parfois ''rose'' invariable par application trop stricte de la règle. Il faut mémoriser la liste des exceptions qui s''accordent : rose, mauve, fauve, pourpre, écarlate.', 'valide', 'CRPE Français V3', 'free', true),

('a3080000-0000-0000-0000-000000000004', 'Francais', 'orthographe', 'accord_adjectif_couleur', 'Accord de l''adjectif de couleur', 'Intermediaire', 'qcm', 'Quelle est la forme correcte pour qualifier des pulls masculins pluriels d''une couleur nuancée ?', NULL, '[{"id":"a","label":"des pulls bleus clairs"},{"id":"b","label":"des pulls bleu-clair"},{"id":"c","label":"des pulls bleu clair"},{"id":"d","label":"des pulls bleus-clairs"}]'::jsonb, '{"mode":"single_choice","value":"c"}'::jsonb, 'Quand un adjectif de couleur est accompagné d''un qualificatif de nuance (clair, foncé, vif, pâle, sombre), l''ensemble forme un groupe adjectival composé qui est toujours invariable : ''des pulls bleu clair'', ''des chemises vert foncé''. Ni l''adjectif de couleur ni le qualificatif de nuance ne prennent de marque de pluriel ou de féminin.', 'L''erreur ''des pulls bleus clairs'' vient de l''application de la règle des adjectifs simples. Dès qu''un qualificatif de nuance est ajouté, l''ensemble devient invariable.', 'valide', 'CRPE Français V3', 'free', true),

('a3080000-0000-0000-0000-000000000005', 'Francais', 'orthographe', 'accord_adjectif_couleur', 'Accord de l''adjectif de couleur', 'Intermediaire', 'correction_orthographique', 'Corrigez si nécessaire : « Des rideaux crèmes ornaient la fenêtre. »', NULL, NULL, '{"mode":"text","acceptableAnswers":["Des rideaux crème ornaient la fenêtre.","Des rideaux crème ornaient la fenêtre"]}'::jsonb, '''Crème'' est un adjectif de couleur issu du nom de la crème fraîche. Il est invariable : ''des rideaux crème'' (pas ''crèmes''). Cette règle s''applique à tous les adjectifs de couleur dérivés de noms communs désignant des objets ou substances colorés : crème, sable, noisette, turquoise, marine, bordeaux, marron, etc.', 'L''erreur ''crèmes'' vient d''une assimilation à un adjectif ordinaire. La couleur ''crème'' est clairement reconnaissable comme nom utilisé adjectivement, donc invariable.', 'valide', 'CRPE Français V3', 'free', true),

('a3080000-0000-0000-0000-000000000006', 'Francais', 'orthographe', 'accord_adjectif_couleur', 'Accord de l''adjectif de couleur', 'Intermediaire', 'vrai_faux', 'L''adjectif ''châtain'' présente un cas particulier : il peut s''accorder au féminin sous la forme ''châtaine''.', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'C''est vrai. ''Châtain'' est un cas particulier : au féminin, on peut écrire ''châtaine'' (forme accordée) ou ''châtain'' (invariable). Les deux formes sont admises par les grammairiens, bien que l''Académie française recommande l''accord.', 'Les candidats croient parfois que ''châtain'' est toujours invariable comme les autres noms de couleur. En réalité, son statut est ambigu : il est issu du nom ''châtaigne'' mais l''usage a développé une forme féminine ''châtaine''. Les deux sont tolérées.', 'valide', 'CRPE Français V3', 'free', true),

('a3080000-0000-0000-0000-000000000007', 'Francais', 'orthographe', 'accord_adjectif_couleur', 'Accord de l''adjectif de couleur', 'Intermediaire', 'qcm', 'Laquelle de ces phrases est correctement orthographiée ?', NULL, '[{"id":"a","label":"Des écharpes marines et bordeaux"},{"id":"b","label":"Des écharpes marines et bordeauxes"},{"id":"c","label":"Des écharpes marins et bordeaux"},{"id":"d","label":"Des écharpes marine et bordeaux"}]'::jsonb, '{"mode":"single_choice","value":"d"}'::jsonb, 'Les deux adjectifs sont invariables : ''marine'' (nom → couleur bleu foncé de la mer) et ''bordeaux'' (nom → couleur du vin de Bordeaux). Ils s''écrivent sans accord : ''des écharpes marine et bordeaux''. Attention : ''marine'' en tant qu''adjectif de couleur est invariable, mais ''marine'' en tant qu''adjectif commun (la flotte marine) s''accorde normalement.', 'Les candidats accordent parfois ''marine'' en ''marines'' car sa terminaison rappelle les adjectifs ordinaires. Mais comme adjectif de couleur issu d''un nom, ''marine'' est invariable.', 'valide', 'CRPE Français V3', 'free', true),

('a3080000-0000-0000-0000-000000000008', 'Francais', 'orthographe', 'accord_adjectif_couleur', 'Accord de l''adjectif de couleur', 'Intermediaire', 'correction_orthographique', 'Corrigez si nécessaire : « Les joues pourpres de la fillette trahissaient son émotion. »', NULL, NULL, '{"mode":"text","acceptableAnswers":["Les joues pourpres de la fillette trahissaient son émotion.","Aucune correction nécessaire."]}'::jsonb, 'La phrase est correcte. ''Pourpre'' fait partie des exceptions qui s''accordent : bien qu''issu du nom ''pourpre'', il est devenu un véritable adjectif qualificatif qui s''accorde en genre et en nombre. ''Les joues pourpres'' (féminin pluriel) est donc correct.', 'Les candidats laissent parfois ''pourpre'' invariable par application de la règle générale des noms de couleur. Il faut mémoriser la liste des exceptions : pourpre, écarlate, fauve, mauve, rose s''accordent comme de vrais adjectifs.', 'valide', 'CRPE Français V3', 'free', true),

('a3080000-0000-0000-0000-000000000009', 'Francais', 'orthographe', 'accord_adjectif_couleur', 'Accord de l''adjectif de couleur', 'Intermediaire', 'vrai_faux', 'Dans ''des yeux noisette'', l''adjectif de couleur est invariable.', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'C''est vrai. ''Noisette'' est le nom du fruit utilisé comme adjectif de couleur. Comme tous les adjectifs de couleur issus de noms communs, il est invariable : ''des yeux noisette'', ''une veste noisette''. On écrit donc ''noisette'' sans accord, quel que soit le genre ou le nombre du nom qualifié.', 'L''erreur ''noisettes'' vient d''une assimilation à un adjectif ordinaire. La règle est claire : nom commun utilisé comme adjectif de couleur = invariable, sauf pour les exceptions consacrées (rose, mauve, pourpre, fauve, écarlate).', 'valide', 'CRPE Français V3', 'free', true),

('a3080000-0000-0000-0000-00000000000a', 'Francais', 'orthographe', 'accord_adjectif_couleur', 'Accord de l''adjectif de couleur', 'Intermediaire', 'reponse_courte', 'Citez trois adjectifs de couleur issus de noms communs qui sont invariables.', NULL, NULL, '{"mode":"text","acceptableAnswers":["marron","orange","kaki","crème","bordeaux","marine","noisette","turquoise","sable","marron orange kaki","orange bordeaux marine"]}'::jsonb, 'De nombreux adjectifs de couleur sont issus de noms communs et restent invariables : marron (châtaigne), orange (fruit), kaki (terre), crème (produit laitier), bordeaux (vin), marine (mer), noisette (fruit), turquoise (pierre), sable (matière), nacre, caramel, chocolat, lilas, abricot, citron, lavande... Tous ces noms désignent une substance ou un objet dont la couleur a été empruntée par métonymie.', 'Les candidats mémorisent parfois seulement ''marron'' et ''orange'' et oublient les nombreux autres adjectifs de couleur invariables. La liste est longue ; la règle générale (nom → invariable) est plus efficace que la mémorisation cas par cas.', 'valide', 'CRPE Français V3', 'free', true),

-- ─── Batch A — Série 09 : Accord de tout, même et quelque ────────────────────
('a3090000-0000-0000-0000-000000000001', 'Francais', 'orthographe', 'tout_meme_accord', 'Accord de tout, même et quelque', 'Difficile', 'correction_orthographique', 'Corrigez si nécessaire : « Elle était tout heureuse de sa victoire. »', NULL, NULL, '{"mode":"text","acceptableAnswers":["Elle était toute heureuse de sa victoire.","Elle était toute heureuse de sa victoire"]}'::jsonb, '''Tout'' est ici adverbe (= entièrement). Devant un adjectif féminin commençant par une consonne, ''tout'' adverbe s''accorde : ''toute heureuse''. Cette exception phonétique évite la cacophonie. Devant un adjectif féminin commençant par une voyelle, ''tout'' reste invariable : ''elle était tout émue''.', 'La règle de ''tout'' adverbe est particulièrement délicate : il est invariable devant adjectif masculin (tout surpris) et devant adjectif féminin commençant par une voyelle (tout émue), mais variable devant adjectif féminin commençant par consonne ou h aspiré (toute petite, toute honteuse).', 'valide', 'CRPE Français V3', 'free', true),

('a3090000-0000-0000-0000-000000000002', 'Francais', 'orthographe', 'tout_meme_accord', 'Accord de tout, même et quelque', 'Difficile', 'qcm', 'Dans « Les élèves eux-mêmes ont corrigé leurs copies », quelle est la nature de ''mêmes'' ?', NULL, '[{"id":"a","label":"Adverbe invariable"},{"id":"b","label":"Adjectif indéfini accordé avec ''élèves''"},{"id":"c","label":"Pronom personnel"},{"id":"d","label":"Conjonction de coordination"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'Ici, ''mêmes'' renforce le pronom ''eux'' (pronom de reprise de ''les élèves''). Il joue le rôle d''un adjectif apposé qui insiste sur l''identité du sujet et s''accorde avec ''élèves'' (masculin pluriel). C''est le ''même'' d''identité ou d''insistance, qui s''accorde. À distinguer du ''même'' adverbe (= aussi, jusqu''à) qui est invariable.', 'La confusion porte sur la distinction ''même'' adjectif (accord) vs ''même'' adverbe (invariable). Test : peut-on remplacer ''même'' par ''aussi'' ou ''y compris'' sans changer le sens → adverbe invariable. Sinon → adjectif, accord.', 'valide', 'CRPE Français V3', 'free', true),

('a3090000-0000-0000-0000-000000000003', 'Francais', 'orthographe', 'tout_meme_accord', 'Accord de tout, même et quelque', 'Difficile', 'vrai_faux', 'Dans « Quelques élèves sont absents », ''quelques'' est un adverbe invariable.', NULL, NULL, '{"mode":"boolean","value":false}'::jsonb, 'C''est faux. Dans ''quelques élèves'', ''quelques'' est un adjectif indéfini (déterminant) qui s''accorde avec le nom ''élèves'' (masculin pluriel). L''adverbe ''quelque'' (invariable) apparaît dans le sens de ''si'' ou ''aussi'' devant un adjectif ou un adverbe : « Quelque savant qu''il soit » (= si savant qu''il soit).', 'La distinction adjectif/adverbe pour ''quelque'' est délicate. Moyen de reconnaissance : si ''quelque'' peut être remplacé par ''si'' ou ''aussi'' devant un adjectif → adverbe invariable. S''il introduit un nom → adjectif, accord avec le nom.', 'valide', 'CRPE Français V3', 'free', true),

('a3090000-0000-0000-0000-000000000004', 'Francais', 'orthographe', 'tout_meme_accord', 'Accord de tout, même et quelque', 'Difficile', 'correction_orthographique', 'Corrigez si nécessaire : « Quel que soit votre décision, je la respecterai. »', NULL, NULL, '{"mode":"text","acceptableAnswers":["Quelle que soit votre décision, je la respecterai.","Quelle que soit votre décision, je la respecterai"]}'::jsonb, '''Quel que'' (deux mots) s''accorde avec le sujet du verbe ''être'' qui suit. Ici, le sujet de ''soit'' est ''votre décision'' (féminin singulier), donc il faut ''quelle que soit votre décision''. L''accord se fait toujours avec le sujet du verbe ''être'' qui suit.', 'L''erreur classique est d''écrire ''quelque soit'' (un seul mot, sans accord), qui est doublement incorrect : il faut deux mots (''quel que'') et l''accord avec le sujet du verbe être.', 'valide', 'CRPE Français V3', 'free', true),

('a3090000-0000-0000-0000-000000000005', 'Francais', 'orthographe', 'tout_meme_accord', 'Accord de tout, même et quelque', 'Difficile', 'qcm', 'Dans « Toutes les filles sont venues », quelle est la nature de ''toutes'' ?', NULL, '[{"id":"a","label":"Adverbe"},{"id":"b","label":"Adjectif indéfini (déterminant)"},{"id":"c","label":"Pronom indéfini"},{"id":"d","label":"Nom"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'Dans ''toutes les filles'', ''toutes'' est un adjectif indéfini (déterminant) qui accompagne le nom ''filles'' et s''accorde avec lui (féminin pluriel). C''est le ''tout'' déterminant, qui indique la totalité et qui s''accorde toujours. À distinguer du ''tout'' adverbe (invariable devant un adjectif masculin ou féminin vocalique) et du ''tout'' pronom.', 'Les candidats confondent parfois les différentes natures grammaticales de ''tout''. Méthode : identifier si ''tout'' est devant un nom (déterminant, accord), devant un adjectif (adverbe, règle complexe) ou seul (pronom, accord).', 'valide', 'CRPE Français V3', 'free', true),

('a3090000-0000-0000-0000-000000000006', 'Francais', 'orthographe', 'tout_meme_accord', 'Accord de tout, même et quelque', 'Difficile', 'vrai_faux', 'Dans « Même les professeurs étaient surpris », ''même'' est un adverbe invariable.', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'C''est vrai. Ici, ''même'' signifie ''y compris'', ''jusqu''à'' et ne qualifie aucun nom ni pronom : c''est un adverbe invariable. On peut le remplacer par ''y compris'' ou ''jusqu''aux'' : « Y compris les professeurs étaient surpris ». Ce ''même'' d''insistance ou d''extension est toujours invariable.', 'La confusion vient de la ressemblance avec ''même'' adjectif. Test de remplacement : ''même = y compris / jusqu''à'' → adverbe invariable. ''même = identique / en personne'' → adjectif, accord.', 'valide', 'CRPE Français V3', 'free', true),

('a3090000-0000-0000-0000-000000000007', 'Francais', 'orthographe', 'tout_meme_accord', 'Accord de tout, même et quelque', 'Difficile', 'correction_orthographique', 'Corrigez si nécessaire : « Les résultats même de l''expérience étaient décevants. »', NULL, NULL, '{"mode":"text","acceptableAnswers":["Les résultats mêmes de l''expérience étaient décevants.","Les résultats mêmes de l''expérience étaient décevants"]}'::jsonb, 'Ici, ''même'' est placé après le nom ''résultats'' pour le renforcer (= les résultats eux-mêmes, en personne). C''est le ''même'' d''insistance adjectival, qui s''accorde avec le nom : ''les résultats mêmes''. Ce ''même'' postposé au nom est toujours adjectif et s''accorde.', 'Les candidats laissent parfois ''même'' invariable dans cette position. Règle : ''même'' placé immédiatement après un nom ou un pronom et servant à le renforcer est adjectif et s''accorde.', 'valide', 'CRPE Français V3', 'free', true),

('a3090000-0000-0000-0000-000000000008', 'Francais', 'orthographe', 'tout_meme_accord', 'Accord de tout, même et quelque', 'Difficile', 'qcm', 'Quelle est la forme correcte : « Elle était ___ surprise de voir son ami. »', NULL, '[{"id":"a","label":"toute"},{"id":"b","label":"tout"},{"id":"c","label":"tous"},{"id":"d","label":"toutes"}]'::jsonb, '{"mode":"single_choice","value":"a"}'::jsonb, '''Surprise'' est un adjectif féminin commençant par la consonne ''s''. Devant un adjectif féminin commençant par une consonne (ou h aspiré), ''tout'' adverbe s''accorde et devient ''toute'' pour des raisons euphoniques. On écrit donc : ''elle était toute surprise''. Si l''adjectif féminin commençait par une voyelle, ''tout'' resterait invariable : ''elle était tout étonnée''.', 'L''erreur est d''écrire ''tout surprise'' en appliquant mécaniquement la règle de l''invariabilité de l''adverbe. La règle comporte une exception euphonique : toute + adjectif féminin commençant par consonne ou h aspiré.', 'valide', 'CRPE Français V3', 'free', true),

('a3090000-0000-0000-0000-000000000009', 'Francais', 'orthographe', 'tout_meme_accord', 'Accord de tout, même et quelque', 'Difficile', 'vrai_faux', 'Dans « Quels que soient les obstacles, il persévérera », ''quels que'' est correctement accordé.', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'C''est vrai. ''Quels que'' s''accorde avec le sujet du verbe ''être'' qui suit. Le sujet de ''soient'' est ''les obstacles'' (masculin pluriel) → ''quels que''. La règle : ''quel que'' (deux mots) + verbe être ou verbe attributif + sujet → accord de ''quel'' avec le sujet.', 'L''erreur typique est d''écrire ''quelque'' (un mot) invariable. Rappel : ''quel que'' (deux mots, accord) s''utilise devant le verbe être ; ''quelque'' (un mot) est soit déterminant (accord), soit adverbe de manière (invariable).', 'valide', 'CRPE Français V3', 'free', true),

('a3090000-0000-0000-0000-00000000000a', 'Francais', 'orthographe', 'tout_meme_accord', 'Accord de tout, même et quelque', 'Difficile', 'correction_orthographique', 'Corrigez si nécessaire : « Ils ont tous les même problèmes. »', NULL, NULL, '{"mode":"text","acceptableAnswers":["Ils ont tous les mêmes problèmes.","Ils ont tous les mêmes problèmes"]}'::jsonb, 'La correction : ''même'' doit s''accorder avec ''problèmes'' (masculin pluriel) → ''mêmes''. La forme correcte est : ''Ils ont tous les mêmes problèmes.'' ''Même'' adjectif (= identique, pareil) s''accorde toujours avec le nom qu''il qualifie.', 'Les deux erreurs possibles dans cette phrase concernent ''même'' (non accordé) et la présence de l''apostrophe entre ''tout'' et ''les''. ''Tous les'' est correct ici car ''tous'' est déterminant devant le groupe nominal pluriel.', 'valide', 'CRPE Français V3', 'free', true),

-- ─── Batch A — Série 10 : La ponctuation ─────────────────────────────────────
('a30a0000-0000-0000-0000-000000000001', 'Francais', 'orthographe', 'ponctuation_usages', 'La ponctuation', 'Intermediaire', 'qcm', 'Laquelle de ces phrases contient une erreur de ponctuation ?', NULL, '[{"id":"a","label":"Les enfants, fatigués par la journée, s''endormirent rapidement."},{"id":"b","label":"Les enfants, s''endormirent rapidement."},{"id":"c","label":"Fatigués par la journée, les enfants s''endormirent rapidement."},{"id":"d","label":"Les enfants s''endormirent rapidement, épuisés par la journée."}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'La phrase b contient une erreur grave : la virgule sépare le sujet (''les enfants'') du verbe (''s''endormirent''), ce qui est interdit. La règle fondamentale est que la virgule ne doit jamais s''intercaler entre le sujet et son verbe (ni entre le verbe et son COD). Les phrases a, c et d sont correctes.', 'C''est l''erreur de ponctuation la plus fréquente dans les productions écrites. La virgule entre sujet et verbe est formellement interdite, même quand le sujet est long.', 'valide', 'CRPE Français V3', 'free', true),

('a30a0000-0000-0000-0000-000000000002', 'Francais', 'orthographe', 'ponctuation_usages', 'La ponctuation', 'Intermediaire', 'qcm', 'Quel est le rôle du deux-points dans : « Il n''aimait qu''une chose : lire. » ?', NULL, '[{"id":"a","label":"Séparer deux propositions de même nature"},{"id":"b","label":"Annoncer une explication ou une reformulation"},{"id":"c","label":"Introduire une opposition"},{"id":"d","label":"Marquer une longue pause équivalente au point"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'Le deux-points annonce ici une reformulation ou une précision de ce qui précède : ''une chose'' est précisé par ''lire''. Le deux-points a plusieurs emplois : annoncer une explication, une liste, une citation, ou une reformulation précisant le terme antécédent.', 'Les candidats confondent parfois le deux-points et le point-virgule. Le deux-points annonce ou explique ce qui suit ; le point-virgule relie deux propositions de sens lié mais équivalentes.', 'valide', 'CRPE Français V3', 'free', true),

('a30a0000-0000-0000-0000-000000000003', 'Francais', 'orthographe', 'ponctuation_usages', 'La ponctuation', 'Intermediaire', 'vrai_faux', 'Le point-virgule peut s''utiliser à la place d''une conjonction de coordination pour relier deux propositions de sens lié.', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'C''est vrai. Le point-virgule exprime un lien logique entre deux propositions sans le nommer explicitement. Il peut remplacer une conjonction de coordination dans un texte soutenu : « Il pleuvait ; nous sommes restés » (= ...donc nous sommes restés). C''est le signe de la juxtaposition entre deux propositions de même importance et de sens lié.', 'Les candidats sous-utilisent le point-virgule, le remplaçant par une virgule (trop faible) ou un point (qui coupe le lien). Le point-virgule est le signe de la liaison sémantique forte entre deux propositions indépendantes.', 'valide', 'CRPE Français V3', 'free', true),

('a30a0000-0000-0000-0000-000000000004', 'Francais', 'orthographe', 'ponctuation_usages', 'La ponctuation', 'Intermediaire', 'qcm', 'Dans quel cas les guillemets sont-ils correctement utilisés ?', NULL, '[{"id":"a","label":"Pour mettre en valeur un titre de chapitre dans un livre"},{"id":"b","label":"Pour rapporter les paroles exactes d''une personne (discours direct)"},{"id":"c","label":"Pour séparer deux éléments d''une liste"},{"id":"d","label":"Pour introduire une explication après une proposition"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'Les guillemets (« ») ont trois emplois principaux : 1) le discours direct (paroles rapportées fidèlement) ; 2) les citations (extraits de textes) ; 3) l''emploi distancié ou ironique d''un mot. Les titres d''œuvres s''écrivent en italique, pas entre guillemets. Les listes sont introduites par le deux-points.', 'Les candidats utilisent parfois les guillemets pour des titres d''œuvres ou pour mettre en relief un mot important. En français, les titres d''œuvres s''écrivent en italique ou soulignés à la main, non entre guillemets.', 'valide', 'CRPE Français V3', 'free', true),

('a30a0000-0000-0000-0000-000000000005', 'Francais', 'orthographe', 'ponctuation_usages', 'La ponctuation', 'Intermediaire', 'correction_orthographique', 'Corrigez la ponctuation si nécessaire : « Pour réussir cet examen il faut : travailler régulièrement, réviser ses cours et dormir suffisamment. »', NULL, NULL, '{"mode":"text","acceptableAnswers":["Pour réussir cet examen, il faut : travailler régulièrement, réviser ses cours et dormir suffisamment.","Pour réussir cet examen, il faut travailler régulièrement, réviser ses cours et dormir suffisamment."]}'::jsonb, 'La phrase comporte une erreur : l''absence de virgule après ''examen'' (le complément circonstanciel de but ''pour réussir cet examen'' devrait être suivi d''une virgule). Le deux-points avant la liste est optionnel mais correct. La forme canonique : « Pour réussir cet examen, il faut : travailler régulièrement, réviser ses cours et dormir suffisamment. »', 'Les candidats oublient parfois la virgule après un long complément circonstanciel initial. Règle : un complément circonstanciel placé en tête de phrase doit généralement être suivi d''une virgule pour séparer le thème du propos.', 'valide', 'CRPE Français V3', 'free', true),

('a30a0000-0000-0000-0000-000000000006', 'Francais', 'orthographe', 'ponctuation_usages', 'La ponctuation', 'Intermediaire', 'vrai_faux', 'Dans un dialogue littéraire, le tiret est utilisé pour introduire chaque nouvelle réplique d''un personnage.', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'C''est vrai. Dans la présentation typographique d''un dialogue, chaque changement de locuteur est signalé par un tiret en début de réplique. Cette convention typographique est distincte du tiret d''encadrement (parenthèse renforcée).', 'Les candidats confondent parfois le tiret du dialogue (changement de réplique) et le tiret d''encadrement (parenthèse). Ce sont deux emplois distincts du même signe typographique.', 'valide', 'CRPE Français V3', 'free', true),

('a30a0000-0000-0000-0000-000000000007', 'Francais', 'orthographe', 'ponctuation_usages', 'La ponctuation', 'Intermediaire', 'qcm', 'Laquelle de ces phrases utilise correctement le deux-points ?', NULL, '[{"id":"a","label":"Il a réussi son examen : parce qu''il a beaucoup travaillé."},{"id":"b","label":"Il a réussi son examen : il avait beaucoup travaillé."},{"id":"c","label":"Il : a réussi son examen."},{"id":"d","label":"Il a réussi : son examen était difficile."}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'La phrase b illustre l''emploi correct du deux-points pour annoncer une explication causale : la seconde proposition explique la première. La phrase a est incorrecte : le deux-points ne peut pas être suivi d''une conjonction de subordination (''parce que''). La phrase c est absurde (sujet séparé du verbe). La phrase d a le sens inversé.', 'L''erreur consiste à placer un deux-points suivi d''une conjonction de subordination (''parce que'', ''car'', ''puisque''). Le deux-points prend déjà en charge la valeur causale ou explicative.', 'valide', 'CRPE Français V3', 'free', true),

('a30a0000-0000-0000-0000-000000000008', 'Francais', 'orthographe', 'ponctuation_usages', 'La ponctuation', 'Intermediaire', 'qcm', 'Quel signe de ponctuation faut-il employer pour encadrer une incise (information secondaire insérée dans la phrase) ?', NULL, '[{"id":"a","label":"Des points-virgules"},{"id":"b","label":"Des deux-points"},{"id":"c","label":"Des virgules (ou des tirets, ou des parenthèses)"},{"id":"d","label":"Des guillemets"}]'::jsonb, '{"mode":"single_choice","value":"c"}'::jsonb, 'Une incise (proposition ou groupe nominal apposé, explication secondaire) peut être encadrée par des virgules (niveau neutre), des tirets (niveau expressif ou renforcé), ou des parenthèses (niveau informatif secondaire). Le deux-points ne peut pas encadrer une incise : il n''a qu''un emploi unidirectionnel.', 'Les candidats choisissent parfois le deux-points pour introduire une incise. Le deux-points ne peut pas encadrer une incise : il n''a qu''un emploi unidirectionnel (ce qui vient après explique ou précise ce qui précède).', 'valide', 'CRPE Français V3', 'free', true),

('a30a0000-0000-0000-0000-000000000009', 'Francais', 'orthographe', 'ponctuation_usages', 'La ponctuation', 'Intermediaire', 'vrai_faux', 'La virgule est obligatoire pour séparer des éléments coordonnés par ''et'', ''ou'' ou ''ni'' dans une énumération.', NULL, NULL, '{"mode":"boolean","value":false}'::jsonb, 'C''est faux. Dans une énumération, la virgule s''utilise entre les éléments SAUF avant la dernière conjonction (et, ou, ni) qui la remplace généralement : « Il achète du pain, du lait et du beurre » (pas de virgule avant ''et''). La virgule et la conjonction sont complémentaires, non cumulatives.', 'Les candidats mettent parfois une virgule ET ''et'' dans une énumération : ''du pain, du lait, et du beurre'' — la virgule avant ''et'' final est considérée comme une erreur dans l''usage standard français.', 'valide', 'CRPE Français V3', 'free', true),

('a30a0000-0000-0000-0000-00000000000a', 'Francais', 'orthographe', 'ponctuation_usages', 'La ponctuation', 'Intermediaire', 'reponse_courte', 'Citez deux emplois du deux-points distincts de l''annonce d''une liste.', NULL, NULL, '{"mode":"text","acceptableAnswers":["annoncer une explication","introduire une citation","introduire un discours direct","reformuler","annoncer une cause","annoncer une conséquence","explication et citation","citation et discours direct"]}'::jsonb, 'Le deux-points a plusieurs emplois : 1) annoncer une explication ou une cause (« Il est absent : il est malade ») ; 2) introduire une citation ou un discours direct (« Il dit : Venez demain. ») ; 3) annoncer une reformulation ou une précision (« Il n''aimait qu''une chose : lire ») ; 4) annoncer une conséquence ou une conclusion. Le deux-points est toujours annoncé par une proposition complète.', 'Les candidats associent parfois exclusivement le deux-points aux listes. Ses emplois sont plus variés : explication, citation, reformulation, annonce de discours direct.', 'valide', 'CRPE Français V3', 'free', true),

-- ─── Batch B — Série 1 : Le subjonctif ────────────────────────────────────────
('b3010000-0000-0000-0000-000000000001', 'Francais', 'conjugaison', 'subjonctif_formes_valeurs', 'Le subjonctif', 'Difficile', 'qcm', 'Quelle est la règle générale pour former le radical du subjonctif présent des verbes réguliers ?', NULL, '[{"id":"a","label":"On prend le radical de l''infinitif."},{"id":"b","label":"On prend le radical de la 3e personne du pluriel de l''indicatif présent."},{"id":"c","label":"On prend le radical de la 1re personne du singulier de l''indicatif présent."},{"id":"d","label":"On prend le radical du participe passé."}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'Pour former le subjonctif présent des verbes réguliers, on supprime le -ent de la 3e personne du pluriel de l''indicatif présent (ils chantent → chant-) et on ajoute les terminaisons : -e, -es, -e, -ions, -iez, -ent. Cette règle couvre la grande majorité des verbes.', 'Confondre avec la formation de l''imparfait, qui utilise aussi le radical de la 1re personne du pluriel du présent, mais avec des terminaisons différentes.', 'valide', 'CRPE Français V3', 'free', true),

('b3010000-0000-0000-0000-000000000002', 'Francais', 'conjugaison', 'subjonctif_formes_valeurs', 'Le subjonctif', 'Difficile', 'qcm', 'Laquelle de ces formes verbales est correctement conjuguée au subjonctif présent ?', NULL, '[{"id":"a","label":"que tu sois"},{"id":"b","label":"que tu es"},{"id":"c","label":"que tu sera"},{"id":"d","label":"que tu serait"}]'::jsonb, '{"mode":"single_choice","value":"a"}'::jsonb, '«Être» a un subjonctif présent entièrement irrégulier : que je sois, que tu sois, qu''il soit, que nous soyons, que vous soyez, qu''ils soient. Il faut l''apprendre par cœur car le radical «soi-» ne se déduit d''aucune forme de l''indicatif.', 'Employer la forme de l''indicatif présent «tu es» après «que», ce qui est une erreur fréquente à l''oral comme à l''écrit.', 'valide', 'CRPE Français V3', 'free', true),

('b3010000-0000-0000-0000-000000000003', 'Francais', 'conjugaison', 'subjonctif_formes_valeurs', 'Le subjonctif', 'Difficile', 'vrai_faux', 'Vrai ou faux : après «espérer que», on emploie obligatoirement le subjonctif.', NULL, NULL, '{"mode":"boolean","value":false}'::jsonb, 'C''est faux. «Espérer que» est suivi de l''indicatif : «J''espère qu''il viendra» (futur), «J''espère qu''il vient» (présent). Le subjonctif n''apparaît qu''à la forme négative ou interrogative : «Espères-tu qu''il vienne ?» La confusion avec «souhaiter que» (qui impose le subjonctif) est très fréquente.', 'Appliquer mécaniquement le subjonctif après tous les verbes exprimant un souhait, sans distinguer «espérer que» des autres.', 'valide', 'CRPE Français V3', 'free', true),

('b3010000-0000-0000-0000-000000000004', 'Francais', 'conjugaison', 'subjonctif_formes_valeurs', 'Le subjonctif', 'Difficile', 'qcm', 'Choisissez la phrase grammaticalement correcte :', NULL, '[{"id":"a","label":"Il faut que tu finisses ce travail."},{"id":"b","label":"Il faut que tu finis ce travail."},{"id":"c","label":"Il faut que tu finiras ce travail."},{"id":"d","label":"Il faut que tu finissait ce travail."}]'::jsonb, '{"mode":"single_choice","value":"a"}'::jsonb, '«Il faut que» est une locution impersonnelle exprimant la nécessité ; elle impose obligatoirement le subjonctif. La forme correcte de «finir» au subjonctif présent est «finisses» (base : ils finissent → finiss- + terminaison -es).', 'Employer l''indicatif présent «tu finis» ou le futur «tu finiras» après «il faut que», en confondant la construction avec une proposition complétive à l''indicatif.', 'valide', 'CRPE Français V3', 'free', true),

('b3010000-0000-0000-0000-000000000005', 'Francais', 'conjugaison', 'subjonctif_formes_valeurs', 'Le subjonctif', 'Difficile', 'qcm', 'Parmi ces conjonctions, laquelle n''impose PAS le subjonctif ?', NULL, '[{"id":"a","label":"bien que"},{"id":"b","label":"pour que"},{"id":"c","label":"parce que"},{"id":"d","label":"avant que"}]'::jsonb, '{"mode":"single_choice","value":"c"}'::jsonb, '«Parce que» introduit une proposition causale à l''indicatif : «Il est absent parce qu''il est malade.» En revanche, «bien que» (concession), «pour que» (but) et «avant que» (antériorité) sont des conjonctions qui imposent systématiquement le subjonctif.', 'Considérer que toutes les conjonctions de subordination déclenchent le subjonctif, alors que la plupart (parce que, quand, si, dès que…) sont suivies de l''indicatif.', 'valide', 'CRPE Français V3', 'free', true),

('b3010000-0000-0000-0000-000000000006', 'Francais', 'conjugaison', 'subjonctif_formes_valeurs', 'Le subjonctif', 'Difficile', 'vrai_faux', 'Vrai ou faux : «que nous allions» est la forme correcte du subjonctif présent du verbe «aller» à la 1re personne du pluriel.', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'C''est vrai. «Aller» a un subjonctif irrégulier : que j''aille, que tu ailles, qu''il aille, que nous allions, que vous alliez, qu''ils aillent. Notez le changement de radical : «aill-» aux trois personnes du singulier et à la 3e du pluriel, «all-» aux deux personnes du pluriel.', 'Former *que nous aillions, en appliquant mécaniquement le radical «aill-» à toutes les personnes.', 'valide', 'CRPE Français V3', 'free', true),

('b3010000-0000-0000-0000-000000000007', 'Francais', 'conjugaison', 'subjonctif_formes_valeurs', 'Le subjonctif', 'Difficile', 'reponse_courte', 'Conjuguez «savoir» au subjonctif présent, 1re personne du singulier.', NULL, NULL, '{"mode":"text","acceptableAnswers":["que je sache","je sache"]}'::jsonb, '«Savoir» a un subjonctif irrégulier : que je sache, que tu saches, qu''il sache, que nous sachions, que vous sachiez, qu''ils sachent. Le radical «sach-» ne se déduit pas de l''indicatif présent. C''est l''un des sept irréguliers à mémoriser impérativement pour le CRPE.', 'Former *que je saie ou *que je savais, en cherchant une analogie avec d''autres temps.', 'valide', 'CRPE Français V3', 'free', true),

('b3010000-0000-0000-0000-000000000008', 'Francais', 'conjugaison', 'subjonctif_formes_valeurs', 'Le subjonctif', 'Difficile', 'qcm', 'Dans quelle phrase le subjonctif passé est-il correctement formé ?', NULL, '[{"id":"a","label":"Je doute qu''il ait compris la leçon."},{"id":"b","label":"Je doute qu''il a compris la leçon."},{"id":"c","label":"Je doute qu''il aurait compris la leçon."},{"id":"d","label":"Je doute qu''il avait compris la leçon."}]'::jsonb, '{"mode":"single_choice","value":"a"}'::jsonb, 'Le subjonctif passé se forme avec l''auxiliaire «avoir» ou «être» au subjonctif présent + participe passé. Ici : «ait» (subjonctif présent de «avoir») + «compris». Il exprime une action antérieure à celle de la principale, dans un contexte qui exige le subjonctif («douter que»).', 'Employer le conditionnel passé «aurait compris», qui exprime une hypothèse, non une antériorité dans un contexte de doute.', 'valide', 'CRPE Français V3', 'free', true),

('b3010000-0000-0000-0000-000000000009', 'Francais', 'conjugaison', 'subjonctif_formes_valeurs', 'Le subjonctif', 'Difficile', 'vrai_faux', 'Vrai ou faux : dans «Je pense qu''il ne viendra pas», le verbe de la subordonnée doit être au subjonctif.', NULL, NULL, '{"mode":"boolean","value":false}'::jsonb, 'C''est faux. Après «penser que» à la forme affirmative, on emploie l''indicatif : «Je pense qu''il viendra.» Le subjonctif devient possible (et courant) lorsque «penser» est à la forme négative ou interrogative : «Je ne pense pas qu''il vienne» ou «Penses-tu qu''il vienne ?» La phrase proposée est affirmative, donc l''indicatif s''impose.', 'Appliquer le subjonctif après «penser que» dans tous les cas, sans tenir compte de la forme (affirmative, négative, interrogative) du verbe principal.', 'valide', 'CRPE Français V3', 'free', true),

('b3010000-0000-0000-0000-00000000000a', 'Francais', 'conjugaison', 'subjonctif_formes_valeurs', 'Le subjonctif', 'Difficile', 'reponse_courte', 'Donnez la forme du subjonctif présent de «vouloir» à la 3e personne du pluriel.', NULL, NULL, '{"mode":"text","acceptableAnswers":["qu''ils veuillent","ils veuillent"]}'::jsonb, '«Vouloir» a un subjonctif irrégulier : que je veuille, que tu veuilles, qu''il veuille, que nous voulions, que vous vouliez, qu''ils veuillent. Le radical «veuill-» alterne avec «voul-» aux deux personnes du pluriel, sur le modèle des alternances propres aux verbes en -oir.', 'Former *qu''ils voulent ou *qu''ils veulent, par analogie incorrecte avec l''indicatif présent.', 'valide', 'CRPE Français V3', 'free', true),

-- ─── Batch B — Série 2 : Concordance des temps ───────────────────────────────
('b3020000-0000-0000-0000-000000000001', 'Francais', 'conjugaison', 'concordance_des_temps', 'Concordance des temps', 'Difficile', 'qcm', 'Transformez au discours indirect : Il dit : «Je viendrai demain.» → Il dit que…', NULL, '[{"id":"a","label":"Il dit qu''il vient demain."},{"id":"b","label":"Il dit qu''il viendra demain."},{"id":"c","label":"Il dit qu''il viendrait demain."},{"id":"d","label":"Il dit qu''il venait demain."}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'Lorsque la proposition principale est au présent («il dit»), le temps de la subordonnée reste inchangé par rapport au discours direct. Le futur «viendrai» reste donc au futur «viendra». La transformation porte ici surtout sur le pronom (je → il), pas sur le temps.', 'Appliquer la règle de la principale au passé (futur → conditionnel) même quand la principale est au présent.', 'valide', 'CRPE Français V3', 'free', true),

('b3020000-0000-0000-0000-000000000002', 'Francais', 'conjugaison', 'concordance_des_temps', 'Concordance des temps', 'Difficile', 'qcm', 'Transformez au discours indirect : Il a dit : «Je viendrai demain.» → Il a dit que…', NULL, '[{"id":"a","label":"Il a dit qu''il vient demain."},{"id":"b","label":"Il a dit qu''il viendra demain."},{"id":"c","label":"Il a dit qu''il viendrait le lendemain."},{"id":"d","label":"Il a dit qu''il venait le lendemain."}]'::jsonb, '{"mode":"single_choice","value":"c"}'::jsonb, 'Quand la principale est à un temps du passé («il a dit»), le futur du discours direct devient conditionnel présent au discours indirect (futur dans le passé). L''indicateur de temps «demain» devient «le lendemain». Cette double transformation (temps + adverbe) est caractéristique du discours indirect au passé.', 'Oublier de transformer l''adverbe de temps «demain» en «le lendemain», ou ne pas changer le futur en conditionnel.', 'valide', 'CRPE Français V3', 'free', true),

('b3020000-0000-0000-0000-000000000003', 'Francais', 'conjugaison', 'concordance_des_temps', 'Concordance des temps', 'Difficile', 'vrai_faux', 'Vrai ou faux : dans «Il savait que la Terre tourne autour du Soleil», le présent «tourne» est correct malgré la principale au passé.', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'C''est vrai. Lorsque la subordonnée exprime une vérité générale, scientifique ou universelle, on maintient le présent de l''indicatif même si la principale est au passé. C''est une exception importante à la règle générale de concordance des temps.', 'Appliquer mécaniquement la règle de concordance et écrire «tournait», en ignorant l''exception des vérités générales.', 'valide', 'CRPE Français V3', 'free', true),

('b3020000-0000-0000-0000-000000000004', 'Francais', 'conjugaison', 'concordance_des_temps', 'Concordance des temps', 'Difficile', 'qcm', 'Complétez : «Elle pensait que son frère … déjà parti quand elle arriva.»', NULL, '[{"id":"a","label":"est"},{"id":"b","label":"était"},{"id":"c","label":"avait été"},{"id":"d","label":"serait"}]'::jsonb, '{"mode":"single_choice","value":"c"}'::jsonb, 'La principale est à l''imparfait («pensait»). La subordonnée exprime une action antérieure à «pensait» : il faut donc le plus-que-parfait («avait été»). En concordance des temps : principale au passé + antériorité dans la subordonnée → plus-que-parfait.', 'Employer l''imparfait «était» qui exprimerait une simultanéité, non une antériorité.', 'valide', 'CRPE Français V3', 'free', true),

('b3020000-0000-0000-0000-000000000005', 'Francais', 'conjugaison', 'concordance_des_temps', 'Concordance des temps', 'Difficile', 'reponse_courte', 'Dans la concordance des temps, quel temps de la subordonnée correspond au futur simple quand la principale est au passé ?', NULL, NULL, '{"mode":"text","acceptableAnswers":["conditionnel présent","conditionnel","le conditionnel présent"]}'::jsonb, 'Quand la principale est à un temps du passé, le futur simple du discours direct se transforme en conditionnel présent dans la subordonnée (futur dans le passé). Exemple : «Il promit qu''il reviendrait.» Le conditionnel joue ici un rôle temporel, non modal.', 'Répondre «imparfait», en confondant la correspondance présent→imparfait (simultanéité) avec celle du futur.', 'valide', 'CRPE Français V3', 'free', true),

('b3020000-0000-0000-0000-000000000006', 'Francais', 'conjugaison', 'concordance_des_temps', 'Concordance des temps', 'Difficile', 'qcm', 'Laquelle de ces phrases applique correctement la concordance des temps ?', NULL, '[{"id":"a","label":"Je croyais qu''il viendra."},{"id":"b","label":"Je croyais qu''il viendrait."},{"id":"c","label":"Je croyais qu''il vient."},{"id":"d","label":"Je croyais qu''il est venu."}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'Principale à l''imparfait («croyais») + action postérieure dans la subordonnée → conditionnel présent («viendrait»). La phrase A est incorrecte (futur après passé), C exprime une simultanéité mais avec le présent (incorrect après passé sauf vérité générale), D exprime une antériorité (passé composé → incorrect, il faudrait le plus-que-parfait).', 'Employer le futur «viendra» après un verbe principal au passé, en omettant d''appliquer la concordance.', 'valide', 'CRPE Français V3', 'free', true),

('b3020000-0000-0000-0000-000000000007', 'Francais', 'conjugaison', 'concordance_des_temps', 'Concordance des temps', 'Difficile', 'vrai_faux', 'Vrai ou faux : au discours indirect introduit par un verbe au passé, le présent du discours direct devient toujours imparfait.', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'C''est vrai dans le cas général. Un présent (simultanéité) dans le discours direct devient imparfait au discours indirect quand la principale est au passé. Exemple : «Il dit : Je suis fatigué.» → «Il dit qu''il était fatigué.» L''exception des vérités générales ne s''applique qu''aux faits universels.', 'Maintenir le présent du discours direct sans l''adapter, en croyant que seuls les temps futurs se transforment.', 'valide', 'CRPE Français V3', 'free', true),

('b3020000-0000-0000-0000-000000000008', 'Francais', 'conjugaison', 'concordance_des_temps', 'Concordance des temps', 'Difficile', 'qcm', 'Transformez : Elle a annoncé : «J''ai terminé le rapport hier.» → Elle a annoncé que…', NULL, '[{"id":"a","label":"elle a terminé le rapport la veille."},{"id":"b","label":"elle avait terminé le rapport la veille."},{"id":"c","label":"elle terminerait le rapport la veille."},{"id":"d","label":"elle terminait le rapport la veille."}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'Principale au passé («a annoncé») + passé composé dans le discours direct → plus-que-parfait au discours indirect («avait terminé»). De plus, l''adverbe «hier» devient «la veille». Le passé composé qui exprime une antériorité dans le discours direct se transforme en plus-que-parfait au discours indirect passé.', 'Conserver le passé composé «a terminé» sans le transformer, ou oublier de changer «hier» en «la veille».', 'valide', 'CRPE Français V3', 'free', true),

('b3020000-0000-0000-0000-000000000009', 'Francais', 'conjugaison', 'concordance_des_temps', 'Concordance des temps', 'Difficile', 'vrai_faux', 'Vrai ou faux : dans «Il faudrait que tu aies fini avant midi», la forme «aies fini» est un subjonctif passé.', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'C''est vrai. «Aies fini» est le subjonctif passé du verbe «finir» (auxiliaire «avoir» au subjonctif présent + participe passé «fini»). Il exprime une action qui devra être achevée avant midi, donc antérieure au moment envisagé. La concordance au subjonctif suit les mêmes logiques d''antériorité.', 'Identifier «aies fini» comme un conditionnel passé ou un indicatif passé composé.', 'valide', 'CRPE Français V3', 'free', true),

('b3020000-0000-0000-0000-00000000000a', 'Francais', 'conjugaison', 'concordance_des_temps', 'Concordance des temps', 'Difficile', 'reponse_courte', 'Quel adverbe de temps remplace «maintenant» au discours indirect passé ?', NULL, NULL, '{"mode":"text","acceptableAnswers":["alors","à ce moment-là","à ce moment là"]}'::jsonb, 'Dans les transformations du discours direct en discours indirect passé, les indicateurs de temps changent : «maintenant» → «alors» ou «à ce moment-là», «aujourd''hui» → «ce jour-là», «hier» → «la veille», «demain» → «le lendemain», «ici» → «là». Ces changements reflètent le décalage entre le moment de l''énonciation et celui du récit.', 'Ne pas modifier les adverbes de temps, en ne retenant que le changement des temps verbaux.', 'valide', 'CRPE Français V3', 'free', true),

-- ─── Batch B — Série 3 : L''aspect verbal ────────────────────────────────────
('b3030000-0000-0000-0000-000000000001', 'Francais', 'conjugaison', 'aspect_verbal', 'L''aspect verbal', 'Difficile', 'qcm', 'Quelle notion l''aspect verbal permet-il de décrire ?', NULL, '[{"id":"a","label":"Le moment où se situe l''action par rapport au présent."},{"id":"b","label":"La manière dont le locuteur envisage le déroulement interne de l''action."},{"id":"c","label":"Le mode d''expression de la modalité (doute, ordre, souhait)."},{"id":"d","label":"La personne grammaticale qui accomplit l''action."}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'L''aspect verbal ne concerne pas le moment de l''action (c''est le rôle du temps) mais la façon dont le locuteur envisage son déroulement : l''action est-elle vue en cours, comme un tout achevé, dans ses limites, comme accomplie… ? C''est une dimension interne au procès, distincte de la temporalité.', 'Confondre aspect et temps, en croyant que l''aspect indique simplement si l''action est passée, présente ou future.', 'valide', 'CRPE Français V3', 'free', true),

('b3030000-0000-0000-0000-000000000002', 'Francais', 'conjugaison', 'aspect_verbal', 'L''aspect verbal', 'Difficile', 'vrai_faux', 'Vrai ou faux : l''imparfait exprime un aspect sécant, c''est-à-dire que l''action est présentée en cours de déroulement.', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'C''est vrai. L''imparfait est le temps de l''aspect sécant par excellence : il présente l''action comme coupée dans son déroulement, vue de l''intérieur, sans en montrer le début ni la fin. C''est pourquoi il sert de fond narratif (décor, description, état) dans les récits au passé.', 'Croire que l''imparfait exprime uniquement la répétition ou l''habitude, en ignorant sa valeur aspectuelle fondamentale.', 'valide', 'CRPE Français V3', 'free', true),

('b3030000-0000-0000-0000-000000000003', 'Francais', 'conjugaison', 'aspect_verbal', 'L''aspect verbal', 'Difficile', 'qcm', 'Dans la phrase : «Tout à coup, il entra et posa son manteau», quel aspect exprime le passé simple ?', NULL, '[{"id":"a","label":"Aspect sécant : l''action est vue en cours."},{"id":"b","label":"Aspect global : l''action est vue comme un tout délimité."},{"id":"c","label":"Aspect accompli : le résultat est présent dans la conscience du locuteur."},{"id":"d","label":"Aspect inaccompli : l''action n''est pas terminée."}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'Le passé simple exprime l''aspect global : l''action est présentée comme un tout, avec un début et une fin implicites, sans durée intérieure visible. Il fait avancer le récit (premier plan narratif), contrairement à l''imparfait qui crée l''arrière-plan. Ici, les deux actions successives s''enchaînent comme des points sur la ligne du temps.', 'Confondre aspect global avec accompli : le passé simple ne signifie pas que le résultat est encore présent, contrairement au passé composé.', 'valide', 'CRPE Français V3', 'free', true),

('b3030000-0000-0000-0000-000000000004', 'Francais', 'conjugaison', 'aspect_verbal', 'L''aspect verbal', 'Difficile', 'qcm', 'Quelle est la valeur aspectuelle principale du passé composé ?', NULL, '[{"id":"a","label":"Aspect sécant + inaccompli"},{"id":"b","label":"Aspect global + accompli ancré dans le présent"},{"id":"c","label":"Aspect global + inaccompli"},{"id":"d","label":"Aspect sécant + accompli"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'Le passé composé exprime un aspect accompli (l''action est terminée, son résultat est perçu depuis le présent de l''énonciation) et souvent global (l''action est vue comme un tout). C''est ce lien avec le présent qui le distingue du passé simple, qui exprime aussi un aspect global mais coupé du présent.', 'Confondre passé composé et passé simple sur le seul critère temporel, sans tenir compte du lien aspectuel avec le présent.', 'valide', 'CRPE Français V3', 'free', true),

('b3030000-0000-0000-0000-000000000005', 'Francais', 'conjugaison', 'aspect_verbal', 'L''aspect verbal', 'Difficile', 'vrai_faux', 'Vrai ou faux : le plus-que-parfait exprime un aspect accompli dans le passé, c''est-à-dire une action terminée avant un point de référence passé.', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'C''est vrai. Le plus-que-parfait combine l''aspect accompli (action terminée, résultat acquis) et une temporalité passée : le résultat est présent non pas dans le présent de l''énonciation, mais à un moment passé antérieur. Exemple : «Quand elle arriva, il était parti» : le départ est accompli au moment de l''arrivée.', 'Confondre le plus-que-parfait avec l''imparfait, en oubliant que le plus-que-parfait exprime une antériorité et un aspect accompli.', 'valide', 'CRPE Français V3', 'free', true),

('b3030000-0000-0000-0000-000000000006', 'Francais', 'conjugaison', 'aspect_verbal', 'L''aspect verbal', 'Difficile', 'reponse_courte', 'Dans la phrase «Il dormait quand le téléphone sonna», quel est l''aspect du verbe «dormait» et quel est l''aspect du verbe «sonna» ?', NULL, NULL, '{"mode":"text","acceptableAnswers":["dormait : sécant / sonna : global","dormait sécant sonna global","sécant et global","imparfait sécant passé simple global"]}'::jsonb, '«Dormait» (imparfait) présente l''action en cours de déroulement, vue de l''intérieur : aspect sécant. «Sonna» (passé simple) présente l''action comme un tout ponctuel, délimité : aspect global. Cette opposition fondamentale explique la complémentarité des deux temps dans le récit : l''imparfait crée l''arrière-plan, le passé simple fait avancer l''action.', 'Décrire uniquement la valeur temporelle (passé) sans distinguer les deux aspects différents exprimés par ces deux temps.', 'valide', 'CRPE Français V3', 'free', true),

('b3030000-0000-0000-0000-000000000007', 'Francais', 'conjugaison', 'aspect_verbal', 'L''aspect verbal', 'Difficile', 'qcm', 'Dans la phrase «Je suis épuisé : j''ai couru dix kilomètres», quelle valeur aspectuelle justifie l''emploi du passé composé ?', NULL, '[{"id":"a","label":"L''action est vue en cours de déroulement."},{"id":"b","label":"L''action est accomplie et son résultat (l''épuisement) est présent maintenant."},{"id":"c","label":"L''action est globale, coupée de tout lien avec le présent."},{"id":"d","label":"L''action est habituelle et répétée."}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'Le passé composé exprime ici son aspect accompli à valeur de bilan présent : l''action de courir est terminée, mais son résultat (l''épuisement) est bien présent au moment de l''énonciation. Le lien avec le présent est explicite grâce à «je suis épuisé». C''est la différence essentielle avec le passé simple.', 'Choisir la réponse sur l''aspect global, en confondant passé simple et passé composé dans leur rapport avec le présent.', 'valide', 'CRPE Français V3', 'free', true),

('b3030000-0000-0000-0000-000000000008', 'Francais', 'conjugaison', 'aspect_verbal', 'L''aspect verbal', 'Difficile', 'vrai_faux', 'Vrai ou faux : le présent de l''indicatif peut exprimer un aspect sécant lorsqu''il décrit une action en cours au moment de l''énonciation.', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'C''est vrai. Le présent de l''indicatif peut avoir une valeur sécante (présent d''énonciation ou actuel) : «En ce moment, il travaille.» L''action est saisie dans son déroulement. Mais le présent peut aussi exprimer d''autres valeurs : habitude, vérité générale, présent historique — chacune avec une nuance aspectuelle différente.', 'Croire que l''aspect sécant est l''apanage exclusif de l''imparfait, en ignorant que le présent peut aussi présenter une action en cours.', 'valide', 'CRPE Français V3', 'free', true),

('b3030000-0000-0000-0000-000000000009', 'Francais', 'conjugaison', 'aspect_verbal', 'L''aspect verbal', 'Difficile', 'qcm', 'Quelle est la différence aspectuelle entre «Il lisait le journal» (imparfait) et «Il lut le journal» (passé simple) ?', NULL, '[{"id":"a","label":"L''imparfait indique une action plus longue que le passé simple."},{"id":"b","label":"L''imparfait présente l''action en cours (aspect sécant) ; le passé simple la présente comme un tout délimité (aspect global)."},{"id":"c","label":"L''imparfait exprime une habitude ; le passé simple une action unique."},{"id":"d","label":"Il n''y a aucune différence aspectuelle, seulement une différence de registre."}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'La distinction fondamentale est aspectuelle, pas temporelle : les deux formes situent l''action dans le passé. L''imparfait (aspect sécant) présente la lecture en train de se dérouler, sans en voir la fin. Le passé simple (aspect global) la présente comme un événement accompli dans ses limites. Ce choix a des effets stylistiques majeurs dans les textes narratifs.', 'Réduire la différence à une question de durée ou de répétition, sans mobiliser la notion d''aspect.', 'valide', 'CRPE Français V3', 'free', true),

('b3030000-0000-0000-0000-00000000000a', 'Francais', 'conjugaison', 'aspect_verbal', 'L''aspect verbal', 'Difficile', 'reponse_courte', 'Quel terme désigne l''aspect qui présente l''action comme terminée, dont le résultat est encore perçu au moment de référence ?', NULL, NULL, '{"mode":"text","acceptableAnswers":["accompli","aspect accompli"]}'::jsonb, 'L''aspect accompli (ou perfectif dans certaines terminologies) présente l''action comme terminée, son résultat restant présent dans la conscience du locuteur au moment de référence. Il s''oppose à l''aspect inaccompli qui ne tient pas compte de l''achèvement. Le passé composé et le plus-que-parfait sont les temps typiques de l''aspect accompli en français.', 'Répondre «global» en confondant les deux axes de l''aspect : sécant/global d''une part, accompli/inaccompli d''autre part.', 'valide', 'CRPE Français V3', 'free', true),

-- ─── Batch B — Série 4 : Les valeurs du conditionnel ─────────────────────────
('b3040000-0000-0000-0000-000000000001', 'Francais', 'conjugaison', 'valeurs_conditionnel', 'Les valeurs du conditionnel', 'Intermediaire', 'qcm', 'Dans «Elle avait annoncé qu''elle partirait le soir même», quelle est la valeur du conditionnel «partirait» ?', NULL, '[{"id":"a","label":"Hypothèse non réalisée"},{"id":"b","label":"Futur dans le passé (valeur temporelle)"},{"id":"c","label":"Politesse"},{"id":"d","label":"Information non confirmée"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'Ici, le conditionnel est employé comme futur dans le passé, sa valeur temporelle : la principale est au plus-que-parfait («avait annoncé»), et le conditionnel exprime ce qui, du point de vue de ce moment passé, est postérieur. C''est la concordance des temps classique : principale au passé + futur → conditionnel.', 'Identifier une valeur modale (hypothèse) alors qu''il s''agit d''une valeur purement temporelle liée à la concordance des temps.', 'valide', 'CRPE Français V3', 'free', true),

('b3040000-0000-0000-0000-000000000002', 'Francais', 'conjugaison', 'valeurs_conditionnel', 'Les valeurs du conditionnel', 'Intermediaire', 'qcm', 'Dans «Si j''avais le temps, je t''aiderais», quelle structure hypothétique est employée ?', NULL, '[{"id":"a","label":"Irréel du passé : si + plus-que-parfait → conditionnel passé"},{"id":"b","label":"Potentiel : si + présent → futur simple"},{"id":"c","label":"Irréel du présent : si + imparfait → conditionnel présent"},{"id":"d","label":"Certitude : si + futur → futur simple"}]'::jsonb, '{"mode":"single_choice","value":"c"}'::jsonb, 'La structure «si + imparfait → conditionnel présent» exprime l''irréel du présent : une hypothèse contraire à la réalité actuelle (sous-entendu : je n''ai pas le temps). C''est une condition non remplie dans le présent. À distinguer de l''irréel du passé (si + plus-que-parfait → conditionnel passé) et du potentiel (si + présent → futur).', 'Confondre l''irréel du présent et l''irréel du passé, ou employer «si + conditionnel», ce qui est une faute grammaticale en français.', 'valide', 'CRPE Français V3', 'free', true),

('b3040000-0000-0000-0000-000000000003', 'Francais', 'conjugaison', 'valeurs_conditionnel', 'Les valeurs du conditionnel', 'Intermediaire', 'vrai_faux', 'Vrai ou faux : dans la phrase «Le ministre aurait remis sa démission ce matin», le conditionnel exprime une information non vérifiée.', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'C''est vrai. C''est le conditionnel journalistique ou épistémique : il indique que l''information rapportée n''est pas confirmée par le locuteur, qui ne prend pas en charge sa véracité. Ce conditionnel est très fréquent dans la presse pour rapporter des faits non vérifiés. Il s''oppose au conditionnel hypothétique qui requiert une protase en «si».', 'Identifier ce conditionnel comme un futur dans le passé ou une hypothèse, en ignorant sa valeur de non-prise en charge énonciative.', 'valide', 'CRPE Français V3', 'free', true),

('b3040000-0000-0000-0000-000000000004', 'Francais', 'conjugaison', 'valeurs_conditionnel', 'Les valeurs du conditionnel', 'Intermediaire', 'qcm', 'Dans «Je voudrais un café, s''il vous plaît», quelle valeur a le conditionnel ?', NULL, '[{"id":"a","label":"Hypothèse non réalisée"},{"id":"b","label":"Futur dans le passé"},{"id":"c","label":"Atténuation ou politesse"},{"id":"d","label":"Irréel du présent"}]'::jsonb, '{"mode":"single_choice","value":"c"}'::jsonb, 'Le conditionnel de politesse ou d''atténuation est employé pour adoucir une demande, une affirmation ou un ordre. «Je voudrais» est moins direct que «je veux» et marque une déférence envers l''interlocuteur. C''est un emploi modal très fréquent dans les interactions sociales.', 'Chercher une hypothèse là où il n''y en a pas, en croyant que tout conditionnel exprime une condition.', 'valide', 'CRPE Français V3', 'free', true),

('b3040000-0000-0000-0000-000000000005', 'Francais', 'conjugaison', 'valeurs_conditionnel', 'Les valeurs du conditionnel', 'Intermediaire', 'qcm', 'Quelle phrase contient une erreur grammaticale ?', NULL, '[{"id":"a","label":"Si tu venais, je serais content."},{"id":"b","label":"S''il avait travaillé, il aurait réussi."},{"id":"c","label":"Si tu viendrais, je serais content."},{"id":"d","label":"Si le temps le permet, nous sortirons."}]'::jsonb, '{"mode":"single_choice","value":"c"}'::jsonb, 'En français, la proposition conditionnelle introduite par «si» ne peut jamais contenir un conditionnel. La règle est absolue : «si» + indicatif (présent, imparfait, plus-que-parfait), jamais «si» + conditionnel. La phrase C est donc fautive ; la forme correcte est «si tu venais, je serais content» (irréel du présent).', 'Employer «si + conditionnel» par analogie avec d''autres langues ou par hypercorrection, en croyant qu''une phrase hypothétique requiert le conditionnel dans les deux propositions.', 'valide', 'CRPE Français V3', 'free', true),

('b3040000-0000-0000-0000-000000000006', 'Francais', 'conjugaison', 'valeurs_conditionnel', 'Les valeurs du conditionnel', 'Intermediaire', 'vrai_faux', 'Vrai ou faux : le conditionnel passé peut exprimer l''irréel du passé, c''est-à-dire une hypothèse qui ne s''est pas réalisée.', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'C''est vrai. La structure de l''irréel du passé est : «si + plus-que-parfait → conditionnel passé». Exemple : «Si tu m''avais prévenu, je serais venu.» L''action conditionnée (venir) ne s''est pas réalisée parce que la condition (prévenir) ne s''est pas réalisée. Le conditionnel passé marque ainsi l''irréalité rétrospective.', 'Confondre conditionnel passé (irréel du passé) et conditionnel présent (irréel du présent), en mélangeant les deux structures.', 'valide', 'CRPE Français V3', 'free', true),

('b3040000-0000-0000-0000-000000000007', 'Francais', 'conjugaison', 'valeurs_conditionnel', 'Les valeurs du conditionnel', 'Intermediaire', 'reponse_courte', 'Complétez : «Si nous avions su, nous … (venir) plus tôt.» Donnez la forme correcte du conditionnel.', NULL, NULL, '{"mode":"text","acceptableAnswers":["serions venus","nous serions venus"]}'::jsonb, 'La structure est l''irréel du passé : «si + plus-que-parfait → conditionnel passé». Le verbe «venir» se conjugue avec l''auxiliaire «être» : nous serions venus. Le conditionnel passé est formé de l''auxiliaire au conditionnel présent (serions) + participe passé (venus) avec accord du participe.', 'Former *aurions venu, en utilisant l''auxiliaire «avoir» avec un verbe qui se conjugue avec «être» (venir, partir, aller…).', 'valide', 'CRPE Français V3', 'free', true),

('b3040000-0000-0000-0000-000000000008', 'Francais', 'conjugaison', 'valeurs_conditionnel', 'Les valeurs du conditionnel', 'Intermediaire', 'qcm', 'Dans «Tu devrais réviser davantage avant le concours», quelle valeur a le conditionnel ?', NULL, '[{"id":"a","label":"Futur dans le passé"},{"id":"b","label":"Conseil ou recommandation (valeur modale)"},{"id":"c","label":"Information non confirmée"},{"id":"d","label":"Irréel du présent"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'Le conditionnel de conseil ou de recommandation est une valeur modale fréquente. «Tu devrais» exprime une suggestion polie, moins injonctive que l''impératif «révise». Ce type d''emploi est courant avec les verbes devoir, pouvoir, falloir, valoir mieux. Il atténue l''ordre tout en orientant le comportement de l''interlocuteur.', 'Chercher une structure hypothétique ou une concordance des temps, alors que le conditionnel exprime ici simplement un conseil.', 'valide', 'CRPE Français V3', 'free', true),

('b3040000-0000-0000-0000-000000000009', 'Francais', 'conjugaison', 'valeurs_conditionnel', 'Les valeurs du conditionnel', 'Intermediaire', 'vrai_faux', 'Vrai ou faux : «il ferait beau demain» peut être la transcription au discours indirect d''une phrase au discours direct «il fera beau demain».', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'C''est vrai. C''est la valeur temporelle du conditionnel (futur dans le passé). Mais ici, avec un verbe principal sous-entendu au passé («La météo annonçait qu''il ferait beau demain»), le conditionnel est le résultat de la concordance des temps. Sans contexte de discours indirect, «il ferait beau demain» peut aussi s''interpréter comme une hypothèse ou une information non confirmée.', 'Ne reconnaître qu''une seule valeur possible pour le conditionnel, sans tenir compte du contexte qui détermine l''interprétation.', 'valide', 'CRPE Français V3', 'free', true),

('b3040000-0000-0000-0000-00000000000a', 'Francais', 'conjugaison', 'valeurs_conditionnel', 'Les valeurs du conditionnel', 'Intermediaire', 'reponse_courte', 'Comment appelle-t-on l''emploi du conditionnel dans une phrase comme «Le suspect aurait avoué» (dans un article de presse) ?', NULL, NULL, '{"mode":"text","acceptableAnswers":["conditionnel journalistique","conditionnel épistémique","conditionnel de non-prise en charge","conditionnel d''information non vérifiée"]}'::jsonb, 'On parle de conditionnel journalistique (ou épistémique, ou de non-prise en charge énonciative). Il indique que le locuteur rapporte un fait sans en garantir la vérité. C''est un outil rhétorique qui permet de diffuser une information tout en se dédouanant de sa véracité. Il est très présent dans la presse et les discours rapportés.', 'Répondre «conditionnel hypothétique» ou «irréel», en ignorant cette valeur discursive spécifique.', 'valide', 'CRPE Français V3', 'free', true),

-- ─── Batch B — Série 5 : L''impératif ────────────────────────────────────────
('b3050000-0000-0000-0000-000000000001', 'Francais', 'conjugaison', 'imperatif_formes_emplois', 'L''impératif', 'Facile', 'correction_orthographique', 'Corrigez si nécessaire : «Manges ta soupe sans te plaindre.»', NULL, NULL, '{"mode":"text","acceptableAnswers":["Mange ta soupe sans te plaindre."]}'::jsonb, 'Les verbes en -er perdent le -s à la 2e personne du singulier de l''impératif présent. On écrit donc «mange» et non «manges». Seule exception : devant les pronoms «en» et «y», on rétablit le -s pour des raisons euphoniques (manges-en, vas-y).', 'Conserver le -s par analogie avec l''indicatif présent «tu manges», oubliant que l''impératif des verbes en -er n''a pas de -s.', 'valide', 'CRPE Français V3', 'free', true),

('b3050000-0000-0000-0000-000000000002', 'Francais', 'conjugaison', 'imperatif_formes_emplois', 'L''impératif', 'Facile', 'qcm', 'Laquelle de ces formes à l''impératif est correcte ?', NULL, '[{"id":"a","label":"Vas au marché."},{"id":"b","label":"Va au marché."},{"id":"c","label":"Ves au marché."},{"id":"d","label":"Vais au marché."}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, '«Aller» est un verbe en -er dont l''impératif suit la règle : pas de -s à la 2e personne du singulier. On écrit donc «va». Cependant, devant le pronom «y», on rétablit le -s euphonique : «vas-y». La confusion entre «va» (impératif) et «vas» (impératif devant y) est très fréquente.', 'Écrire «vas» au lieu de «va», par analogie avec «vas-y» où le -s est rétabli devant «y».', 'valide', 'CRPE Français V3', 'free', true),

('b3050000-0000-0000-0000-000000000003', 'Francais', 'conjugaison', 'imperatif_formes_emplois', 'L''impératif', 'Facile', 'vrai_faux', 'Vrai ou faux : à l''impératif affirmatif, les pronoms compléments se placent après le verbe, reliés par un trait d''union.', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'C''est vrai. À l''impératif affirmatif, les pronoms compléments se postposent au verbe avec un trait d''union : «Donne-le-moi», «Appelle-la», «Lève-toi». À l''impératif négatif, on revient à l''ordre habituel, les pronoms précèdent le verbe : «Ne me le donne pas», «Ne l''appelle pas».', 'Placer les pronoms avant le verbe à l''impératif affirmatif, comme dans une phrase ordinaire à l''indicatif.', 'valide', 'CRPE Français V3', 'free', true),

('b3050000-0000-0000-0000-000000000004', 'Francais', 'conjugaison', 'imperatif_formes_emplois', 'L''impératif', 'Facile', 'qcm', 'Quelle est la forme correcte de l''impératif affirmatif pour «tu te lèves» ?', NULL, '[{"id":"a","label":"Te lève !"},{"id":"b","label":"Lève-te !"},{"id":"c","label":"Lève-toi !"},{"id":"d","label":"Lèves-toi !"}]'::jsonb, '{"mode":"single_choice","value":"c"}'::jsonb, 'À l''impératif affirmatif, le pronom réfléchi «te» devient «toi» et se place après le verbe avec un trait d''union : «Lève-toi !». La même règle s''applique à tous les verbes pronominaux : tais-toi, assois-toi, dépêche-toi. Notez aussi l''absence de -s à «lève» (verbe en -er).', 'Écrire «lève-te», en maintenant la forme «te» au lieu de la forme tonique «toi» exigée après le verbe.', 'valide', 'CRPE Français V3', 'free', true),

('b3050000-0000-0000-0000-000000000005', 'Francais', 'conjugaison', 'imperatif_formes_emplois', 'L''impératif', 'Facile', 'correction_orthographique', 'Corrigez si nécessaire : «Ne me dis pas ça !»', NULL, NULL, '{"mode":"text","acceptableAnswers":["Ne me dis pas ça !"]}'::jsonb, 'La phrase est correcte. À l''impératif négatif, les pronoms précèdent le verbe dans l''ordre habituel : ne + pronom(s) + verbe + pas. Ici : «ne» + «me» + «dis» + «pas». Si la phrase avait été affirmative, on aurait : «Dis-le-moi !» (avec postposition et échange de l''ordre).', 'Tenter de corriger une phrase déjà correcte, ou placer les pronoms après le verbe à la forme négative.', 'valide', 'CRPE Français V3', 'free', true),

('b3050000-0000-0000-0000-000000000006', 'Francais', 'conjugaison', 'imperatif_formes_emplois', 'L''impératif', 'Facile', 'qcm', 'Dans «Manges-en davantage», pourquoi y a-t-il un -s à «manges» ?', NULL, '[{"id":"a","label":"Parce que c''est un verbe irrégulier."},{"id":"b","label":"Pour éviter le hiatus entre deux voyelles (liaison euphonique devant «en»)."},{"id":"c","label":"Parce que l''impératif des verbes en -er garde toujours le -s."},{"id":"d","label":"Parce que «en» est un pronom complément direct qui impose le -s."}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'Devant les pronoms «en» et «y», on rétablit le -s euphonique à la 2e personne du singulier des verbes en -er, pour faciliter la liaison : «manges-en» [mɑ̃ʒ-ɑ̃], «vas-y» [va-zi]. Sans ce -s, l''enchaînement vocalique serait difficile. C''est une exception à la règle générale qui supprime le -s.', 'Croire que tous les impératifs des verbes en -er gardent le -s, ou ignorer l''existence de cette exception euphonique.', 'valide', 'CRPE Français V3', 'free', true),

('b3050000-0000-0000-0000-000000000007', 'Francais', 'conjugaison', 'imperatif_formes_emplois', 'L''impératif', 'Facile', 'vrai_faux', 'Vrai ou faux : l''impératif n''existe qu''à trois personnes : 2e personne du singulier, 1re et 2e du pluriel.', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'C''est vrai. L''impératif présent ne se conjugue qu''à trois personnes : 2e sg. (tu), 1re pl. (nous), 2e pl. (vous). Il n''a pas de 1re personne du singulier ni de 3e personne. Cette restriction s''explique par la nature même de l''impératif, qui s''adresse directement à un ou plusieurs interlocuteurs.', 'Croire que l''impératif existe à toutes les personnes, comme les autres modes.', 'valide', 'CRPE Français V3', 'free', true),

('b3050000-0000-0000-0000-000000000008', 'Francais', 'conjugaison', 'imperatif_formes_emplois', 'L''impératif', 'Facile', 'qcm', 'Quelle est la valeur de l''impératif dans la phrase : «Prends un parapluie, il va pleuvoir» ?', NULL, '[{"id":"a","label":"Ordre autoritaire"},{"id":"b","label":"Conseil ou recommandation bienveillante"},{"id":"c","label":"Souhait du locuteur"},{"id":"d","label":"Invitation à une fête"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'L''impératif peut exprimer différentes valeurs selon le contexte : ici, la justification qui suit («il va pleuvoir») et le registre familier indiquent un conseil bienveillant, non un ordre autoritaire. L''impératif peut ainsi exprimer un ordre, une prière, un conseil, un souhait ou une invitation selon le contexte situationnel et la relation entre les interlocuteurs.', 'Réduire systématiquement l''impératif à l''expression d''un ordre, sans tenir compte des valeurs contextuelles.', 'valide', 'CRPE Français V3', 'free', true),

('b3050000-0000-0000-0000-000000000009', 'Francais', 'conjugaison', 'imperatif_formes_emplois', 'L''impératif', 'Facile', 'correction_orthographique', 'Corrigez si nécessaire : «Donnez-moi-le immédiatement !»', NULL, NULL, '{"mode":"text","acceptableAnswers":["Donnez-le-moi immédiatement !"]}'::jsonb, 'À l''impératif affirmatif avec deux pronoms, l''ordre est : verbe + COD + COI (objet direct avant objet indirect). On dit donc «donnez-le-moi» et non «donnez-moi-le». Cette règle s''applique systématiquement : «montre-les-nous», «apporte-le-leur». À la forme négative, l''ordre s''inverse : «ne me le donnez pas».', 'Placer le pronom indirect (moi) avant le pronom direct (le), en suivant l''ordre de la phrase ordinaire à l''indicatif.', 'valide', 'CRPE Français V3', 'free', true),

('b3050000-0000-0000-0000-00000000000a', 'Francais', 'conjugaison', 'imperatif_formes_emplois', 'L''impératif', 'Facile', 'reponse_courte', 'Qu''exprime l''impératif passé dans la phrase «Ayez terminé ce rapport avant lundi» ?', NULL, NULL, '{"mode":"text","acceptableAnswers":["un ordre dont l''accomplissement est attendu avant un moment futur","une action à achever avant un délai","ordre d''accomplissement avant un terme"]}'::jsonb, 'L''impératif passé («ayez terminé», «sois parti», «aie fini») exprime un ordre dont la réalisation complète est exigée avant un moment futur donné. Il indique que l''action doit être accomplie (aspect accompli) avant la limite temporelle mentionnée. C''est une forme rare mais attestée, à connaître pour le CRPE.', 'Confondre l''impératif passé avec le subjonctif passé, qui a une forme identique («que vous ayez terminé»).', 'valide', 'CRPE Français V3', 'free', true),

-- ─── Batch B — Série 6 : Champs lexicaux ─────────────────────────────────────
('b3060000-0000-0000-0000-000000000001', 'Francais', 'lexique', 'champs_lexicaux', 'Champs lexicaux', 'Intermediaire', 'qcm', 'Qu''est-ce qu''un champ lexical ?', NULL, '[{"id":"a","label":"L''ensemble des sens qu''un même mot peut prendre selon le contexte."},{"id":"b","label":"L''ensemble des mots appartenant à la même famille étymologique."},{"id":"c","label":"L''ensemble des mots d''un texte ou d''une langue qui se rapportent à un même thème ou à une même réalité."},{"id":"d","label":"L''ensemble des synonymes d''un mot."}]'::jsonb, '{"mode":"single_choice","value":"c"}'::jsonb, 'Le champ lexical est l''ensemble des mots (noms, verbes, adjectifs, adverbes…) qui, dans un texte ou dans la langue, renvoient à un même thème. Par exemple, le champ lexical de la mer inclut : océan, vague, marée, naviguer, marin, salé, nager… C''est un outil d''analyse thématique et stylistique.', 'Confondre champ lexical avec champ sémantique (les différents sens d''un mot) ou avec famille de mots (mots partageant un même radical).', 'valide', 'CRPE Français V3', 'free', true),

('b3060000-0000-0000-0000-000000000002', 'Francais', 'lexique', 'champs_lexicaux', 'Champs lexicaux', 'Intermediaire', 'vrai_faux', 'Vrai ou faux : les mots «pêcher», «pêcheur», «pêche» et «filet» appartiennent tous au champ lexical de la pêche.', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'C''est vrai. Tous ces mots renvoient au thème de la pêche, même si «filet» appartient aussi à d''autres champs (cuisine, sport, couture). Le champ lexical est déterminé par le contexte : dans un texte sur la pêche, tous ces mots contribuent à ce champ. Notons que «pêcher», «pêcheur» et «pêche» forment aussi une famille de mots (même radical).', 'Exclure «filet» du champ lexical de la pêche parce qu''il appartient aussi à d''autres domaines, en ignorant que la polysémie est normale.', 'valide', 'CRPE Français V3', 'free', true),

('b3060000-0000-0000-0000-000000000003', 'Francais', 'lexique', 'champs_lexicaux', 'Champs lexicaux', 'Intermediaire', 'qcm', 'Quelle est la différence entre champ lexical et champ sémantique ?', NULL, '[{"id":"a","label":"Le champ lexical concerne un texte, le champ sémantique concerne la langue entière."},{"id":"b","label":"Le champ lexical regroupe des mots autour d''un thème ; le champ sémantique regroupe les différents sens d''un même mot."},{"id":"c","label":"Ce sont deux expressions synonymes qui désignent la même notion."},{"id":"d","label":"Le champ lexical s''applique aux noms, le champ sémantique aux verbes."}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'Le champ lexical est un ensemble de mots thématiquement liés (champ de la guerre : soldat, combattre, victoire…). Le champ sémantique est l''ensemble des significations (sens) d''un seul mot : par exemple, «tête» peut signifier la partie du corps, la personne en charge, le début d''une liste… C''est une distinction fondamentale en linguistique.', 'Croire que champ lexical et champ sémantique sont synonymes, en ignorant que le second concerne la polysémie d''un mot unique.', 'valide', 'CRPE Français V3', 'free', true),

('b3060000-0000-0000-0000-000000000004', 'Francais', 'lexique', 'champs_lexicaux', 'Champs lexicaux', 'Intermediaire', 'vrai_faux', 'Vrai ou faux : dans un poème, la superposition de deux champs lexicaux (par exemple la mer et l''amour) peut créer un effet de métaphore filée.', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'C''est vrai. Lorsqu''un texte superpose deux champs lexicaux (l''un littéral, l''autre figuré), il crée une métaphore filée : chaque élément du premier champ renvoie symboliquement au second. C''est un procédé courant en poésie (la mer = l''amour, la tempête = la passion, le naufrage = la rupture). L''analyse de ces superpositions révèle la profondeur du texte.', 'Croire que deux champs lexicaux dans un même texte produisent nécessairement une incohérence ou une erreur stylistique.', 'valide', 'CRPE Français V3', 'free', true),

('b3060000-0000-0000-0000-000000000005', 'Francais', 'lexique', 'champs_lexicaux', 'Champs lexicaux', 'Intermediaire', 'reponse_courte', 'Relevez dans la liste suivante les mots appartenant au champ lexical de la peur : trembler, lumineux, frémir, terreur, courageux, effroi, pâlir, ombre.', NULL, NULL, '{"mode":"text","acceptableAnswers":["trembler, frémir, terreur, effroi, pâlir","trembler frémir terreur effroi pâlir"]}'::jsonb, 'Appartiennent au champ lexical de la peur : trembler (réaction physique de la peur), frémir (frisson de peur), terreur (peur intense), effroi (peur soudaine et intense), pâlir (réaction physique due à la peur). En revanche, «lumineux» et «courageux» n''appartiennent pas à ce champ, et «ombre» y est associé connotativement mais n''en fait pas partie de manière certaine sans contexte.', 'Inclure «ombre» systématiquement, par association connotative, sans vérifier son appartenance thématique directe.', 'valide', 'CRPE Français V3', 'free', true),

('b3060000-0000-0000-0000-000000000006', 'Francais', 'lexique', 'champs_lexicaux', 'Champs lexicaux', 'Intermediaire', 'qcm', 'Qu''est-ce que l''isotopie sémantique dans un texte ?', NULL, '[{"id":"a","label":"La répétition d''un même mot sous différentes formes grammaticales."},{"id":"b","label":"La récurrence de traits sémantiques (sèmes) communs qui assure la cohérence du texte."},{"id":"c","label":"La présence d''un seul champ lexical dominant dans tout le texte."},{"id":"d","label":"L''emploi de synonymes pour éviter les répétitions."}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'L''isotopie est le concept introduit par A.-J. Greimas : c''est la récurrence de sèmes (traits sémantiques élémentaires) qui garantit la cohérence sémantique d''un texte. Par exemple, dans un texte sur la chaleur, les mots brûler, soleil, transpirer, fournaise partagent le sème /chaleur/. Cette répétition de traits communs tisse la signification du texte.', 'Confondre isotopie et simple répétition lexicale, ou avec la notion de champ lexical à laquelle elle est liée mais distincte.', 'valide', 'CRPE Français V3', 'free', true),

('b3060000-0000-0000-0000-000000000007', 'Francais', 'lexique', 'champs_lexicaux', 'Champs lexicaux', 'Intermediaire', 'vrai_faux', 'Vrai ou faux : un mot connoté appartient à un champ lexical de manière aussi certaine qu''un mot qui y appartient par dénotation.', NULL, NULL, '{"mode":"boolean","value":false}'::jsonb, 'C''est faux. La dénotation (sens littéral, objectif d''un mot) est le critère premier pour établir l''appartenance à un champ lexical. La connotation (sens second, subjectif, culturel) peut rapprocher un mot d''un champ sans qu''il y appartienne strictement. Par exemple, «noir» connote le deuil mais n''appartient pas directement au champ lexical de la mort.', 'Inclure dans un champ lexical tous les mots qui évoquent vaguement son thème, sans distinguer dénotation et connotation.', 'valide', 'CRPE Français V3', 'free', true),

('b3060000-0000-0000-0000-000000000008', 'Francais', 'lexique', 'champs_lexicaux', 'Champs lexicaux', 'Intermediaire', 'qcm', 'Dans le texte : «Le soleil brûlait, l''asphalte fondait, les passants cherchaient l''ombre, haletants», quel champ lexical domine ?', NULL, '[{"id":"a","label":"Le champ lexical de l''été"},{"id":"b","label":"Le champ lexical de la chaleur"},{"id":"c","label":"Le champ lexical de la ville"},{"id":"d","label":"Le champ lexical de la souffrance"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'Les mots «brûlait», «fondait», «haletants» et l''action de «chercher l''ombre» constituent le champ lexical de la chaleur. Bien que l''été et la souffrance soient présents par connotation, et la ville par «asphalte» et «passants», c''est la chaleur qui domine thématiquement le texte. Un champ lexical peut englober des termes d''autres classes grammaticales.', 'Choisir «été» ou «souffrance» en se basant sur une impression générale plutôt que sur un relevé précis des mots.', 'valide', 'CRPE Français V3', 'free', true),

('b3060000-0000-0000-0000-000000000009', 'Francais', 'lexique', 'champs_lexicaux', 'Champs lexicaux', 'Intermediaire', 'reponse_courte', 'Quelle est la différence entre champ lexical et famille de mots ? Donnez un exemple.', NULL, NULL, '{"mode":"text","acceptableAnswers":["le champ lexical regroupe des mots thématiquement liés, la famille de mots partage un même radical","champ lexical : thème commun ; famille de mots : radical commun","champ lexical thème famille mots radical"]}'::jsonb, 'Le champ lexical regroupe des mots liés par un thème commun, quelle que soit leur étymologie. La famille de mots regroupe des mots partageant un même radical, quelle que soit leur signification thématique. Exemple : dans le champ lexical de la pluie, on trouve averse, parapluie, mouillé, flaque — des mots sans lien étymologique. La famille du mot «eau» inclut aquatique, aqueuse, aqueduc — qui n''appartiennent pas tous au même champ.', 'Considérer que champ lexical et famille de mots sont synonymes parce que certains mots d''une même famille partagent souvent le même thème.', 'valide', 'CRPE Français V3', 'free', true),

('b3060000-0000-0000-0000-00000000000a', 'Francais', 'lexique', 'champs_lexicaux', 'Champs lexicaux', 'Intermediaire', 'qcm', 'Quelle est la fonction principale de l''analyse du champ lexical dans l''étude d''un texte littéraire ?', NULL, '[{"id":"a","label":"Corriger les fautes d''orthographe des élèves."},{"id":"b","label":"Identifier les thèmes dominants et les intentions stylistiques de l''auteur."},{"id":"c","label":"Établir l''étymologie des mots employés."},{"id":"d","label":"Vérifier la richesse du vocabulaire de l''auteur."}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'L''analyse des champs lexicaux permet d''identifier les thèmes dominants d''un texte, les obsessions de l''auteur, les réseaux de sens et les effets stylistiques intentionnels. Elle révèle comment le choix lexical construit le sens et l''effet esthétique. C''est l''un des outils fondamentaux de l''explication de texte au CRPE.', 'Réduire l''analyse lexicale à une simple comptabilité des mots, sans en dégager la signification interprétative.', 'valide', 'CRPE Français V3', 'free', true),

-- ─── Batch B — Série 7 : Registres et niveaux de langue ──────────────────────
('b3070000-0000-0000-0000-000000000001', 'Francais', 'lexique', 'registres_niveaux_langue', 'Registres et niveaux de langue', 'Intermediaire', 'qcm', 'Quelle est la différence fondamentale entre «niveau de langue» et «registre littéraire» ?', NULL, '[{"id":"a","label":"Ce sont deux termes synonymes désignant le style d''un texte."},{"id":"b","label":"Le niveau de langue caractérise la situation sociolinguistique du discours ; le registre littéraire désigne un effet esthétique produit par le texte."},{"id":"c","label":"Le niveau de langue s''applique à l''oral, le registre littéraire s''applique à l''écrit."},{"id":"d","label":"Le registre littéraire est plus élevé que le niveau de langue."}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'Les niveaux de langue (soutenu, courant, familier, argotique) décrivent l''adaptation du locuteur à sa situation de communication selon des critères sociolinguistiques. Les registres littéraires (comique, tragique, lyrique, épique, satirique, pathétique…) désignent les effets et tonalités esthétiques produits par un texte littéraire. Ces deux notions sont indépendantes.', 'Utiliser les termes «niveau de langue» et «registre» de façon interchangeable, ce qui crée une confusion conceptuelle grave lors des épreuves.', 'valide', 'CRPE Français V3', 'free', true),

('b3070000-0000-0000-0000-000000000002', 'Francais', 'lexique', 'registres_niveaux_langue', 'Registres et niveaux de langue', 'Intermediaire', 'qcm', 'Classez ces trois formulations du plus soutenu au plus familier : A. «Je suis dans l''impossibilité de venir» / B. «Je ne peux pas venir» / C. «Je peux pas venir»', NULL, '[{"id":"a","label":"A → B → C"},{"id":"b","label":"C → B → A"},{"id":"c","label":"B → A → C"},{"id":"d","label":"A → C → B"}]'::jsonb, '{"mode":"single_choice","value":"a"}'::jsonb, 'A est le niveau soutenu : tournure nominale («dans l''impossibilité de»), vocabulaire précis. B est le niveau courant ou standard : phrase correcte avec la négation complète. C est le niveau familier : omission du «ne» de négation, typique de l''oral spontané. Cette gradation illustre les critères lexicaux et syntaxiques qui distinguent les niveaux.', 'Classer C avant B, en ignorant que la suppression du «ne» est un marqueur clairement familier.', 'valide', 'CRPE Français V3', 'free', true),

('b3070000-0000-0000-0000-000000000003', 'Francais', 'lexique', 'registres_niveaux_langue', 'Registres et niveaux de langue', 'Intermediaire', 'vrai_faux', 'Vrai ou faux : un texte peut être rédigé dans un niveau de langue soutenu et relever en même temps du registre comique.', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'C''est vrai. Niveau de langue et registre littéraire sont deux dimensions indépendantes. Molière, par exemple, écrit en vers (niveau soutenu) des comédies relevant du registre comique. De même, un niveau familier peut servir un registre pathétique ou lyrique. Les deux notions se combinent librement.', 'Croire qu''un niveau soutenu correspond nécessairement au registre tragique ou épique, et un niveau familier au registre comique.', 'valide', 'CRPE Français V3', 'free', true),

('b3070000-0000-0000-0000-000000000004', 'Francais', 'lexique', 'registres_niveaux_langue', 'Registres et niveaux de langue', 'Intermediaire', 'reponse_courte', 'Citez trois critères linguistiques qui permettent de distinguer les niveaux de langue.', NULL, NULL, '{"mode":"text","acceptableAnswers":["lexique, morphologie, syntaxe","lexique syntaxe morphologie","vocabulaire, grammaire, syntaxe","lexique, syntaxe, phonétique"]}'::jsonb, 'Les trois critères principaux sont : le lexique (vocabulaire choisi : «automobile» / «voiture» / «caisse»), la morphologie (formes grammaticales : maintien ou suppression de la négation «ne», formes verbales…) et la syntaxe (construction des phrases : complètes vs elliptiques, ordre canonique vs inversé). On peut aussi citer la phonétique à l''oral (liaison, élision, déformation).', 'Citer uniquement le vocabulaire sans mentionner les critères syntaxiques et morphologiques, qui sont tout aussi importants.', 'valide', 'CRPE Français V3', 'free', true),

('b3070000-0000-0000-0000-000000000005', 'Francais', 'lexique', 'registres_niveaux_langue', 'Registres et niveaux de langue', 'Intermediaire', 'qcm', 'Quel registre littéraire est principalement à l''œuvre dans un texte qui cherche à toucher le lecteur par la description de la souffrance et de la misère humaine ?', NULL, '[{"id":"a","label":"Registre comique"},{"id":"b","label":"Registre épique"},{"id":"c","label":"Registre pathétique"},{"id":"d","label":"Registre satirique"}]'::jsonb, '{"mode":"single_choice","value":"c"}'::jsonb, 'Le registre pathétique vise à susciter la pitié, la compassion, l''émotion du lecteur face à la souffrance ou au malheur. Il se caractérise par un vocabulaire expressif de la douleur, des figures d''insistance (anaphore, hyperbole), des tonalités plaintives. À distinguer du registre lyrique (expression du moi et de ses émotions intimes) et du registre tragique (fatalité et grandeur face à la mort).', 'Confondre registre pathétique et registre lyrique, qui partagent l''expression de l''émotion mais selon des modalités différentes.', 'valide', 'CRPE Français V3', 'free', true),

('b3070000-0000-0000-0000-000000000006', 'Francais', 'lexique', 'registres_niveaux_langue', 'Registres et niveaux de langue', 'Intermediaire', 'vrai_faux', 'Vrai ou faux : enseigner les niveaux de langue aux élèves revient à leur apprendre que le langage familier est incorrect et doit être évité.', NULL, NULL, '{"mode":"boolean","value":false}'::jsonb, 'C''est faux. L''objectif n''est pas de hiérarchiser les niveaux de langue en corrects/incorrects, mais d''apprendre aux élèves à adapter leur discours au contexte, au destinataire et à l''enjeu de communication. Le niveau familier est légitime dans les échanges informels. L''école doit enrichir le répertoire langagier des élèves, non stigmatiser leurs usages.', 'Confondre enseignement des niveaux de langue avec correction des «mauvaises» façons de parler, ce qui est une erreur didactique grave.', 'valide', 'CRPE Français V3', 'free', true),

('b3070000-0000-0000-0000-000000000007', 'Francais', 'lexique', 'registres_niveaux_langue', 'Registres et niveaux de langue', 'Intermediaire', 'qcm', 'Lequel de ces termes appartient au niveau argotique ?', NULL, '[{"id":"a","label":"se trouver dans l''impossibilité"},{"id":"b","label":"ne pas pouvoir"},{"id":"c","label":"pouvoir pas"},{"id":"d","label":"être dans le pétrin"}]'::jsonb, '{"mode":"single_choice","value":"d"}'::jsonb, '«Être dans le pétrin» est une expression familière/argotique (origine : le pétrin est le bac où l''on pétrit la pâte, d''où l''idée d''être englué dans une situation difficile). Les autres options illustrent le niveau soutenu (A), courant (B) et familier avec élision du «ne» (C). Le niveau argotique se caractérise par un vocabulaire codé, souvent d''origine populaire ou de groupes sociaux spécifiques.', 'Confondre niveau familier et argotique, qui sont deux niveaux distincts : l''argot est plus marqué socialement et plus codé.', 'valide', 'CRPE Français V3', 'free', true),

('b3070000-0000-0000-0000-000000000008', 'Francais', 'lexique', 'registres_niveaux_langue', 'Registres et niveaux de langue', 'Intermediaire', 'qcm', 'Quel registre littéraire caractérise un texte où le héros affronte une destinée implacable avec grandeur et noblesse ?', NULL, '[{"id":"a","label":"Registre pathétique"},{"id":"b","label":"Registre tragique"},{"id":"c","label":"Registre épique"},{"id":"d","label":"Registre lyrique"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'Le registre tragique met en scène un héros confronté à une fatalité inévitable, à un conflit insurmontable, souvent face à la mort, avec une dimension de grandeur et de noblesse. Il se distingue du registre épique (exaltation des exploits guerriers collectifs), du pathétique (apitoiement sur la souffrance) et du lyrique (expression du moi et de ses émotions intimes).', 'Confondre registre tragique et pathétique, car les deux évoquent la souffrance, mais le tragique implique la fatalité et la grandeur que le pathétique n''a pas.', 'valide', 'CRPE Français V3', 'free', true),

('b3070000-0000-0000-0000-000000000009', 'Francais', 'lexique', 'registres_niveaux_langue', 'Registres et niveaux de langue', 'Intermediaire', 'vrai_faux', 'Vrai ou faux : en France, la norme linguistique scolaire correspond au niveau de langue courant ou standard.', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'C''est vrai. La norme scolaire vise le niveau courant ou standard : celui de la communication ordinaire soignée, ni trop soutenu ni familier. L''école n''a pas pour objectif de former des locuteurs exclusivement en registre soutenu, mais de donner accès au registre standard qui permet l''insertion sociale et professionnelle, tout en élargissant le répertoire vers le soutenu.', 'Croire que la norme scolaire correspond au niveau soutenu ou littéraire, ce qui est une vision élitiste et inexacte de la mission de l''école.', 'valide', 'CRPE Français V3', 'free', true),

('b3070000-0000-0000-0000-00000000000a', 'Francais', 'lexique', 'registres_niveaux_langue', 'Registres et niveaux de langue', 'Intermediaire', 'reponse_courte', 'Citez deux registres littéraires distincts des niveaux de langue, en donnant pour chacun une caractéristique principale.', NULL, NULL, '{"mode":"text","acceptableAnswers":["comique : faire rire / tragique : fatalité et grandeur","lyrique : expression du moi / épique : exploits collectifs","satirique : critiquer par le rire / pathétique : susciter la pitié","comique tragique lyrique épique satirique pathétique"]}'::jsonb, 'Les registres littéraires les plus courants sont : le comique (faire rire par décalage, absurde, ironie), le tragique (fatalité, grandeur face à la mort), le lyrique (expression des émotions intimes du je), l''épique (exaltation des exploits héroïques), le pathétique (susciter la pitié face à la souffrance), le satirique (critique par le rire ou l''ironie), le polémique (combat d''idées). Chacun produit un effet esthétique spécifique.', 'Citer des niveaux de langue (soutenu, familier) à la place des registres littéraires, ce qui témoigne d''une confusion fondamentale.', 'valide', 'CRPE Français V3', 'free', true),

-- ─── Batch B — Série 8 : Polysémie et homonymie ──────────────────────────────
('b3080000-0000-0000-0000-000000000001', 'Francais', 'lexique', 'polysemie_homonymie', 'Polysémie et homonymie', 'Intermediaire', 'qcm', 'Quelle est la définition de la polysémie ?', NULL, '[{"id":"a","label":"Deux mots différents ayant exactement la même prononciation."},{"id":"b","label":"Un seul mot ayant plusieurs sens reliés entre eux par une relation sémantique."},{"id":"c","label":"Deux mots phonétiquement proches mais de sens différents."},{"id":"d","label":"Un mot qui a le même sens dans plusieurs langues."}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'La polysémie désigne le fait qu''un seul et même mot (une seule entrée dans le dictionnaire) possède plusieurs sens liés entre eux. Exemple : «feuille» peut désigner une feuille d''arbre, une feuille de papier, une feuille d''or. Ces sens sont liés par une analogie de forme plate et fine. C''est différent de l''homonymie où les mots sont d''origines distinctes.', 'Confondre polysémie et homonymie, en croyant que tout mot à plusieurs sens est un homonyme.', 'valide', 'CRPE Français V3', 'free', true),

('b3080000-0000-0000-0000-000000000002', 'Francais', 'lexique', 'polysemie_homonymie', 'Polysémie et homonymie', 'Intermediaire', 'vrai_faux', 'Vrai ou faux : «avocat» (juriste) et «avocat» (fruit) sont deux sens d''un même mot polysémique.', NULL, NULL, '{"mode":"boolean","value":false}'::jsonb, 'C''est faux. «Avocat» (juriste) vient du latin «advocatus» (celui qu''on appelle à son secours), tandis qu''avocat (fruit) vient du nahuatl «ahuacatl» via l''espagnol «aguacate». Ces deux mots ont des étymologies entièrement différentes : ce sont des homonymes, non un mot polysémique. La distinction se fait grâce à l''étymologie.', 'Considérer comme polysémique tout mot ayant plusieurs sens, sans vérifier si ces sens partagent la même étymologie.', 'valide', 'CRPE Français V3', 'free', true),

('b3080000-0000-0000-0000-000000000003', 'Francais', 'lexique', 'polysemie_homonymie', 'Polysémie et homonymie', 'Intermediaire', 'qcm', 'Lequel de ces exemples illustre la paronymie ?', NULL, '[{"id":"a","label":"ver / vers / verre / vert"},{"id":"b","label":"conjoncture / conjecture"},{"id":"c","label":"tête : partie du corps / tête : chef d''une entreprise"},{"id":"d","label":"louer : prendre en location / louer : célébrer"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, '«Conjoncture» (situation économique d''ensemble) et «conjecture» (hypothèse, supposition) sont des paronymes : ils sont phonétiquement très proches mais de sens entièrement différents, ce qui génère des confusions fréquentes. A illustre l''homonymie (mots homophones), C et D illustrent la polysémie (plusieurs sens du même mot).', 'Confondre paronymie et homonymie, en croyant que les paronymes sont simplement des mots qui se ressemblent à l''écrit.', 'valide', 'CRPE Français V3', 'free', true),

('b3080000-0000-0000-0000-000000000004', 'Francais', 'lexique', 'polysemie_homonymie', 'Polysémie et homonymie', 'Intermediaire', 'qcm', 'Quel critère permet de distinguer la polysémie de l''homonymie ?', NULL, '[{"id":"a","label":"Le nombre de syllabes du mot."},{"id":"b","label":"L''étymologie : même origine = polysémie ; origines différentes = homonymie."},{"id":"c","label":"La classe grammaticale : même classe = polysémie ; classes différentes = homonymie."},{"id":"d","label":"La fréquence d''emploi dans la langue."}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'Le critère décisif est étymologique : si deux sens d''un mot remontent à la même origine, il y a polysémie (un mot, plusieurs sens liés). Si deux mots de forme identique ont des étymologies distinctes, il y a homonymie (deux mots différents de forme accidentellement identique). Le dictionnaire indique l''étymologie pour trancher.', 'Utiliser la classe grammaticale comme critère, alors que des homonymes peuvent appartenir à la même classe (avocat juriste / avocat fruit : tous deux noms communs).', 'valide', 'CRPE Français V3', 'free', true),

('b3080000-0000-0000-0000-000000000005', 'Francais', 'lexique', 'polysemie_homonymie', 'Polysémie et homonymie', 'Intermediaire', 'vrai_faux', 'Vrai ou faux : «éminent» (remarquable, illustre) et «imminent» (qui va arriver très prochainement) sont des paronymes.', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'C''est vrai. «Éminent» (du latin «eminere», se distinguer) et «imminent» (du latin «imminere», menacer) sont phonétiquement très proches mais de sens entièrement différents : ce sont des paronymes. La confusion entre ces deux mots est une erreur fréquente, notamment dans les écrits professionnels.', 'Les confondre effectivement dans une phrase, ce qui est précisément l''erreur que la connaissance des paronymes permet d''éviter.', 'valide', 'CRPE Français V3', 'free', true),

('b3080000-0000-0000-0000-000000000006', 'Francais', 'lexique', 'polysemie_homonymie', 'Polysémie et homonymie', 'Intermediaire', 'reponse_courte', 'Expliquez la différence entre le sens propre et le sens figuré d''un mot, avec un exemple.', NULL, NULL, '{"mode":"text","acceptableAnswers":["sens propre : sens littéral, premier / sens figuré : sens métaphorique, dérivé","sens propre littéral sens figuré métaphorique","sens propre premier sens figuré image métaphore"]}'::jsonb, 'Le sens propre (ou littéral) est le sens premier, concret, originel d''un mot. Le sens figuré est un sens dérivé par métaphore ou analogie. Exemple : «dévorer» au sens propre signifie manger voracement ; au sens figuré, «dévorer un livre» signifie le lire avec avidité. Les sens figurés lexicalisés s''éloignent progressivement du sens propre pour devenir des sens standards enregistrés dans les dictionnaires.', 'Croire que le sens propre est le sens le plus fréquent, alors que pour certains mots polysémiques, le sens figuré peut être plus courant.', 'valide', 'CRPE Français V3', 'free', true),

('b3080000-0000-0000-0000-000000000007', 'Francais', 'lexique', 'polysemie_homonymie', 'Polysémie et homonymie', 'Intermediaire', 'qcm', 'Les mots «collision» (choc entre deux corps) et «collusion» (accord secret entre deux parties) sont des exemples de :', NULL, '[{"id":"a","label":"Polysémie"},{"id":"b","label":"Homonymie"},{"id":"c","label":"Paronymie"},{"id":"d","label":"Synonymie"}]'::jsonb, '{"mode":"single_choice","value":"c"}'::jsonb, 'Ces deux mots sont des paronymes : phonétiquement très proches (collision [kɔliziɔ̃] / collusion [kɔlyziɔ̃]), ils sont souvent confondus à l''écrit et à l''oral. Pourtant leurs sens sont radicalement différents : «collision» vient du latin «collidere» (heurter), «collusion» du latin «colludere» (jouer de concert). Les confondre constitue une faute de sens grave.', 'Répondre «homonymie», en oubliant que les homonymes ont une forme identique, tandis que les paronymes ont des formes seulement proches.', 'valide', 'CRPE Français V3', 'free', true),

('b3080000-0000-0000-0000-000000000008', 'Francais', 'lexique', 'polysemie_homonymie', 'Polysémie et homonymie', 'Intermediaire', 'vrai_faux', 'Vrai ou faux : dans un texte, c''est toujours le contexte qui permet de déterminer quel sens d''un mot polysémique est actualisé.', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'C''est vrai. La polysémie crée une ambiguïté potentielle, mais le contexte linguistique et situationnel lève généralement cette ambiguïté. Le lecteur sélectionne automatiquement le sens pertinent grâce aux autres éléments de la phrase et du texte. Cette sélection sémantique contextuelle est un processus fondamental de la compréhension du langage.', 'Croire que la polysémie crée systématiquement des ambiguïtés, alors que le contexte les résout presque toujours automatiquement.', 'valide', 'CRPE Français V3', 'free', true),

('b3080000-0000-0000-0000-000000000009', 'Francais', 'lexique', 'polysemie_homonymie', 'Polysémie et homonymie', 'Intermediaire', 'qcm', 'Parmi ces paires, laquelle constitue un couple d''homophones homographes (même prononciation ET même orthographe) ?', NULL, '[{"id":"a","label":"ver (animal) / vert (couleur)"},{"id":"b","label":"louer (prendre en location) / louer (célébrer)"},{"id":"c","label":"sein (poitrine) / saint (sacré)"},{"id":"d","label":"cou (partie du corps) / coup (frappe)"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, '«Louer» (prendre en location, du latin «locare») et «louer» (célébrer, du latin «laudare») ont la même orthographe et la même prononciation : ce sont des homophones homographes (ou homonymie parfaite). En revanche, ver/vert, sein/saint et cou/coup sont homophones mais non homographes (orthographe différente).', 'Choisir une paire homophone mais non homographe, en ignorant la condition d''identité graphique exigée.', 'valide', 'CRPE Français V3', 'free', true),

('b3080000-0000-0000-0000-00000000000a', 'Francais', 'lexique', 'polysemie_homonymie', 'Polysémie et homonymie', 'Intermediaire', 'reponse_courte', 'Le mot «nommer» quelqu''un à un poste est un dérivé sémantique de quel sens premier ? Quelle figure de sens explique ce glissement ?', NULL, NULL, '{"mode":"text","acceptableAnswers":["appeler par un nom / métonymie ou glissement métaphorique","donner un nom / extension de sens","sens propre : donner un nom / sens figuré : désigner à une fonction"]}'::jsonb, 'Le sens premier de «nommer» est «appeler par un nom, donner un nom» (du latin «nominare»). Le sens «désigner quelqu''un à une fonction» est un glissement sémantique par extension : nommer quelqu''un, c''est lui attribuer un titre, un rôle — lui donner le «nom» de ce poste. Ce phénomène de polysémie par extension métaphorique ou métonymique est courant dans l''histoire des langues.', 'Croire que les deux sens sont indépendants (homonymie) plutôt que liés par une relation sémantique (polysémie).', 'valide', 'CRPE Français V3', 'free', true),

-- ─── Batch B — Série 9 : Connecteurs logiques ────────────────────────────────
('b3090000-0000-0000-0000-000000000001', 'Francais', 'lexique', 'connecteurs_logiques', 'Connecteurs logiques', 'Intermediaire', 'qcm', 'Quel connecteur logique introduit une relation de conséquence ?', NULL, '[{"id":"a","label":"En effet"},{"id":"b","label":"Cependant"},{"id":"c","label":"Par conséquent"},{"id":"d","label":"De plus"}]'::jsonb, '{"mode":"single_choice","value":"c"}'::jsonb, '«Par conséquent» introduit une relation de conséquence : ce qui suit est le résultat de ce qui précède. «En effet» introduit une relation de cause ou de justification. «Cependant» exprime l''opposition ou la concession. «De plus» exprime l''addition. Maîtriser ces catégories est essentiel pour analyser la logique d''un texte argumentatif.', 'Confondre cause et conséquence : «en effet» justifie ce qui précède (cause), «par conséquent» annonce ce qui suit (conséquence).', 'valide', 'CRPE Français V3', 'free', true),

('b3090000-0000-0000-0000-000000000002', 'Francais', 'lexique', 'connecteurs_logiques', 'Connecteurs logiques', 'Intermediaire', 'qcm', 'Lequel de ces connecteurs exprime une opposition ou concession ?', NULL, '[{"id":"a","label":"Ainsi"},{"id":"b","label":"Néanmoins"},{"id":"c","label":"Par ailleurs"},{"id":"d","label":"En effet"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, '«Néanmoins» exprime une concession ou opposition : malgré ce qui a été dit, il en est autrement. Synonymes : cependant, pourtant, toutefois, or. «Ainsi» peut exprimer une conséquence ou une illustration. «Par ailleurs» exprime l''addition ou la progression. «En effet» introduit une justification ou explication.', 'Confondre «néanmoins» avec un connecteur d''addition ou de cause, sans l''associer à sa valeur d''opposition.', 'valide', 'CRPE Français V3', 'free', true),

('b3090000-0000-0000-0000-000000000003', 'Francais', 'lexique', 'connecteurs_logiques', 'Connecteurs logiques', 'Intermediaire', 'vrai_faux', 'Vrai ou faux : «car» et «parce que» expriment tous les deux une relation de cause, mais «car» ne peut pas débuter une phrase.', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'C''est vrai. «Car» est une conjonction de coordination qui ne peut ni débuter une phrase ni être précédé d''une virgule dans certains emplois. «Parce que» est une conjonction de subordination qui peut occuper diverses positions. Les deux expriment bien la cause, mais leurs contraintes syntaxiques diffèrent.', 'Employer «car» en début de phrase ou le confondre avec «parce que» sur le plan syntaxique.', 'valide', 'CRPE Français V3', 'free', true),

('b3090000-0000-0000-0000-000000000004', 'Francais', 'lexique', 'connecteurs_logiques', 'Connecteurs logiques', 'Intermediaire', 'reponse_courte', 'Citez deux connecteurs exprimant l''addition, différents de «et».', NULL, NULL, '{"mode":"text","acceptableAnswers":["de plus, en outre","de plus, par ailleurs","en outre, par ailleurs","de plus en outre par ailleurs également","également, de plus"]}'::jsonb, 'Les connecteurs d''addition incluent : de plus, en outre, par ailleurs, également, de surcroît, qui plus est, voire, non seulement… mais aussi. Ils permettent d''ajouter un argument, une information ou un élément sans marquer d''opposition. Dans un texte argumentatif, ils signalent une accumulation d''arguments allant dans le même sens.', 'Citer uniquement «et» ou «aussi», qui sont des connecteurs additifs mais trop basiques pour illustrer la maîtrise des connecteurs logiques.', 'valide', 'CRPE Français V3', 'free', true),

('b3090000-0000-0000-0000-000000000005', 'Francais', 'lexique', 'connecteurs_logiques', 'Connecteurs logiques', 'Intermediaire', 'qcm', 'Dans la phrase : «Il a travaillé dur ; c''est pourquoi il a réussi», quelle relation logique «c''est pourquoi» exprime-t-il ?', NULL, '[{"id":"a","label":"Opposition"},{"id":"b","label":"Addition"},{"id":"c","label":"Conséquence"},{"id":"d","label":"Cause"}]'::jsonb, '{"mode":"single_choice","value":"c"}'::jsonb, '«C''est pourquoi» est un connecteur de conséquence : ce qui suit est le résultat de ce qui précède. Le travail (cause) entraîne la réussite (conséquence). Attention à ne pas confondre avec «c''est pourquoi» dans une question rhétorique, où il a une autre valeur. Les connecteurs de conséquence incluent : donc, ainsi, par conséquent, c''est pourquoi, aussi (en tête de phrase inversée).', 'Confondre conséquence et cause, en lisant la relation de droite à gauche au lieu de gauche à droite.', 'valide', 'CRPE Français V3', 'free', true),

('b3090000-0000-0000-0000-000000000006', 'Francais', 'lexique', 'connecteurs_logiques', 'Connecteurs logiques', 'Intermediaire', 'vrai_faux', 'Vrai ou faux : «premièrement», «ensuite», «enfin» sont des connecteurs logiques exprimant une relation de causalité.', NULL, NULL, '{"mode":"boolean","value":false}'::jsonb, 'C''est faux. «Premièrement», «ensuite», «enfin» sont des organisateurs textuels (ou marqueurs de structuration du discours), non des connecteurs logiques de causalité. Ils structurent l''énumération ou le déroulement d''un texte dans l''ordre, sans exprimer une relation logique de type cause/conséquence/opposition. La distinction connecteurs logiques / organisateurs textuels est fondamentale.', 'Considérer tous les mots de liaison comme des connecteurs logiques, sans distinguer les organisateurs textuels qui structurent le discours.', 'valide', 'CRPE Français V3', 'free', true),

('b3090000-0000-0000-0000-000000000007', 'Francais', 'lexique', 'connecteurs_logiques', 'Connecteurs logiques', 'Intermediaire', 'qcm', 'Quel connecteur permet d''introduire une reformulation ou une explication ?', NULL, '[{"id":"a","label":"Cependant"},{"id":"b","label":"C''est-à-dire"},{"id":"c","label":"Ainsi"},{"id":"d","label":"Or"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, '«C''est-à-dire» est un connecteur de reformulation : il introduit une explication, une précision ou une traduction du propos précédent dans des termes plus accessibles. Synonymes : autrement dit, en d''autres termes, soit. Ce type de connecteur est essentiel dans les textes explicatifs et pédagogiques pour clarifier une notion.', 'Confondre «c''est-à-dire» avec un connecteur d''illustration comme «par exemple», alors que la reformulation paraphrase sans illustrer.', 'valide', 'CRPE Français V3', 'free', true),

('b3090000-0000-0000-0000-000000000008', 'Francais', 'lexique', 'connecteurs_logiques', 'Connecteurs logiques', 'Intermediaire', 'qcm', 'Dans un texte argumentatif, quel est le rôle du connecteur «or» ?', NULL, '[{"id":"a","label":"Il exprime une addition entre deux arguments de même valeur."},{"id":"b","label":"Il introduit un fait nouveau qui entre en tension avec ce qui précède, relançant le raisonnement."},{"id":"c","label":"Il conclut le texte en résumant les arguments."},{"id":"d","label":"Il illustre un argument par un exemple."}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, '«Or» est un connecteur argumentatif particulier : il introduit un élément nouveau, souvent une constatation ou un fait qui entre en tension, en opposition ou en complément avec ce qui précède, permettant au raisonnement de progresser. Il est fréquent dans les syllogismes : «Tous les hommes sont mortels. Or Socrate est un homme. Donc Socrate est mortel.»', 'Confondre «or» avec «mais» (opposition simple) ou avec les organisateurs textuels, sans reconnaître sa valeur argumentative spécifique.', 'valide', 'CRPE Français V3', 'free', true),

('b3090000-0000-0000-0000-000000000009', 'Francais', 'lexique', 'connecteurs_logiques', 'Connecteurs logiques', 'Intermediaire', 'vrai_faux', 'Vrai ou faux : la cohérence textuelle dépend uniquement des connecteurs logiques.', NULL, NULL, '{"mode":"boolean","value":false}'::jsonb, 'C''est faux. La cohérence textuelle est assurée par plusieurs mécanismes : les connecteurs logiques, certes, mais aussi la progression thématique (enchaînement des thèmes et des rhèmes), les reprises anaphoriques (pronoms, synonymes, hyperonymes), la continuité isotopique (champs lexicaux cohérents) et la ponctuation. Les connecteurs ne sont qu''un des outils de la cohésion textuelle.', 'Réduire la cohérence textuelle aux seuls connecteurs, en ignorant les autres mécanismes de cohésion (reprises nominales, isotopies, progression thématique).', 'valide', 'CRPE Français V3', 'free', true),

('b3090000-0000-0000-0000-00000000000a', 'Francais', 'lexique', 'connecteurs_logiques', 'Connecteurs logiques', 'Intermediaire', 'reponse_courte', 'Quelle différence y a-t-il entre un connecteur logique et une conjonction de subordination ? Illustrez par un exemple.', NULL, NULL, '{"mode":"text","acceptableAnswers":["connecteur logique : adverbe ou locution qui exprime une relation sans créer de subordination / conjonction de subordination : crée une proposition subordonnée","connecteur logique lien sémantique / conjonction de subordination crée subordonnée","connecteur donc par conséquent / conjonction parce que bien que"]}'::jsonb, 'Les connecteurs logiques (donc, cependant, par conséquent, en effet…) sont des adverbes ou locutions adverbiales qui expriment une relation de sens entre deux propositions syntaxiquement indépendantes. Les conjonctions de subordination (parce que, bien que, pour que…) créent une proposition subordonnée qui dépend syntaxiquement d''une principale. Exemple : «Il est parti ; par conséquent, je suis seul» (connecteur) vs «Parce qu''il est parti, je suis seul» (conjonction).', 'Confondre les deux en croyant que tout mot qui établit une relation logique est une conjonction de subordination.', 'valide', 'CRPE Français V3', 'free', true),

-- ─── Batch B — Série 10 : Emploi des majuscules ──────────────────────────────
('b30a0000-0000-0000-0000-000000000001', 'Francais', 'orthographe', 'majuscules_regles', 'Emploi des majuscules', 'Facile', 'correction_orthographique', 'Corrigez si nécessaire : «Les français sont réputés pour leur gastronomie.»', NULL, NULL, '{"mode":"text","acceptableAnswers":["Les Français sont réputés pour leur gastronomie."]}'::jsonb, '«Français» est ici un gentilé employé comme nom (il désigne les habitants de France, pas un adjectif qualifiant un nom). Dans ce cas, il prend une majuscule. En revanche, dans «le peuple français» ou «la cuisine française», «français» est un adjectif et prend une minuscule.', 'Mettre systématiquement une minuscule aux mots désignant les nationalités, sans distinguer l''emploi nominal (majuscule) de l''emploi adjectival (minuscule).', 'valide', 'CRPE Français V3', 'free', true),

('b30a0000-0000-0000-0000-000000000002', 'Francais', 'orthographe', 'majuscules_regles', 'Emploi des majuscules', 'Facile', 'vrai_faux', 'Vrai ou faux : dans «la cuisine italienne», «italienne» prend une minuscule parce qu''il est employé comme adjectif.', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'C''est vrai. La règle des gentilés est claire : employé comme adjectif (pour qualifier un nom), le mot prend une minuscule. Employé comme nom (pour désigner les habitants), il prend une majuscule. Ici, «italienne» qualifie «cuisine» : c''est un adjectif, donc minuscule. Exemples de noms : «Les Italiens sont nombreux à Paris.»', 'Mettre systématiquement une majuscule à toutes les nationalités, sans distinguer leur fonction grammaticale.', 'valide', 'CRPE Français V3', 'free', true),

('b30a0000-0000-0000-0000-000000000003', 'Francais', 'orthographe', 'majuscules_regles', 'Emploi des majuscules', 'Facile', 'qcm', 'Laquelle de ces phrases est orthographiquement correcte concernant les majuscules ?', NULL, '[{"id":"a","label":"J''ai lu le petit prince de Saint-Exupéry."},{"id":"b","label":"J''ai lu Le Petit Prince de Saint-Exupéry."},{"id":"c","label":"J''ai lu le Petit Prince de saint-Exupéry."},{"id":"d","label":"J''ai lu Le petit prince de Saint-Exupéry."}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'Pour les titres d''œuvres commençant par un article défini, la règle typographique française préconise : majuscule à l''article + majuscule au premier nom + majuscule aux adjectifs antéposés. «Le Petit Prince» : majuscule à «Le» (article), à «Petit» (adjectif antéposé), à «Prince» (nom). Le nom de l''auteur s''écrit avec un trait d''union et une majuscule à «Saint».', 'Ne mettre la majuscule qu''au premier mot du titre, sur le modèle de l''anglais (Le petit prince), ou au seul nom commun.', 'valide', 'CRPE Français V3', 'free', true),

('b30a0000-0000-0000-0000-000000000004', 'Francais', 'orthographe', 'majuscules_regles', 'Emploi des majuscules', 'Facile', 'correction_orthographique', 'Corrigez si nécessaire : «Il habite rue Victor-Hugo, dans le quartier nord de Lyon.»', NULL, NULL, '{"mode":"text","acceptableAnswers":["Il habite rue Victor-Hugo, dans le quartier nord de Lyon."]}'::jsonb, 'La phrase est correcte. «Rue Victor-Hugo» : «rue» est un nom commun (minuscule) et «Victor-Hugo» est un nom propre (majuscules). «Lyon» est un nom propre de ville (majuscule). «Quartier nord» : «quartier» est un nom commun, «nord» est ici un adjectif de position (minuscule). Les points cardinaux ne prennent la majuscule que lorsqu''ils désignent une région géographique (le Nord de la France) ou un pays (le Pôle Nord).', 'Mettre une majuscule à «Nord» systématiquement, sans distinguer le point cardinal comme adjectif de position (minuscule) et comme nom de région (majuscule).', 'valide', 'CRPE Français V3', 'free', true),

('b30a0000-0000-0000-0000-000000000005', 'Francais', 'orthographe', 'majuscules_regles', 'Emploi des majuscules', 'Facile', 'qcm', 'Laquelle de ces phrases emploie correctement la majuscule ?', NULL, '[{"id":"a","label":"Il a déposé sa poubelle devant la Maison."},{"id":"b","label":"Jette ça à la poubelle !"},{"id":"c","label":"La Poubelle est un mot venant du nom du préfet Poubelle."},{"id":"d","label":"Cette Poubelle est pleine."}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'Le nom commun «poubelle» s''écrit en minuscule : c''est un nom propre (le préfet Eugène Poubelle) devenu nom commun par lexicalisation. Ce phénomène s''appelle l''antonomase. D''autres exemples : un frigidaire (marque), une béchamel (du marquis de Béchamel), un jacuzzi, un bikini. La majuscule ne se maintient que si l''on désigne explicitement la marque ou la personne.', 'Conserver la majuscule à «poubelle» parce qu''on sait qu''il vient d''un nom propre, en ignorant que la lexicalisation impose la minuscule.', 'valide', 'CRPE Français V3', 'free', true),

('b30a0000-0000-0000-0000-000000000006', 'Francais', 'orthographe', 'majuscules_regles', 'Emploi des majuscules', 'Facile', 'vrai_faux', 'Vrai ou faux : les noms d''institutions officielles comme «l''Académie française» ou «le Conseil d''État» prennent une majuscule au premier nom.', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'C''est vrai. Les noms d''institutions, d''organismes officiels et d''administrations prennent généralement une majuscule au premier nom significatif : l''Académie française, le Conseil d''État, le Parlement européen, l''Assemblée nationale. Notez que l''adjectif «française» reste en minuscule car il suit le nom. La règle varie légèrement selon les guides typographiques.', 'Mettre une majuscule à tous les mots du nom de l''institution, sur le modèle anglais («The French Academy»), ce qui ne correspond pas à l''usage français.', 'valide', 'CRPE Français V3', 'free', true),

('b30a0000-0000-0000-0000-000000000007', 'Francais', 'orthographe', 'majuscules_regles', 'Emploi des majuscules', 'Facile', 'correction_orthographique', 'Corrigez si nécessaire : «J''adore lire la nuit des temps de Barjavel.»', NULL, NULL, '{"mode":"text","acceptableAnswers":["J''adore lire La Nuit des temps de Barjavel.","J''adore lire La Nuit des Temps de Barjavel."]}'::jsonb, 'Le titre d''œuvre «La Nuit des temps» requiert des majuscules : «La» (article en tête de titre), «Nuit» (premier nom). Selon certains guides typographiques, «temps» (deuxième nom, non directement lié à l''article) peut prendre ou non une majuscule. La forme la plus courante est «La Nuit des temps». Le nom de l''auteur «Barjavel» est un nom propre (majuscule).', 'Ne mettre aucune majuscule dans le titre, en le traitant comme un titre de chapitre ou une phrase ordinaire.', 'valide', 'CRPE Français V3', 'free', true),

('b30a0000-0000-0000-0000-000000000008', 'Francais', 'orthographe', 'majuscules_regles', 'Emploi des majuscules', 'Facile', 'qcm', 'Dans quelle situation un nom propre géographique prend-il une majuscule ?', NULL, '[{"id":"a","label":"Uniquement pour les pays et les continents."},{"id":"b","label":"Pour toute entité géographique nommée : pays, villes, fleuves, montagnes, régions, mers…"},{"id":"c","label":"Uniquement pour les capitales et les grandes villes."},{"id":"d","label":"Uniquement quand le nom est en début de phrase."}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'Tous les noms géographiques propres prennent une majuscule, quelle que soit la nature de l''entité : pays (la France), villes (Paris), fleuves (la Seine, le Nil), montagnes (le Mont-Blanc, les Alpes), régions (la Bretagne, le Midi), mers et océans (la Méditerranée, l''Atlantique), îles (la Corse). C''est une règle générale qui ne connaît pas d''exception liée à la taille ou à l''importance.', 'Limiter la majuscule aux pays et capitales, en l''omettant pour les fleuves, les massifs montagneux ou les régions.', 'valide', 'CRPE Français V3', 'free', true),

('b30a0000-0000-0000-0000-000000000009', 'Francais', 'orthographe', 'majuscules_regles', 'Emploi des majuscules', 'Facile', 'vrai_faux', 'Vrai ou faux : dans le titre «Les Misérables», seul «Les» prend une majuscule.', NULL, NULL, '{"mode":"boolean","value":false}'::jsonb, 'C''est faux. Pour les titres commençant par un article pluriel («Les»), la règle typographique française donne une majuscule à «Les» ET au premier mot significatif qui suit : «Les Misérables». Les deux prennent donc la majuscule. De même : «Les Fleurs du mal», «Les Trois Mousquetaires». C''est la même règle que pour l''article singulier défini.', 'Croire que seul l''article initial prend la majuscule dans un titre, en laissant le reste en minuscule.', 'valide', 'CRPE Français V3', 'free', true),

('b30a0000-0000-0000-0000-00000000000a', 'Francais', 'orthographe', 'majuscules_regles', 'Emploi des majuscules', 'Facile', 'reponse_courte', 'Comment appelle-t-on le phénomène par lequel un nom propre devient un nom commun (exemple : «poubelle», «béchamel») ?', NULL, NULL, '{"mode":"text","acceptableAnswers":["antonomase","antonomase du nom propre","lexicalisation","nominalisation d''un nom propre"]}'::jsonb, 'Ce phénomène s''appelle l''antonomase (ou antonomase du nom propre) : un nom propre est employé comme nom commun pour désigner une catégorie d''objets ou de personnes. Exemples : une poubelle (préfet Poubelle), une béchamel (marquis de Béchamel), un frigidaire (marque Frigidaire), un atlas (le géant Atlas). Le nouveau nom commun prend une minuscule et peut se mettre au pluriel.', 'Appeler ce phénomène «métaphore» ou «métonymie», en ignorant le terme linguistique précis désignant ce transfert du propre au commun.', 'valide', 'CRPE Français V3', 'free', true),

-- ─── Batch C — Série 1 : Préfixes, suffixes et radical ────────────────────────
('c3010000-0000-0000-0000-000000000001', 'Francais', 'analyse_langue', 'prefixes_suffixes_radical', 'Préfixes, suffixes et radical', 'Intermediaire', 'qcm', 'Dans le mot «irresponsable», quel est le radical ?', NULL, '[{"id":"a","label":"ir-"},{"id":"b","label":"responsa-"},{"id":"c","label":"respons-"},{"id":"d","label":"-able"}]'::jsonb, '{"mode":"single_choice","value":"c"}'::jsonb, 'Le mot se décompose ainsi : préfixe ir- (négation) + radical respons- (du latin respondere) + suffixe -able. Le radical est respons-, base porteuse du sens «répondre, être garant».', 'Confondre le radical avec le mot entier «responsable» ou prendre le suffixe -able pour le radical.', 'valide', 'CRPE Français V3', 'free', true),

('c3010000-0000-0000-0000-000000000002', 'Francais', 'analyse_langue', 'prefixes_suffixes_radical', 'Préfixes, suffixes et radical', 'Intermediaire', 'qcm', 'Lequel de ces préfixes exprime une idée d''antériorité ou de priorité temporelle ?', NULL, '[{"id":"a","label":"re-"},{"id":"b","label":"sur-"},{"id":"c","label":"pré-"},{"id":"d","label":"dé-"}]'::jsonb, '{"mode":"single_choice","value":"c"}'::jsonb, 'Le préfixe pré- (du latin prae, «avant») indique l''antériorité : prévoir, prévenir, préretraite. Re- marque la répétition, sur- l''excès, dé- la séparation ou le contraire.', 'Choisir sur- en pensant à «avant-garde» ou à une idée de hauteur hiérarchique.', 'valide', 'CRPE Français V3', 'free', true),

('c3010000-0000-0000-0000-000000000003', 'Francais', 'analyse_langue', 'prefixes_suffixes_radical', 'Préfixes, suffixes et radical', 'Intermediaire', 'vrai_faux', 'Vrai ou faux : dans le mot «illisible», le préfixe il- est une variante du préfixe in- exprimant la négation.', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'Le préfixe in- possède plusieurs allomorphes selon le contexte phonologique : il- devant l (illisible, illégal), im- devant b, m, p (impossible, immobile), ir- devant r (irréel). Ces formes expriment toutes la négation.', 'Croire que il- est un préfixe distinct de in-, ou ne pas connaître le phénomène d''assimilation phonologique.', 'valide', 'CRPE Français V3', 'free', true),

('c3010000-0000-0000-0000-000000000004', 'Francais', 'analyse_langue', 'prefixes_suffixes_radical', 'Préfixes, suffixes et radical', 'Intermediaire', 'reponse_courte', 'Le suffixe -ité sert à former des noms à partir d''adjectifs. Donnez un exemple de mot ainsi formé à partir de l''adjectif «fragile».', NULL, NULL, '{"mode":"text","acceptableAnswers":["fragilité"]}'::jsonb, 'Le suffixe -ité est un suffixe nominalisateur qui forme des noms abstraits à partir d''adjectifs : fragile → fragilité, agile → agilité, fertile → fertilité. Il correspond souvent aux suffixes latins -itas/-itatis.', 'Proposer «fragilesse» ou une autre forme incorrecte par analogie avec d''autres formations.', 'valide', 'CRPE Français V3', 'free', true),

('c3010000-0000-0000-0000-000000000005', 'Francais', 'analyse_langue', 'prefixes_suffixes_radical', 'Préfixes, suffixes et radical', 'Intermediaire', 'qcm', 'Quelle est la valeur du préfixe «sous-» dans le mot «sous-estimer» ?', NULL, '[{"id":"a","label":"Répétition"},{"id":"b","label":"Insuffisance ou infériorité"},{"id":"c","label":"Excès"},{"id":"d","label":"Antériorité"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'Le préfixe sous- exprime l''idée d''insuffisance, d''infériorité ou d''un niveau inférieur à la norme : sous-estimer (estimer insuffisamment), sous-alimenté, sous-développé. Son antonyme est sur- (surestimer, surdéveloppé).', 'Choisir «répétition» en assimilant sous- à re-, ou confondre sous- et dé-.', 'valide', 'CRPE Français V3', 'free', true),

('c3010000-0000-0000-0000-000000000006', 'Francais', 'analyse_langue', 'prefixes_suffixes_radical', 'Préfixes, suffixes et radical', 'Intermediaire', 'vrai_faux', 'Vrai ou faux : le suffixe -eur peut former aussi bien des noms de personnes (chanteur) que des noms désignant un appareil ou une machine (aspirateur).', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'Le suffixe -eur est polyfonctionnel : il forme des noms d''agents humains (chanteur, lecteur) mais aussi des noms d''instruments ou de machines (aspirateur, moteur, réfrigérateur). Le contexte seul permet de distinguer les deux valeurs.', 'Croire que -eur désigne exclusivement des personnes et oublier ses emplois pour les machines.', 'valide', 'CRPE Français V3', 'free', true),

('c3010000-0000-0000-0000-000000000007', 'Francais', 'analyse_langue', 'prefixes_suffixes_radical', 'Préfixes, suffixes et radical', 'Intermediaire', 'qcm', 'Les mots «fragile» et «frêle» sont des doublets. Qu''est-ce qu''un doublet ?', NULL, '[{"id":"a","label":"Deux mots de sens opposé issus de la même langue"},{"id":"b","label":"Deux mots issus du même étymon latin, l''un par voie savante, l''autre par voie populaire"},{"id":"c","label":"Deux mots formés avec le même suffixe"},{"id":"d","label":"Deux mots synonymes issus de deux langues différentes"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'Un doublet est une paire de mots issus du même étymon latin : fragile vient directement du latin fragilis (voie savante), tandis que frêle est l''aboutissement phonétique populaire du même mot. Autre exemple : noctambule (savant) / nuit (populaire), tous deux issus de nox/noctis.', 'Croire que doublet désigne simplement deux synonymes, sans tenir compte du critère étymologique.', 'valide', 'CRPE Français V3', 'free', true),

('c3010000-0000-0000-0000-000000000008', 'Francais', 'analyse_langue', 'prefixes_suffixes_radical', 'Préfixes, suffixes et radical', 'Intermediaire', 'reponse_courte', 'Quel suffixe permet de former un adjectif signifiant «qui peut être mangé» à partir du verbe «manger» ?', NULL, NULL, '{"mode":"text","acceptableAnswers":["-able","mangeable"]}'::jsonb, 'Le suffixe -able (du latin -abilis) s''attache à des bases verbales pour former des adjectifs exprimant la possibilité ou la capacité passive : manger → mangeable, lire → lisible (variante -ible), faire → faisable. Le mot formé est «mangeable».', 'Proposer le suffixe -ible sans justifier l''alternance, ou former «mangeant» qui est un participe présent et non un adjectif dérivé.', 'valide', 'CRPE Français V3', 'free', true),

('c3010000-0000-0000-0000-000000000009', 'Francais', 'analyse_langue', 'prefixes_suffixes_radical', 'Préfixes, suffixes et radical', 'Intermediaire', 'vrai_faux', 'Vrai ou faux : le préfixe anti- exprime toujours une idée d''opposition ou de protection contre quelque chose.', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'Le préfixe anti- (du grec anti, «contre») exprime systématiquement l''opposition ou la protection : antibrouillard, antiraciste, antiseptique, antivirus. Il ne faut pas le confondre avec ante- (antérieur, antéposition) qui exprime l''antériorité.', 'Confondre anti- et ante-, ou croire que anti- peut parfois exprimer l''excès (rôle de sur-).', 'valide', 'CRPE Français V3', 'free', true),

('c3010000-0000-0000-0000-00000000000a', 'Francais', 'analyse_langue', 'prefixes_suffixes_radical', 'Préfixes, suffixes et radical', 'Intermediaire', 'qcm', 'Dans le mot «déforestation», quelle est la structure morphologique correcte ?', NULL, '[{"id":"a","label":"dé- + forest- + -ation"},{"id":"b","label":"dé- + forêt + -isation"},{"id":"c","label":"dé- + forest- + -at + -ion"},{"id":"d","label":"dé-forêt + -ation"}]'::jsonb, '{"mode":"single_choice","value":"a"}'::jsonb, 'Le mot «déforestation» se décompose en : préfixe dé- (suppression, privation) + radical forest- (du latin forestis) + suffixe nominalisateur -ation. La graphie forêt (avec accent circonflexe) est la forme française du radical, mais la morphologie dérivationnelle utilise forest-.', 'Proposer forêt comme base en oubliant que la dérivation utilise souvent le radical latin sans accent.', 'valide', 'CRPE Français V3', 'free', true),

-- ─── Batch C — Série 2 : La dérivation ────────────────────────────────────────
('c3020000-0000-0000-0000-000000000001', 'Francais', 'analyse_langue', 'derivation_mots', 'La dérivation', 'Intermediaire', 'qcm', 'Quel est le type de dérivation à l''œuvre dans la création du mot «marche» à partir du verbe «marcher» ?', NULL, '[{"id":"a","label":"Dérivation préfixale"},{"id":"b","label":"Dérivation suffixale"},{"id":"c","label":"Dérivation régressive"},{"id":"d","label":"Dérivation impropre"}]'::jsonb, '{"mode":"single_choice","value":"c"}'::jsonb, 'La dérivation régressive consiste à supprimer un suffixe (ici la terminaison verbale -er) pour obtenir un nouveau mot : marcher → marche (nom féminin). Autres exemples : voler → vol, chanter → chant. Ce procédé va à rebours de la suffixation habituelle.', 'Confondre avec la dérivation impropre (changement de catégorie sans affixe) ou avec la substantivation d''un infinitif (le manger).', 'valide', 'CRPE Français V3', 'free', true),

('c3020000-0000-0000-0000-000000000002', 'Francais', 'analyse_langue', 'derivation_mots', 'La dérivation', 'Intermediaire', 'vrai_faux', 'Vrai ou faux : «le manger» est un exemple de dérivation impropre car l''infinitif «manger» est employé comme nom sans ajout d''affixe.', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'La dérivation impropre (ou conversion) est le passage d''une catégorie grammaticale à une autre sans modification morphologique. L''infinitif employé comme nom (le manger, le savoir, le bien-être) est le cas le plus courant. On parle aussi de substantivation de l''infinitif.', 'Croire qu''un affixe est nécessaire pour qu''il y ait dérivation, et donc qualifier ce phénomène de simple emploi métaphorique.', 'valide', 'CRPE Français V3', 'free', true),

('c3020000-0000-0000-0000-000000000003', 'Francais', 'analyse_langue', 'derivation_mots', 'La dérivation', 'Intermediaire', 'reponse_courte', 'Citez deux mots de la famille du radical «port-» (du latin portare, porter) formés par dérivation suffixale.', NULL, NULL, '{"mode":"text","acceptableAnswers":["porteur","portable","portage","transport","exportation","importation","report","apport"]}'::jsonb, 'Le radical port- génère une famille riche : porteur (-eur, agent), portable (-able, possibilité), portage (-age, action collective), transport (dérivé préfixal avec trans-), exportation, importation. La dérivation suffixale permet de changer la catégorie ou d''affiner le sens.', 'Citer des mots composés (porte-monnaie) qui relèvent de la composition et non de la dérivation.', 'valide', 'CRPE Français V3', 'free', true),

('c3020000-0000-0000-0000-000000000004', 'Francais', 'analyse_langue', 'derivation_mots', 'La dérivation', 'Intermediaire', 'qcm', 'Le mot «emprisonner» est qualifié de parasynthétique. Qu''est-ce que cela signifie ?', NULL, '[{"id":"a","label":"Il est formé uniquement par préfixation"},{"id":"b","label":"Il est formé par ajout simultané d''un préfixe et d''un suffixe à un radical"},{"id":"c","label":"Il est formé par composition de deux mots autonomes"},{"id":"d","label":"Il est formé par dérivation régressive d''un nom"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'Un mot parasynthétique est formé par l''ajout simultané d''un préfixe et d''un suffixe à un radical : em- + prison + -er → emprisonner. Ce mécanisme est dit parasynthétique car ni *emprison ni *prisonner n''existent en français. Autres exemples : défolier, atterrir (at- + terre + -ir).', 'Croire qu''il s''agit d''une composition car on voit plusieurs éléments, ou confondre avec la préfixation seule.', 'valide', 'CRPE Français V3', 'free', true),

('c3020000-0000-0000-0000-000000000005', 'Francais', 'analyse_langue', 'derivation_mots', 'La dérivation', 'Intermediaire', 'qcm', 'Lequel de ces mots est un néologisme formé par dérivation ?', NULL, '[{"id":"a","label":"téléphone"},{"id":"b","label":"déprogrammer"},{"id":"c","label":"brunch"},{"id":"d","label":"boulangerie"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, '«Déprogrammer» est un néologisme récent formé par dérivation préfixale : dé- + programmer. Il suit un procédé productif en français contemporain. Téléphone est ancien (XIXe), brunch est un mot-valise (composition tronquée) et boulangerie est un dérivé classique.', 'Choisir téléphone parce qu''il intègre un élément gréco-latin, ce qui ne suffit pas à en faire un néologisme.', 'valide', 'CRPE Français V3', 'free', true),

('c3020000-0000-0000-0000-000000000006', 'Francais', 'analyse_langue', 'derivation_mots', 'La dérivation', 'Intermediaire', 'vrai_faux', 'Vrai ou faux : «courriel» est un néologisme formé par dérivation à partir du mot «courrier».', NULL, NULL, '{"mode":"boolean","value":false}'::jsonb, '«Courriel» n''est pas formé par dérivation suffixale ou préfixale classique. Il s''agit d''un mot-valise (télescopage) créé par contraction de «courrier» et «électronique». Ce terme, proposé par les autorités linguistiques francophones québécoises, est un exemple de néologie formelle par troncation-fusion.', 'Considérer courriel comme un dérivé de courrier parce que les deux mots sont liés sémantiquement.', 'valide', 'CRPE Français V3', 'free', true),

('c3020000-0000-0000-0000-000000000007', 'Francais', 'analyse_langue', 'derivation_mots', 'La dérivation', 'Intermediaire', 'reponse_courte', 'Quel est le radical commun aux mots suivants : «portable», «portage», «reporter», «importation» ?', NULL, NULL, '{"mode":"text","acceptableAnswers":["port","port-"]}'::jsonb, 'Tous ces mots partagent le radical port- issu du latin portare (porter). La dérivation suffixale (-able, -age) et préfixale (re-, im-) ainsi que les suffixes nominalisateurs (-ation) permettent de construire des mots de catégories différentes à partir de cette même base.', 'Proposer «porter» au lieu d''isoler le radical port-, confondant ainsi le mot entier et la base morphologique.', 'valide', 'CRPE Français V3', 'free', true),

('c3020000-0000-0000-0000-000000000008', 'Francais', 'analyse_langue', 'derivation_mots', 'La dérivation', 'Intermediaire', 'qcm', 'Dans quelle série tous les mots sont-ils formés par dérivation suffixale ?', NULL, '[{"id":"a","label":"refaire, délier, prévenir"},{"id":"b","label":"chanteur, liberté, agréable"},{"id":"c","label":"portefeuille, timbre-poste, gratte-ciel"},{"id":"d","label":"vol (de voler), marche (de marcher), chant (de chanter)"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'Chanteur (chanter + -eur), liberté (libre + -té, avec modification du radical), agréable (agréer + -able) : tous trois résultent d''une dérivation suffixale. La série A relève de la préfixation, la série C de la composition, la série D de la dérivation régressive.', 'Choisir la série D en confondant dérivation régressive et dérivation suffixale.', 'valide', 'CRPE Français V3', 'free', true),

('c3020000-0000-0000-0000-000000000009', 'Francais', 'analyse_langue', 'derivation_mots', 'La dérivation', 'Intermediaire', 'vrai_faux', 'Vrai ou faux : la dérivation impropre est un procédé marginal qui ne concerne que l''infinitif substantivé.', NULL, NULL, '{"mode":"boolean","value":false}'::jsonb, 'La dérivation impropre (conversion) touche de nombreuses catégories : l''adjectif employé comme nom (le beau, un pauvre), le participe passé comme adjectif ou nom (un blessé, l''attendu), le nom comme adjectif (une couleur crème, un regard acier). Elle est bien plus large que la seule substantivation de l''infinitif.', 'Croire que la conversion se limite à «le manger» ou «le boire», deux exemples canoniques qui masquent la richesse du procédé.', 'valide', 'CRPE Français V3', 'free', true),

('c3020000-0000-0000-0000-00000000000a', 'Francais', 'analyse_langue', 'derivation_mots', 'La dérivation', 'Intermediaire', 'qcm', 'Vous ne connaissez pas le mot «incoercible». Quelle décomposition morphologique vous aide le mieux à en déduire le sens ?', NULL, '[{"id":"a","label":"in- (négation) + coercible (qui peut être contraint), donc «qu''on ne peut pas contraindre»"},{"id":"b","label":"in- (dans) + coer- (cœur) + -ible (capable), donc «capable d''aller dans le cœur»"},{"id":"c","label":"inco- (préfixe) + ercible (radical), donc sens indéterminé"},{"id":"d","label":"in- (négatif) + coer- (couler) + -ible, donc «qui ne coule pas»"}]'::jsonb, '{"mode":"single_choice","value":"a"}'::jsonb, 'Le mot se décompose en in- (préfixe de négation) + coercible (adjectif dérivé du latin coercere, contraindre, avec le suffixe -ible indiquant la possibilité). Incoercible signifie donc «qu''on ne peut pas réprimer ou contraindre» : une envie incoercible de rire. Savoir analyser les morphèmes permet de décoder des mots inconnus du lexique savant.', 'Se laisser tromper par la ressemblance avec «cœur» et proposer une étymologie fantaisiste.', 'valide', 'CRPE Français V3', 'free', true),

-- ─── Batch C — Série 3 : La composition des mots ─────────────────────────────
('c3030000-0000-0000-0000-000000000001', 'Francais', 'analyse_langue', 'composition_mots', 'La composition des mots', 'Intermediaire', 'qcm', 'Quelle est la principale différence entre un mot composé et un mot dérivé ?', NULL, '[{"id":"a","label":"Le mot composé contient toujours un trait d''union"},{"id":"b","label":"Le mot composé assemble des unités pouvant exister seules, le mot dérivé ajoute des affixes non autonomes"},{"id":"c","label":"Le mot dérivé vient du latin, le mot composé vient du grec"},{"id":"d","label":"Le mot composé est toujours plus long que le mot dérivé"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'La composition assemble des bases lexicales autonomes (chou + fleur = chou-fleur ; porte + monnaie = portefeuille). La dérivation ajoute des affixes (préfixes ou suffixes) qui ne sont pas des mots autonomes en français (re-, -tion, -eur). Le trait d''union est un critère graphique variable, pas définitoire.', 'Utiliser le trait d''union comme critère principal de composition, alors que de nombreux composés s''écrivent en un seul mot (portefeuille).', 'valide', 'CRPE Français V3', 'free', true),

('c3030000-0000-0000-0000-000000000002', 'Francais', 'analyse_langue', 'composition_mots', 'La composition des mots', 'Intermediaire', 'vrai_faux', 'Vrai ou faux : dans «chou-fleur», les deux éléments sont des noms pouvant fonctionner de manière autonome en français.', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'Chou-fleur est un composé nominal formé de deux noms autonomes (chou et fleur) reliés par un trait d''union. Cette structure [N + N] est très productive en français : timbre-poste, oiseau-mouche, wagon-lit. Le sens du composé n''est pas la simple addition des sens des composants (un chou-fleur n''est pas une fleur de chou).', 'Croire que «fleur» est ici un suffixe ou un élément de dérivation parce qu''il est placé en deuxième position.', 'valide', 'CRPE Français V3', 'free', true),

('c3030000-0000-0000-0000-000000000003', 'Francais', 'analyse_langue', 'composition_mots', 'La composition des mots', 'Intermediaire', 'qcm', 'Le mot «bibliothèque» est formé de deux éléments gréco-latins. Quelle est la bonne décomposition ?', NULL, '[{"id":"a","label":"biblio- (livre) + -thèque (lieu de rangement)"},{"id":"b","label":"biblio- (deux fois) + -thèque (collection)"},{"id":"c","label":"bi- (deux) + -blio + -thèque (boîte)"},{"id":"d","label":"bibli- (papier) + -othèque (réserve)"}]'::jsonb, '{"mode":"single_choice","value":"a"}'::jsonb, 'Bibliothèque est formé de biblio- (du grec biblion, livre) et de -thèque (du grec thêkê, coffre, lieu de rangement). Ce schéma est productif : discothèque (disque + thèque), cinémathèque, DVDthèque. Ces compositions savantes utilisent des bases gréco-latines non autonomes en français.', 'Associer biblio- à «bible» uniquement et oublier le sens générique de «livre» dans la racine grecque.', 'valide', 'CRPE Français V3', 'free', true),

('c3030000-0000-0000-0000-000000000004', 'Francais', 'analyse_langue', 'composition_mots', 'La composition des mots', 'Intermediaire', 'reponse_courte', 'Le mot «gratte-ciel» est un composé à base verbale. Quel est le schéma de formation de ce type de composé ?', NULL, NULL, '{"mode":"text","acceptableAnswers":["verbe + nom","[V + N]","verbe-nom"]}'::jsonb, 'Les composés à base verbale suivent le schéma [Verbe + Nom] : gratte-ciel (gratter + ciel), pèse-lettre, tire-bouchon, porte-monnaie, cache-nez. La forme verbale est à la 3e personne du singulier du présent de l''indicatif (ou à l''impératif). Ces composés sont souvent des noms d''instruments ou de personnes.', 'Confondre ce type de composé avec un groupe verbal ordinaire ou croire que l''élément verbal est un nom.', 'valide', 'CRPE Français V3', 'free', true),

('c3030000-0000-0000-0000-000000000005', 'Francais', 'analyse_langue', 'composition_mots', 'La composition des mots', 'Intermediaire', 'qcm', 'Qu''est-ce qu''un mot-valise (ou télescopage) ?', NULL, '[{"id":"a","label":"Un mot emprunté à une autre langue sans adaptation phonétique"},{"id":"b","label":"Un mot formé par la fusion partielle de deux mots, conservant chacun une portion"},{"id":"c","label":"Un mot composé dont les deux éléments sont reliés par un trait d''union"},{"id":"d","label":"Un mot formé par ajout simultané d''un préfixe et d''un suffixe"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'Un mot-valise résulte du télescopage de deux mots dont chacun est tronqué : brunch = breakfast + lunch, courriel = courrier + électronique, franglais = français + anglais. Ce procédé est très productif dans les néologismes contemporains et dans la langue des médias.', 'Confondre mot-valise et emprunt, ou avec la composition classique qui conserve intégralement les deux éléments.', 'valide', 'CRPE Français V3', 'free', true),

('c3030000-0000-0000-0000-000000000006', 'Francais', 'analyse_langue', 'composition_mots', 'La composition des mots', 'Intermediaire', 'vrai_faux', 'Vrai ou faux : «portefeuille» est un mot composé qui s''écrit sans trait d''union parce qu''il a été lexicalisé (soudé graphiquement).', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'Portefeuille (porte + feuille) est un composé [V + N] dont la soudure graphique traduit une lexicalisation avancée. En français, les mots composés peuvent être écrits avec trait d''union (porte-monnaie), soudés (portefeuille, tournesol) ou en deux mots séparés (pomme de terre). Ces variations graphiques ne changent pas la nature compositionnelle du mot.', 'Croire que l''absence de trait d''union signifie que le mot n''est pas composé mais dérivé.', 'valide', 'CRPE Français V3', 'free', true),

('c3030000-0000-0000-0000-000000000007', 'Francais', 'analyse_langue', 'composition_mots', 'La composition des mots', 'Intermediaire', 'qcm', 'Dans «télévision», quel est le sens de l''élément téléo- ?', NULL, '[{"id":"a","label":"Rapide"},{"id":"b","label":"À distance, loin"},{"id":"c","label":"Automatique"},{"id":"d","label":"Électronique"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'L''élément téléo- / télé- vient du grec têle, «loin, à distance». Il entre dans de nombreux composés savants : télévision (voir à distance), téléphone (son à distance), télépathie, télécommande. Il ne faut pas le confondre avec le préfixe télé- de télévision (abréviation familière).', 'Associer télé- à l''appareil (le téléviseur) et oublier le sens étymologique «loin».', 'valide', 'CRPE Français V3', 'free', true),

('c3030000-0000-0000-0000-000000000008', 'Francais', 'analyse_langue', 'composition_mots', 'La composition des mots', 'Intermediaire', 'reponse_courte', 'Donnez un exemple de mot composé savant utilisant l''élément «-graphe» ou «-graphie» en précisant son sens.', NULL, NULL, '{"mode":"text","acceptableAnswers":["photographie","géographie","biographie","orthographe","calligraphie","cartographie"]}'::jsonb, 'L''élément -graphe / -graphie vient du grec graphein (écrire, dessiner). Il entre dans de nombreux composés : photographie (écriture par la lumière), biographie (écriture de la vie), géographie (écriture de la Terre), orthographe (écriture correcte). Ces composés savants sont appelés «mots construits à base gréco-latine».', 'Citer un mot dérivé ordinaire en -age ou -ation au lieu d''un composé à base grecque.', 'valide', 'CRPE Français V3', 'free', true),

('c3030000-0000-0000-0000-000000000009', 'Francais', 'analyse_langue', 'composition_mots', 'La composition des mots', 'Intermediaire', 'vrai_faux', 'Vrai ou faux : un xénisme est un emprunt parfaitement intégré au système phonétique et graphique du français.', NULL, NULL, '{"mode":"boolean","value":false}'::jsonb, 'Un xénisme est un emprunt qui conserve les caractéristiques phonétiques, graphiques et parfois grammaticales de la langue d''origine. Il n''est pas adapté : week-end, meeting, pizza, sushi. À l''inverse, un emprunt intégré (ou assimilé) a subi des adaptations : bifteck (beefsteak), boulingrin (bowling green). Cette distinction est attendue au CRPE pour aborder la néologie et le contact de langues.', 'Confondre xénisme et néologisme, ou croire que tout emprunt à l''anglais est automatiquement un xénisme.', 'valide', 'CRPE Français V3', 'free', true),

('c3030000-0000-0000-0000-00000000000a', 'Francais', 'analyse_langue', 'composition_mots', 'La composition des mots', 'Intermediaire', 'qcm', 'Lequel de ces mots est formé par composition savante à bases gréco-latines ?', NULL, '[{"id":"a","label":"chou-fleur"},{"id":"b","label":"portefeuille"},{"id":"c","label":"noctambule"},{"id":"d","label":"tire-bouchon"}]'::jsonb, '{"mode":"single_choice","value":"c"}'::jsonb, 'Noctambule est formé de noctis (nuit, latin) et ambulare (marcher, latin) : «celui qui marche la nuit». C''est un composé savant à bases latines non autonomes en français. Chou-fleur et tire-bouchon sont des composés populaires à bases françaises autonomes. Portefeuille est un composé [V + N] soudé.', 'Choisir portefeuille parce qu''il s''écrit en un seul mot, ce qui ne suffit pas à en faire un composé savant.', 'valide', 'CRPE Français V3', 'free', true),

-- ─── Batch C — Série 4 : L''énonciation ──────────────────────────────────────
('c3040000-0000-0000-0000-000000000001', 'Francais', 'analyse_langue', 'enonciation_modalites', 'L''énonciation', 'Difficile', 'qcm', 'Qu''est-ce qu''un déictique ?', NULL, '[{"id":"a","label":"Un mot qui exprime une relation logique entre deux propositions"},{"id":"b","label":"Un élément linguistique dont l''interprétation dépend de la situation d''énonciation"},{"id":"c","label":"Un pronom qui reprend un élément déjà mentionné dans le texte"},{"id":"d","label":"Un adverbe qui situe l''action dans le temps"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'Un déictique est un terme dont le référent ne peut être identifié qu''en se référant à la situation d''énonciation. Les pronoms je/tu, les adverbes ici/maintenant, les démonstratifs ce/ceci sont des déictiques. Les pronoms anaphoriques (option C) renvoient au texte lui-même et non à la situation d''énonciation.', 'Confondre déictique et anaphorique : «il» peut être les deux selon qu''il désigne une personne présente dans la situation ou reprend un antécédent textuel.', 'valide', 'CRPE Français V3', 'free', true),

('c3040000-0000-0000-0000-000000000002', 'Francais', 'analyse_langue', 'enonciation_modalites', 'L''énonciation', 'Difficile', 'vrai_faux', 'Vrai ou faux : un énoncé coupé de la situation d''énonciation utilise typiquement le passé simple et la troisième personne.', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'Un énoncé coupé de la situation d''énonciation (discours historique selon Benveniste) se caractérise par l''absence de déictiques, l''emploi du passé simple et de l''imparfait, et l''utilisation de la 3e personne. Il s''oppose à l''énoncé ancré qui emploie le présent, le passé composé, les pronoms je/tu et les déictiques.', 'Croire que tous les textes au passé sont coupés de la situation d''énonciation, en oubliant que le passé composé peut être ancré.', 'valide', 'CRPE Français V3', 'free', true),

('c3040000-0000-0000-0000-000000000003', 'Francais', 'analyse_langue', 'enonciation_modalites', 'L''énonciation', 'Difficile', 'qcm', 'Dans la phrase «Il faut absolument que vous partiez !», quelle est la modalité énonciative ?', NULL, '[{"id":"a","label":"Assertive"},{"id":"b","label":"Interrogative"},{"id":"c","label":"Injonctive"},{"id":"d","label":"Exclamative"}]'::jsonb, '{"mode":"single_choice","value":"c"}'::jsonb, 'La modalité injonctive exprime un ordre ou une obligation. Elle se reconnaît à l''emploi de l''impératif, du subjonctif injonctif ou de périphrases modales (il faut que). Le point d''exclamation marque l''intensité mais ne change pas la modalité fondamentale, qui reste injonctive.', 'Choisir la modalité exclamative en raison du point d''exclamation, en confondant signe de ponctuation et modalité énonciative.', 'valide', 'CRPE Français V3', 'free', true),

('c3040000-0000-0000-0000-000000000004', 'Francais', 'analyse_langue', 'enonciation_modalites', 'L''énonciation', 'Difficile', 'reponse_courte', 'Identifiez le type de discours rapporté dans cet extrait : «Il rentra chez lui. Comme il était fatigué ! Il n''aurait jamais dû accepter ce travail.»', NULL, NULL, '{"mode":"text","acceptableAnswers":["discours indirect libre","style indirect libre","DIL"]}'::jsonb, 'Le discours indirect libre (DIL) est caractérisé par l''absence de verbe introducteur et de subordonnant, le maintien des temps du récit (imparfait, conditionnel) et la présence de marques expressives. Le narrateur prête sa voix au personnage sans le signaler explicitement.', 'Répondre «discours indirect» en oubliant que le DIL n''a ni verbe introducteur ni conjonction de subordination.', 'valide', 'CRPE Français V3', 'free', true),

('c3040000-0000-0000-0000-000000000005', 'Francais', 'analyse_langue', 'enonciation_modalites', 'L''énonciation', 'Difficile', 'qcm', 'Quelle est la différence entre la focalisation interne et la focalisation zéro dans un récit ?', NULL, '[{"id":"a","label":"La focalisation interne utilise le «je», la focalisation zéro utilise le «il»"},{"id":"b","label":"En focalisation interne, le narrateur ne sait que ce que sait un personnage ; en focalisation zéro, il est omniscient"},{"id":"c","label":"La focalisation interne décrit les pensées, la focalisation zéro décrit les actions"},{"id":"d","label":"La focalisation interne est propre au roman, la focalisation zéro au conte"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'La focalisation (terme de Genette) désigne la relation entre ce que le narrateur sait et ce que le personnage sait. En focalisation interne, le narrateur adopte le point de vue d''un personnage et n''en sait pas plus que lui. En focalisation zéro, le narrateur omniscient en sait plus que tous les personnages.', 'Confondre focalisation interne et narration à la première personne : un récit à la 3e personne peut adopter une focalisation interne.', 'valide', 'CRPE Français V3', 'free', true),

('c3040000-0000-0000-0000-000000000006', 'Francais', 'analyse_langue', 'enonciation_modalites', 'L''énonciation', 'Difficile', 'vrai_faux', 'Vrai ou faux : la modalité appréciative concerne uniquement les adverbes d''opinion comme «heureusement» ou «malheureusement».', NULL, NULL, '{"mode":"boolean","value":false}'::jsonb, 'La modalité appréciative exprime le jugement de l''énonciateur. Elle se manifeste par de nombreux procédés : adverbes d''opinion, adjectifs évaluatifs (admirable, regrettable), verbes de sentiment (je déplore que), lexique connoté, modalisateurs (sans doute, il semble que). Les adverbes n''en sont qu''une réalisation parmi d''autres.', 'Réduire la modalité appréciative aux seuls adverbes d''opinion.', 'valide', 'CRPE Français V3', 'free', true),

('c3040000-0000-0000-0000-000000000007', 'Francais', 'analyse_langue', 'enonciation_modalites', 'L''énonciation', 'Difficile', 'qcm', 'Dans la phrase «Viendras-tu demain ?», quel indice montre que cet énoncé est ancré dans la situation d''énonciation ?', NULL, '[{"id":"a","label":"Le futur simple"},{"id":"b","label":"L''inversion du sujet"},{"id":"c","label":"L''adverbe «demain»"},{"id":"d","label":"La forme interrogative"}]'::jsonb, '{"mode":"single_choice","value":"c"}'::jsonb, 'L''adverbe «demain» est un déictique temporel : son référent ne peut être calculé que par rapport au moment de l''énonciation. Il ancre l''énoncé dans la situation de communication. Le futur et l''interrogation peuvent aussi apparaître dans des textes coupés de l''énonciation.', 'Choisir «le futur simple» en croyant que ce temps signale toujours un ancrage énonciatif.', 'valide', 'CRPE Français V3', 'free', true),

('c3040000-0000-0000-0000-000000000008', 'Francais', 'analyse_langue', 'enonciation_modalites', 'L''énonciation', 'Difficile', 'reponse_courte', 'Donnez le nom de la notion qui désigne la présence de plusieurs voix ou points de vue dans un même énoncé.', NULL, NULL, '{"mode":"text","acceptableAnswers":["polyphonie","polyphonie énonciative"]}'::jsonb, 'La polyphonie énonciative (Bakhtine, repris par Ducrot) désigne la présence de plusieurs voix dans un énoncé. L''ironie est un exemple fort de polyphonie : l''énonciateur réel contredit la voix qu''il met en scène. Le discours rapporté (DD, DI, DIL) est une autre manifestation de la polyphonie.', 'Répondre «discours rapporté» qui est une manifestation de la polyphonie, non la notion englobante.', 'valide', 'CRPE Français V3', 'free', true),

('c3040000-0000-0000-0000-000000000009', 'Francais', 'analyse_langue', 'enonciation_modalites', 'L''énonciation', 'Difficile', 'vrai_faux', 'Vrai ou faux : dans le discours direct, les paroles rapportées conservent les marques déictiques de la situation d''énonciation originelle.', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'Dans le discours direct (DD), les paroles sont reproduites telles quelles avec leurs déictiques originaux. Les pronoms (je), les déictiques spatiaux (ici) et temporels (demain) renvoient à la situation du personnage, non à celle du narrateur. Le discours indirect transforme ces déictiques : il dit qu''il viendrait là le lendemain.', 'Croire que le discours direct transpose les pronoms et les temps comme le fait le discours indirect.', 'valide', 'CRPE Français V3', 'free', true),

('c3040000-0000-0000-0000-00000000000a', 'Francais', 'analyse_langue', 'enonciation_modalites', 'L''énonciation', 'Difficile', 'qcm', 'Laquelle de ces phrases contient une modalité assertive avec un modalisateur d''incertitude ?', NULL, '[{"id":"a","label":"Partez immédiatement !"},{"id":"b","label":"Il est peut-être rentré chez lui."},{"id":"c","label":"Est-ce qu''il est rentré ?"},{"id":"d","label":"Comme il fait beau aujourd''hui !"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'La modalité assertive pose un contenu comme vrai ou probable. L''adverbe «peut-être» est un modalisateur épistémique d''incertitude. La phrase A est injonctive, C est interrogative, D est exclamative. L''option B combine assertion et modalisation d''incertitude.', 'Confondre modalité assertive et certitude absolue : une assertion peut être modalisée.', 'valide', 'CRPE Français V3', 'free', true),

-- ─── Batch C — Série 5 : Types et genres de textes ───────────────────────────
('c3050000-0000-0000-0000-000000000001', 'Francais', 'analyse_langue', 'types_genres_textes', 'Types et genres de textes', 'Intermediaire', 'qcm', 'Quelle est la principale différence entre un type de texte et un genre discursif ?', NULL, '[{"id":"a","label":"Le type est plus long que le genre"},{"id":"b","label":"Le type est une catégorie linguistique abstraite ; le genre est une forme socio-discursive historiquement constituée"},{"id":"c","label":"Le genre appartient à la littérature ; le type appartient aux textes fonctionnels"},{"id":"d","label":"Le type concerne l''oral ; le genre concerne l''écrit"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'Le type de texte (narratif, descriptif, argumentatif, etc.) est une catégorie linguistique définie par des critères formels. Le genre est une forme sociale et historique : le roman, la fable, la recette, l''article de presse. Un genre peut relever de plusieurs types.', 'Croire que le genre et le type sont synonymes ou que la distinction est purement terminologique.', 'valide', 'CRPE Français V3', 'free', true),

('c3050000-0000-0000-0000-000000000002', 'Francais', 'analyse_langue', 'types_genres_textes', 'Types et genres de textes', 'Intermediaire', 'vrai_faux', 'Vrai ou faux : le type injonctif se caractérise par l''emploi dominant de l''impératif et/ou de l''infinitif.', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'Le texte injonctif vise à faire agir le destinataire. Il se reconnaît à l''emploi de l''impératif (Prenez deux œufs.), de l''infinitif à valeur injonctive (Battre les blancs en neige.), du présent de vérité générale ou du futur prescriptif. Les modes d''emploi, recettes et règlements relèvent de ce type.', 'Croire que le type injonctif n''emploie que l''impératif, en oubliant l''infinitif très courant dans les recettes.', 'valide', 'CRPE Français V3', 'free', true),

('c3050000-0000-0000-0000-000000000003', 'Francais', 'analyse_langue', 'types_genres_textes', 'Types et genres de textes', 'Intermediaire', 'qcm', 'Quels connecteurs sont typiques du texte explicatif ?', NULL, '[{"id":"a","label":"D''abord, ensuite, enfin"},{"id":"b","label":"Car, parce que, c''est pourquoi, en effet"},{"id":"c","label":"Cependant, néanmoins, or"},{"id":"d","label":"Soudain, alors, tout à coup"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'Le texte explicatif cherche à faire comprendre un phénomène. Il se caractérise par des connecteurs causaux (car, parce que) et consécutifs (c''est pourquoi, donc). Les connecteurs de la série A marquent l''énumération, ceux de C l''opposition (argumentatif), ceux de D la chronologie narrative.', 'Choisir la série A en confondant les connecteurs d''énumération avec ceux de causalité.', 'valide', 'CRPE Français V3', 'free', true),

('c3050000-0000-0000-0000-000000000004', 'Francais', 'analyse_langue', 'types_genres_textes', 'Types et genres de textes', 'Intermediaire', 'reponse_courte', 'Citez deux marques linguistiques caractéristiques du type descriptif.', NULL, NULL, '{"mode":"text","acceptableAnswers":["présent","imparfait","adjectifs qualificatifs","verbes d''état","compléments de lieu","être","paraître","sembler","groupes nominaux expansés"]}'::jsonb, 'Le type descriptif se caractérise par l''emploi de l''imparfait ou du présent de vérité générale, des adjectifs qualificatifs et groupes nominaux expansés, des verbes d''état (être, paraître, sembler), des compléments de lieu, et une progression thématique à thème constant.', 'Citer uniquement «beaucoup d''adjectifs» sans mentionner les verbes d''état ou les temps verbaux.', 'valide', 'CRPE Français V3', 'free', true),

('c3050000-0000-0000-0000-000000000005', 'Francais', 'analyse_langue', 'types_genres_textes', 'Types et genres de textes', 'Intermediaire', 'qcm', 'Le conte merveilleux est un genre discursif. À quel(s) type(s) de texte appartient-il principalement ?', NULL, '[{"id":"a","label":"Argumentatif et explicatif"},{"id":"b","label":"Narratif et descriptif"},{"id":"c","label":"Injonctif et dialogal"},{"id":"d","label":"Explicatif et injonctif"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'Le conte merveilleux relève principalement du type narratif (enchaînement d''événements, schéma narratif) et du type descriptif (portraits, décors). Il peut aussi contenir des passages dialogaux. Cette combinaison illustre que les genres réels mêlent plusieurs types.', 'Choisir uniquement «narratif» en oubliant la dimension descriptive importante dans les contes.', 'valide', 'CRPE Français V3', 'free', true),

('c3050000-0000-0000-0000-000000000006', 'Francais', 'analyse_langue', 'types_genres_textes', 'Types et genres de textes', 'Intermediaire', 'vrai_faux', 'Vrai ou faux : une lettre de réclamation relève du type argumentatif car elle vise à convaincre le destinataire d''agir.', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'Une lettre de réclamation est un genre relevant principalement du type argumentatif : thèse (le problème), arguments (les faits), conclusion (la demande). Elle peut aussi contenir des passages narratifs et injonctifs. Cette hybridité est typique des genres fonctionnels réels.', 'Croire que la lettre est un genre purement narratif parce qu''elle raconte des faits.', 'valide', 'CRPE Français V3', 'free', true),

('c3050000-0000-0000-0000-000000000007', 'Francais', 'analyse_langue', 'types_genres_textes', 'Types et genres de textes', 'Intermediaire', 'qcm', 'Quelle est la marque linguistique la plus caractéristique du type dialogal ?', NULL, '[{"id":"a","label":"L''emploi du passé simple"},{"id":"b","label":"L''alternance de tours de parole avec des pronoms de 1re et 2e personne"},{"id":"c","label":"La présence de nombreux adverbes de temps"},{"id":"d","label":"L''emploi exclusif du présent de l''indicatif"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'Le type dialogal se caractérise par l''alternance de tours de parole entre au moins deux interlocuteurs, avec une forte présence des pronoms de 1re et 2e personne, des déictiques et des marques d''interaction. Les genres relevant du dialogal : pièce de théâtre, interview, dialogue romanesque, conversation.', 'Choisir «l''emploi exclusif du présent» en généralisant à partir de dialogues de théâtre.', 'valide', 'CRPE Français V3', 'free', true),

('c3050000-0000-0000-0000-000000000008', 'Francais', 'analyse_langue', 'types_genres_textes', 'Types et genres de textes', 'Intermediaire', 'reponse_courte', 'Quel type de texte domine dans un article encyclopédique ? Justifiez en citant une marque linguistique.', NULL, NULL, '{"mode":"text","acceptableAnswers":["explicatif","informatif","présent de vérité générale","connecteurs causaux","troisième personne"]}'::jsonb, 'Un article encyclopédique relève principalement du type explicatif/informatif. On y trouve le présent de vérité générale, la 3e personne, des connecteurs logiques (car, en effet, ainsi), et un vocabulaire technique et précis.', 'Répondre «descriptif» parce que l''article décrit des phénomènes, en oubliant la visée explicative et causale.', 'valide', 'CRPE Français V3', 'free', true),

('c3050000-0000-0000-0000-000000000009', 'Francais', 'analyse_langue', 'types_genres_textes', 'Types et genres de textes', 'Intermediaire', 'vrai_faux', 'Vrai ou faux : un texte peut appartenir à plusieurs types à la fois, mais un seul type est généralement dominant.', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'Dans la quasi-totalité des textes réels, plusieurs types coexistent. Un roman peut contenir des passages descriptifs, dialogaux et argumentatifs. Cependant, on identifie un type dominant correspondant à la visée principale du texte.', 'Croire qu''un texte ne peut appartenir qu''à un seul type et chercher à tout prix une catégorie unique.', 'valide', 'CRPE Français V3', 'free', true),

('c3050000-0000-0000-0000-00000000000a', 'Francais', 'analyse_langue', 'types_genres_textes', 'Types et genres de textes', 'Intermediaire', 'qcm', 'Quel genre discursif relève du type argumentatif indirect ?', NULL, '[{"id":"a","label":"L''éditorial de journal"},{"id":"b","label":"Le plaidoyer judiciaire"},{"id":"c","label":"La fable de La Fontaine"},{"id":"d","label":"Le discours politique"}]'::jsonb, '{"mode":"single_choice","value":"c"}'::jsonb, 'L''argumentation indirecte présente une thèse à travers un récit ou une fiction sans l''énoncer directement. La fable est le genre emblématique : le récit animalier illustre une morale que le lecteur doit inférer. L''éditorial, le plaidoyer et le discours politique relèvent de l''argumentation directe.', 'Choisir le discours politique parce qu''il peut utiliser des anecdotes, en oubliant que sa visée argumentative est directe.', 'valide', 'CRPE Français V3', 'free', true),

-- ─── Batch C — Série 6 : Anaphores et substitution lexicale ──────────────────
('c3060000-0000-0000-0000-000000000001', 'Francais', 'analyse_langue', 'anaphores_substitution', 'Anaphores et substitution lexicale', 'Intermediaire', 'qcm', 'Quelle est la différence entre une anaphore et une cataphore ?', NULL, '[{"id":"a","label":"L''anaphore est pronominale, la cataphore est nominale"},{"id":"b","label":"L''anaphore reprend un élément antérieur dans le texte ; la cataphore annonce un élément qui suit"},{"id":"c","label":"L''anaphore est une figure de style ; la cataphore est un procédé grammatical"},{"id":"d","label":"L''anaphore est orale ; la cataphore est écrite"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'L''anaphore textuelle renvoie à un élément déjà mentionné. La cataphore anticipe un élément non encore introduit : «Je vous dirai ceci : partez.» où «ceci» est une cataphore de «partez». L''anaphore est beaucoup plus fréquente que la cataphore dans les textes courants.', 'Confondre avec la figure de répétition rhétorique qui porte aussi le nom d''anaphore.', 'valide', 'CRPE Français V3', 'free', true),

('c3060000-0000-0000-0000-000000000002', 'Francais', 'analyse_langue', 'anaphores_substitution', 'Anaphores et substitution lexicale', 'Intermediaire', 'vrai_faux', 'Vrai ou faux : dans «Marie a acheté un roman. Elle l''a lu en une nuit.», «elle» et «l''» renvoient tous deux à «Marie».', NULL, NULL, '{"mode":"boolean","value":false}'::jsonb, '«Elle» renvoie à Marie. Mais «l''» renvoie à «un roman». Il s''agit de deux anaphores avec deux antécédents différents. Il est essentiel d''identifier l''antécédent de chaque pronom de façon indépendante.', 'Associer automatiquement tous les pronoms à un seul antécédent sans analyser chaque occurrence séparément.', 'valide', 'CRPE Français V3', 'free', true),

('c3060000-0000-0000-0000-000000000003', 'Francais', 'analyse_langue', 'anaphores_substitution', 'Anaphores et substitution lexicale', 'Intermediaire', 'qcm', 'Dans «Le chat s''approcha du feu. L''animal s''endormit aussitôt.», «l''animal» est une reprise de quel type ?', NULL, '[{"id":"a","label":"Anaphore pronominale"},{"id":"b","label":"Anaphore nominale par synonyme"},{"id":"c","label":"Anaphore nominale par hyperonyme"},{"id":"d","label":"Anaphore nominale par périphrase"}]'::jsonb, '{"mode":"single_choice","value":"c"}'::jsonb, '«Animal» est un hyperonyme de «chat» : le terme générique qui inclut l''espèce chat dans une catégorie plus large. Une anaphore par synonyme substituerait un mot de sens équivalent (le félin), une périphrase développerait une description (le compagnon à fourrure).', 'Confondre hyperonyme et synonyme : «animal» désigne la catégorie englobante, pas un équivalent exact.', 'valide', 'CRPE Français V3', 'free', true),

('c3060000-0000-0000-0000-000000000004', 'Francais', 'analyse_langue', 'anaphores_substitution', 'Anaphores et substitution lexicale', 'Intermediaire', 'reponse_courte', 'Dans «La directrice entra dans la salle. Cette femme remarquable imposa le silence d''un regard.», quel est le type de la reprise «cette femme remarquable» ?', NULL, NULL, '{"mode":"text","acceptableAnswers":["anaphore nominale","reprise nominale","anaphore nominale avec appréciation","reprise par périphrase appréciative"]}'::jsonb, '«Cette femme remarquable» est une anaphore nominale avec appréciation : elle reprend «la directrice» avec un adjectif évaluatif (remarquable). Cette reprise assure la cohésion et exprime simultanément un jugement de valeur positif sur le personnage.', 'Répondre «anaphore pronominale» en ne voyant pas que «cette» est un déterminant démonstratif et non un pronom.', 'valide', 'CRPE Français V3', 'free', true),

('c3060000-0000-0000-0000-000000000005', 'Francais', 'analyse_langue', 'anaphores_substitution', 'Anaphores et substitution lexicale', 'Intermediaire', 'qcm', 'Quelle est la fonction des reprises anaphoriques dans un texte ?', NULL, '[{"id":"a","label":"Introduire de nouveaux référents pour enrichir le texte"},{"id":"b","label":"Assurer la cohésion référentielle en évitant les répétitions et en maintenant le fil du discours"},{"id":"c","label":"Exprimer le point de vue subjectif de l''auteur"},{"id":"d","label":"Organiser la progression logique des arguments"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'Les reprises anaphoriques assurent la cohésion textuelle et évitent les répétitions. Dans les reprises nominales enrichies, elles permettent aussi d''apporter des informations supplémentaires sur le référent. Cette notion est centrale pour enseigner la rédaction au cycle 3.', 'Répondre que les reprises introduisent de nouveaux référents, alors qu''elles reprennent des référents déjà connus.', 'valide', 'CRPE Français V3', 'free', true),

('c3060000-0000-0000-0000-000000000006', 'Francais', 'analyse_langue', 'anaphores_substitution', 'Anaphores et substitution lexicale', 'Intermediaire', 'vrai_faux', 'Vrai ou faux : les pronoms «y» et «en» peuvent fonctionner comme des reprises anaphoriques adverbiales.', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'Les pronoms adverbiaux «y» et «en» reprennent des groupes prépositionnels : «Il pense à son avenir → Il y pense» ; «Il revient de Paris → Il en revient». Ces reprises font partie de la chaîne anaphorique au même titre que les reprises pronominales et nominales.', 'Croire que «y» et «en» sont de simples compléments sans fonction anaphorique.', 'valide', 'CRPE Français V3', 'free', true),

('c3060000-0000-0000-0000-000000000007', 'Francais', 'analyse_langue', 'anaphores_substitution', 'Anaphores et substitution lexicale', 'Intermediaire', 'qcm', 'Quelle reprise est à la fois anaphorique et péjorative dans : «Le ministre prit la parole. L''individu se lança dans un long discours.» ?', NULL, '[{"id":"a","label":"prit la parole"},{"id":"b","label":"L''individu"},{"id":"c","label":"un long discours"},{"id":"d","label":"se lança"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, '«L''individu» reprend «le ministre» : c''est une anaphore nominale à valeur péjorative. Le terme «individu» (sans qualification) a une connotation négative dans ce contexte. Les reprises nominales permettent d''exprimer implicitement une appréciation sans utiliser d''adjectif explicite.', 'Choisir «un long discours» qui n''est pas une reprise anaphorique mais une nouvelle information.', 'valide', 'CRPE Français V3', 'free', true),

('c3060000-0000-0000-0000-000000000008', 'Francais', 'analyse_langue', 'anaphores_substitution', 'Anaphores et substitution lexicale', 'Intermediaire', 'reponse_courte', 'Qu''appelle-t-on une «chaîne de référence» ?', NULL, NULL, '{"mode":"text","acceptableAnswers":["chaîne de référence","ensemble des reprises désignant le même référent","suite des expressions coréférentielles"]}'::jsonb, 'Une chaîne de référence est l''ensemble des expressions coréférentielles qui désignent le même référent tout au long d''un texte : Marie → elle → la jeune femme → notre héroïne. Identifier les chaînes de référence est fondamental pour analyser la cohésion textuelle.', 'Décrire seulement une reprise isolée au lieu de définir l''ensemble de la chaîne sur l''ensemble du texte.', 'valide', 'CRPE Français V3', 'free', true),

('c3060000-0000-0000-0000-000000000009', 'Francais', 'analyse_langue', 'anaphores_substitution', 'Anaphores et substitution lexicale', 'Intermediaire', 'vrai_faux', 'Vrai ou faux : une périphrase anaphorique peut renseigner sur le point de vue du narrateur sur le personnage qu''elle désigne.', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'Une périphrase anaphorique révèle le regard du narrateur : «L''homme qui aimait les enfants» ou «le bourreau des familles» désignent le même personnage mais expriment des points de vue opposés. Cette dimension évaluative est exploitable dans l''analyse littéraire et l''enseignement de l''écriture.', 'Croire que la périphrase est un simple substitut neutre sans portée énonciative.', 'valide', 'CRPE Français V3', 'free', true),

('c3060000-0000-0000-0000-00000000000a', 'Francais', 'analyse_langue', 'anaphores_substitution', 'Anaphores et substitution lexicale', 'Intermediaire', 'qcm', 'Dans quelle phrase la reprise anaphorique est-elle mal accordée ?', NULL, '[{"id":"a","label":"Les élèves rendirent leurs copies. Ils avaient bien travaillé."},{"id":"b","label":"La classe était silencieuse. Elle attendait les résultats."},{"id":"c","label":"Paul et Julie arrivèrent. Il était épuisé."},{"id":"d","label":"Le professeur distribua les polycopiés. Il en avait apporté trente."}]'::jsonb, '{"mode":"single_choice","value":"c"}'::jsonb, 'Dans la phrase C, «il» est un pronom masculin singulier qui reprend «Paul et Julie», groupe au pluriel mixte. Il faudrait «ils étaient épuisés». Cette erreur crée une rupture de cohésion référentielle, typique des erreurs à corriger en didactique de l''écriture.', 'Choisir la phrase D en croyant que «en» ne peut pas reprendre un nom de chose.', 'valide', 'CRPE Français V3', 'free', true),

-- ─── Batch C — Série 7 : Cohérence et cohésion textuelle ─────────────────────
('c3070000-0000-0000-0000-000000000001', 'Francais', 'comprehension_texte', 'coherence_textuelle', 'Cohérence et cohésion textuelle', 'Difficile', 'qcm', 'Quelle est la distinction entre cohérence et cohésion textuelle ?', NULL, '[{"id":"a","label":"La cohérence concerne les connecteurs ; la cohésion concerne le sens global"},{"id":"b","label":"La cohérence est le niveau sémantique (non-contradiction, continuité de sens) ; la cohésion est le niveau formel (connecteurs, reprises, ellipses)"},{"id":"c","label":"La cohérence s''applique aux textes écrits ; la cohésion s''applique à l''oral"},{"id":"d","label":"La cohérence et la cohésion sont deux termes synonymes"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'La cohérence est la propriété sémantique du texte : les informations ne doivent pas se contredire et doivent s''enchaîner logiquement (principe de non-contradiction et de continuité). La cohésion désigne les dispositifs formels qui créent la continuité textuelle : connecteurs, reprises pronominales, ellipses, temps verbaux. Un texte peut être cohésif (beaucoup de connecteurs) sans être cohérent (contradictions de sens).', 'Inverser les deux notions ou les confondre en ne retenant qu''une définition floue de «texte bien écrit».', 'valide', 'CRPE Français V3', 'free', true),

('c3070000-0000-0000-0000-000000000002', 'Francais', 'comprehension_texte', 'coherence_textuelle', 'Cohérence et cohésion textuelle', 'Difficile', 'qcm', 'Dans la progression thématique linéaire, comment s''enchaînent les informations ?', NULL, '[{"id":"a","label":"Le même thème est repris dans chaque phrase"},{"id":"b","label":"Le rhème d''une phrase devient le thème de la phrase suivante"},{"id":"c","label":"Les thèmes varient librement d''une phrase à l''autre"},{"id":"d","label":"Le thème global se décompose en sous-thèmes développés en parallèle"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'Dans la progression thématique linéaire, le rhème (information nouvelle) d''une phrase devient le thème (point de départ) de la phrase suivante : «Pierre a rencontré un professeur. Ce professeur lui a remis un document. Ce document contenait des instructions.» Ce type de progression est fréquent dans les récits et les textes explicatifs.', 'Confondre progression linéaire et progression à thème constant (qui répète le même thème).', 'valide', 'CRPE Français V3', 'free', true),

('c3070000-0000-0000-0000-000000000003', 'Francais', 'comprehension_texte', 'coherence_textuelle', 'Cohérence et cohésion textuelle', 'Difficile', 'vrai_faux', 'Vrai ou faux : dans une progression à thème constant, la même entité est reprise comme point de départ de chaque phrase.', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'La progression à thème constant est caractéristique des textes descriptifs et des portraits : chaque phrase repart du même thème (souvent le même personnage ou le même objet) pour lui attribuer de nouvelles informations. Exemple : «Marie est grande. Elle a les cheveux noirs. Elle porte toujours un carnet.» Le thème «Marie» reste constant.', 'Confondre avec la progression à thèmes dérivés où plusieurs sous-thèmes sont développés à partir d''un hyper-thème.', 'valide', 'CRPE Français V3', 'free', true),

('c3070000-0000-0000-0000-000000000004', 'Francais', 'comprehension_texte', 'coherence_textuelle', 'Cohérence et cohésion textuelle', 'Difficile', 'reponse_courte', 'Qu''est-ce qu''une isotopie et quel rôle joue-t-elle dans la cohérence d''un texte ?', NULL, NULL, '{"mode":"text","acceptableAnswers":["isotopie","champ sémantique récurrent","récurrence de sèmes","cohérence sémantique"]}'::jsonb, 'Une isotopie est la récurrence d''un même trait sémantique (sème) dans plusieurs mots d''un texte, créant un champ sémantique cohérent. Par exemple, dans un texte sur la mer, les mots vague, mouette, sel, marée, naufrage partagent le sème /marin/. Les isotopies guident la lecture et assurent la cohérence globale en ancrant le texte dans un univers sémantique stable.', 'Confondre isotopie et champ lexical : le champ lexical désigne les mots liés à un thème, l''isotopie désigne la récurrence d''un trait sémantique partagé.', 'valide', 'CRPE Français V3', 'free', true),

('c3070000-0000-0000-0000-000000000005', 'Francais', 'comprehension_texte', 'coherence_textuelle', 'Cohérence et cohésion textuelle', 'Difficile', 'qcm', 'Laquelle de ces ruptures est une rupture de cohérence (et non seulement de cohésion) ?', NULL, '[{"id":"a","label":"Oublier un connecteur entre deux paragraphes"},{"id":"b","label":"Employer un pronom sans antécédent clairement identifiable"},{"id":"c","label":"Affirmer d''abord que le suspect était absent, puis qu''il se trouvait sur les lieux"},{"id":"d","label":"Changer de temps verbal sans raison apparente"}]'::jsonb, '{"mode":"single_choice","value":"c"}'::jsonb, 'La rupture de cohérence est une contradiction au niveau du sens : affirmer deux propositions incompatibles (absent / présent) viole le principe de non-contradiction. Les options A, B et D sont des ruptures de cohésion (formelle) : connecteur manquant, pronom sans antécédent, incohérence des temps. La distinction cohérence/cohésion est fondamentale pour l''analyse et la correction de textes d''élèves.', 'Confondre rupture de cohésion (problème formel) et rupture de cohérence (contradiction de sens).', 'valide', 'CRPE Français V3', 'free', true),

('c3070000-0000-0000-0000-000000000006', 'Francais', 'comprehension_texte', 'coherence_textuelle', 'Cohérence et cohésion textuelle', 'Difficile', 'vrai_faux', 'Vrai ou faux : un paragraphe bien construit commence généralement par une phrase-thème qui annonce l''idée développée.', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'La phrase-thème (ou phrase d''ouverture de paragraphe) annonce l''idée directrice qui sera développée dans les phrases suivantes. Ce modèle organisationnel est enseigné au cycle 3 et au collège. Il favorise la lisibilité et la cohérence locale (au niveau du paragraphe) et globale (articulation des paragraphes entre eux).', 'Croire que ce schéma est uniquement propre au texte argumentatif : il s''applique aussi aux textes explicatifs et descriptifs.', 'valide', 'CRPE Français V3', 'free', true),

('c3070000-0000-0000-0000-000000000007', 'Francais', 'comprehension_texte', 'coherence_textuelle', 'Cohérence et cohésion textuelle', 'Difficile', 'qcm', 'Quel est le rôle des connecteurs dans la cohésion textuelle ?', NULL, '[{"id":"a","label":"Ils introduisent de nouveaux thèmes dans le texte"},{"id":"b","label":"Ils marquent les relations logiques, temporelles ou spatiales entre les propositions"},{"id":"c","label":"Ils remplacent les répétitions lexicales dans le texte"},{"id":"d","label":"Ils signalent uniquement les rapports de cause à effet"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'Les connecteurs (ou organisateurs textuels) assurent la cohésion en marquant les relations entre propositions : relations logiques (donc, car, cependant), temporelles (ensuite, puis, auparavant), spatiales (au-dessus, à gauche), additives (de plus, en outre). Ils orientent la lecture et signalent la progression du texte. Contrairement à l''option C, les reprises anaphoriques assurent la non-répétition.', 'Croire que les connecteurs servent uniquement à exprimer la cause et la conséquence.', 'valide', 'CRPE Français V3', 'free', true),

('c3070000-0000-0000-0000-000000000008', 'Francais', 'comprehension_texte', 'coherence_textuelle', 'Cohérence et cohésion textuelle', 'Difficile', 'reponse_courte', 'Dans le texte suivant, identifiez la rupture de cohérence : «Paul déteste les légumes. Ce matin, il a mangé une salade avec plaisir. Puis il a refusé le dessert.»', NULL, NULL, '{"mode":"text","acceptableAnswers":["contradiction","rupture de cohérence","Paul déteste les légumes mais mange une salade avec plaisir","incohérence sémantique"]}'::jsonb, 'La rupture de cohérence se situe entre «Paul déteste les légumes» et «il a mangé une salade avec plaisir» : une salade est composée de légumes, et manger avec plaisir contredit l''idée de détester les légumes. C''est une violation du principe de non-contradiction, qui est le cœur de la cohérence sémantique. La troisième phrase est cohérente avec les deux premières si on l''isole.', 'Signaler uniquement la rupture de temps verbal ou l''absence de connecteur, qui sont des problèmes de cohésion et non de cohérence.', 'valide', 'CRPE Français V3', 'free', true),

('c3070000-0000-0000-0000-000000000009', 'Francais', 'comprehension_texte', 'coherence_textuelle', 'Cohérence et cohésion textuelle', 'Difficile', 'vrai_faux', 'Vrai ou faux : la progression à thèmes dérivés développe plusieurs sous-thèmes tirés d''un hyper-thème initial.', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'Dans la progression à thèmes dérivés, un hyper-thème initial se décompose en plusieurs sous-thèmes qui sont développés en parallèle. Exemple : «La France a trois grands reliefs : les montagnes, les plaines et les côtes. Les montagnes... Les plaines... Les côtes...» Ce type de progression est courant dans les textes descriptifs, géographiques et encyclopédiques.', 'Confondre avec la progression linéaire où chaque rhème devient le thème suivant, sans retour à un hyper-thème.', 'valide', 'CRPE Français V3', 'free', true),

('c3070000-0000-0000-0000-00000000000a', 'Francais', 'comprehension_texte', 'coherence_textuelle', 'Cohérence et cohésion textuelle', 'Difficile', 'qcm', 'Quelle compétence didactique est directement liée à la maîtrise de la cohésion textuelle chez les élèves du cycle 3 ?', NULL, '[{"id":"a","label":"La maîtrise de l''orthographe lexicale"},{"id":"b","label":"L''emploi correct des temps du passé"},{"id":"c","label":"L''utilisation des reprises pronominales pour éviter les répétitions dans les productions écrites"},{"id":"d","label":"La lecture à haute voix fluente"}]'::jsonb, '{"mode":"single_choice","value":"c"}'::jsonb, 'Au cycle 3, une difficulté majeure en production écrite est la répétition excessive d''un nom (souvent le personnage principal) au lieu d''utiliser des reprises pronominales ou nominales. Enseigner la cohésion textuelle, c''est apprendre aux élèves à construire des chaînes de référence variées. C''est un point central des programmes de français du cycle 3.', 'Choisir «l''emploi correct des temps du passé» qui est lié à la narration et non directement à la cohésion référentielle.', 'valide', 'CRPE Français V3', 'free', true),

-- ─── Batch C — Série 8 : Le schéma narratif ──────────────────────────────────
('c3080000-0000-0000-0000-000000000001', 'Francais', 'comprehension_texte', 'schema_narratif', 'Le schéma narratif', 'Intermediaire', 'qcm', 'Combien d''étapes compte le schéma narratif canonique ?', NULL, '[{"id":"a","label":"3 étapes"},{"id":"b","label":"4 étapes"},{"id":"c","label":"5 étapes"},{"id":"d","label":"6 étapes"}]'::jsonb, '{"mode":"single_choice","value":"c"}'::jsonb, 'Le schéma narratif canonique (modèle de Larivaille-Adam) comprend 5 étapes : (1) situation initiale (état d''équilibre), (2) élément perturbateur/déclencheur (rupture de l''équilibre), (3) péripéties/actions (tentatives de rétablir l''équilibre), (4) résolution/dénouement (le problème est résolu), (5) situation finale (nouvel état d''équilibre). Ce modèle s''applique à la majorité des récits, notamment les contes.', 'Confondre avec le schéma de Propp ou proposer 3 étapes (début, milieu, fin) qui est une simplification insuffisante.', 'valide', 'CRPE Français V3', 'free', true),

('c3080000-0000-0000-0000-000000000002', 'Francais', 'comprehension_texte', 'schema_narratif', 'Le schéma narratif', 'Intermediaire', 'vrai_faux', 'Vrai ou faux : l''élément perturbateur est l''étape qui rompt l''équilibre de la situation initiale.', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'L''élément perturbateur (ou élément déclencheur) est la force ou l''événement qui brise l''état d''équilibre de la situation initiale et met le récit en mouvement. Sans lui, il n''y aurait pas de récit. Dans un conte, c''est souvent un problème, une menace, une disparition ou un manque. Il est suivi des péripéties qui tentent de rétablir l''équilibre.', 'Confondre l''élément perturbateur avec les péripéties, qui sont les actions menées en réponse à la perturbation.', 'valide', 'CRPE Français V3', 'free', true),

('c3080000-0000-0000-0000-000000000003', 'Francais', 'comprehension_texte', 'schema_narratif', 'Le schéma narratif', 'Intermediaire', 'qcm', 'Dans le schéma actantiel de Greimas, quel rôle désigne l''adjuvant ?', NULL, '[{"id":"a","label":"Le personnage qui s''oppose à la quête du sujet"},{"id":"b","label":"Le personnage ou l''élément qui aide le sujet dans sa quête"},{"id":"c","label":"Le personnage qui fixe l''objectif de la quête"},{"id":"d","label":"Le bénéficiaire de la quête"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'Dans le schéma actantiel de Greimas, les six actants sont : sujet (qui cherche), objet (ce qui est cherché), destinateur (qui motive la quête), destinataire (qui bénéficie de la quête), adjuvant (qui aide le sujet) et opposant (qui s''oppose). L''adjuvant peut être un personnage, un objet magique ou une force naturelle.', 'Confondre adjuvant et destinateur : le destinateur donne la mission, l''adjuvant aide à l''accomplir.', 'valide', 'CRPE Français V3', 'free', true),

('c3080000-0000-0000-0000-000000000004', 'Francais', 'comprehension_texte', 'schema_narratif', 'Le schéma narratif', 'Intermediaire', 'reponse_courte', 'Dans un conte classique, quel temps verbal est employé pour les actions principales qui font avancer le récit ?', NULL, NULL, '{"mode":"text","acceptableAnswers":["passé simple"]}'::jsonb, 'Le passé simple est le temps des actions principales et ponctuelles dans le récit littéraire. Il s''oppose à l''imparfait qui décrit les états, les arrière-plans et les actions habituelles. Cette opposition passé simple / imparfait est fondamentale dans le récit au passé : «La forêt était sombre (imparfait = décor) quand le loup apparut (passé simple = action)».', 'Proposer l''imparfait qui est le temps du décor et de l''arrière-plan, non des actions principales.', 'valide', 'CRPE Français V3', 'free', true),

('c3080000-0000-0000-0000-000000000005', 'Francais', 'comprehension_texte', 'schema_narratif', 'Le schéma narratif', 'Intermediaire', 'qcm', 'Qu''est-ce que l''incipit d''un texte narratif ?', NULL, '[{"id":"a","label":"La dernière phrase du récit"},{"id":"b","label":"Le moment de résolution du problème"},{"id":"c","label":"Les premières lignes du récit, qui posent le cadre et les personnages"},{"id":"d","label":"Le titre du récit"}]'::jsonb, '{"mode":"single_choice","value":"c"}'::jsonb, 'L''incipit (du latin incipit, «il commence») désigne les premières lignes d''un roman ou d''un récit. Il a pour fonction de poser le cadre spatio-temporel, d''introduire les personnages et de créer un contrat de lecture. Son opposé est l''explicit (ou clausule), les dernières lignes qui clôturent le récit. L''analyse de l''incipit est une compétence littéraire attendue au CRPE.', 'Confondre incipit et situation initiale (schéma narratif) : l''incipit est un terme textuel, la situation initiale est une étape structurelle.', 'valide', 'CRPE Français V3', 'free', true),

('c3080000-0000-0000-0000-000000000006', 'Francais', 'comprehension_texte', 'schema_narratif', 'Le schéma narratif', 'Intermediaire', 'vrai_faux', 'Vrai ou faux : le plus-que-parfait sert à exprimer une action antérieure à d''autres actions passées dans un récit.', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'Le plus-que-parfait exprime l''antériorité par rapport à un repère passé : «Il mangea le gâteau que sa mère avait préparé» (le gâteau a été préparé avant qu''il le mange). Dans le récit, le plus-que-parfait permet le retour en arrière (analepse ou flash-back). C''est un temps de l''ancrage dans un système temporel du passé.', 'Confondre plus-que-parfait et passé antérieur (qui exprime aussi l''antériorité mais dans des subordonnées de temps avec des conjonctions temporelles).', 'valide', 'CRPE Français V3', 'free', true),

('c3080000-0000-0000-0000-000000000007', 'Francais', 'comprehension_texte', 'schema_narratif', 'Le schéma narratif', 'Intermediaire', 'qcm', 'Dans quel type de narration le narrateur est-il un personnage de l''histoire ?', NULL, '[{"id":"a","label":"La narration à la 3e personne (hétérodiégétique)"},{"id":"b","label":"La narration à la 1re personne (homodiégétique)"},{"id":"c","label":"La narration omnisciente"},{"id":"d","label":"La narration à focalisation externe"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'La narration homodiégétique (Genette) est celle où le narrateur est un personnage de l''histoire qu''il raconte. Elle utilise la 1re personne (je). La narration hétérodiégétique utilise la 3e personne : le narrateur n''est pas un personnage du récit. Ces notions permettent d''analyser la distance entre narrateur et histoire.', 'Croire que narration à la 1re personne et focalisation interne sont synonymes : une narration homodiégétique peut adopter une focalisation zéro (narrateur qui en sait plus que les autres personnages).', 'valide', 'CRPE Français V3', 'free', true),

('c3080000-0000-0000-0000-000000000008', 'Francais', 'comprehension_texte', 'schema_narratif', 'Le schéma narratif', 'Intermediaire', 'reponse_courte', 'Donnez un synonyme du terme «élément perturbateur» utilisé dans certains manuels scolaires.', NULL, NULL, '{"mode":"text","acceptableAnswers":["élément déclencheur","déclencheur","perturbation","force perturbatrice","nœud"]}'::jsonb, 'L''élément perturbateur est aussi appelé élément déclencheur, force perturbatrice ou nœud selon les manuels. Ces termes désignent tous l''événement qui rompt l''équilibre initial et met le récit en mouvement. La variation terminologique est normale au primaire ; l''essentiel est que les élèves comprennent la fonction de cette étape dans la dynamique narrative.', 'Proposer «péripéties» qui désigne les actions qui suivent la perturbation, non la perturbation elle-même.', 'valide', 'CRPE Français V3', 'free', true),

('c3080000-0000-0000-0000-000000000009', 'Francais', 'comprehension_texte', 'schema_narratif', 'Le schéma narratif', 'Intermediaire', 'vrai_faux', 'Vrai ou faux : la situation finale d''un récit est toujours un retour à l''état de la situation initiale.', NULL, NULL, '{"mode":"boolean","value":false}'::jsonb, 'La situation finale clôt le récit en établissant un nouvel état d''équilibre, mais cet équilibre n''est pas nécessairement identique à la situation initiale. Dans de nombreux récits, la situation finale marque une transformation des personnages ou du monde fictif : le héros a grandi, la société a changé. Les récits tragiques ou ouverts peuvent même ne pas atteindre un équilibre positif.', 'Croire que tout récit revient à son état initial, en confondant avec la structure circulaire des contes traditionnels.', 'valide', 'CRPE Français V3', 'free', true),

('c3080000-0000-0000-0000-00000000000a', 'Francais', 'comprehension_texte', 'schema_narratif', 'Le schéma narratif', 'Intermediaire', 'qcm', 'Quel terme désigne le récit enchâssé à l''intérieur d''un autre récit ?', NULL, '[{"id":"a","label":"Récit cadre"},{"id":"b","label":"Métarécit"},{"id":"c","label":"Récit enchâssé ou récit second"},{"id":"d","label":"Analepse"}]'::jsonb, '{"mode":"single_choice","value":"c"}'::jsonb, 'Lorsqu''un personnage du récit principal raconte lui-même une histoire, on obtient un récit enchâssé (ou récit second, récit métadiégétique chez Genette). Le récit qui le contient est le récit cadre. Exemple célèbre : Les Mille et Une Nuits où Schéhérazade (récit cadre) raconte des histoires (récits enchâssés). L''analepse (flash-back) est différente : c''est un retour en arrière dans le temps du récit.', 'Confondre récit enchâssé et analepse (flash-back) ou avec le récit cadre qui est l''histoire principale.', 'valide', 'CRPE Français V3', 'free', true),

-- ─── Batch C — Série 9 : Le texte argumentatif ───────────────────────────────
('c3090000-0000-0000-0000-000000000001', 'Francais', 'comprehension_texte', 'texte_argumentatif', 'Le texte argumentatif', 'Difficile', 'qcm', 'Quelle est la structure de base de l''argumentation ?', NULL, '[{"id":"a","label":"Introduction, développement, conclusion"},{"id":"b","label":"Thèse, argument(s), exemple(s)/illustration(s)"},{"id":"c","label":"Sujet, verbe, complément"},{"id":"d","label":"Problème, cause, solution"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'L''argumentation repose sur une structure ternaire : la thèse (la position défendue), les arguments (les raisons qui soutiennent la thèse), et les exemples ou illustrations (qui rendent les arguments concrets et crédibles). Cette structure peut être développée de façon linéaire ou dialectique (thèse, antithèse, synthèse).', 'Confondre avec le plan de dissertation (introduction, développement, conclusion) qui est une forme rhétorique et non la structure argumentative minimale.', 'valide', 'CRPE Français V3', 'free', true),

('c3090000-0000-0000-0000-000000000002', 'Francais', 'comprehension_texte', 'texte_argumentatif', 'Le texte argumentatif', 'Difficile', 'vrai_faux', 'Vrai ou faux : une thèse implicite est une thèse que l''auteur n''énonce pas directement mais que le lecteur doit inférer.', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'La thèse implicite n''est pas formulée explicitement par l''auteur : elle est construite par le lecteur à partir des arguments, des exemples et du ton du texte. L''argumentation indirecte (fable, conte philosophique, satire) repose sur des thèses implicites. La thèse explicite, au contraire, est énoncée clairement dans le texte (je pense que, il est certain que).', 'Croire qu''une thèse doit toujours être formulée explicitement pour qu''il y ait argumentation.', 'valide', 'CRPE Français V3', 'free', true),

('c3090000-0000-0000-0000-000000000003', 'Francais', 'comprehension_texte', 'texte_argumentatif', 'Le texte argumentatif', 'Difficile', 'qcm', 'Quel type d''argument s''appuie sur l''opinion d''un expert ou d''une autorité reconnue ?', NULL, '[{"id":"a","label":"L''argument par analogie"},{"id":"b","label":"L''argument d''autorité"},{"id":"c","label":"L''argument a contrario"},{"id":"d","label":"L''argument par les faits"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'L''argument d''autorité s''appuie sur la parole ou l''opinion d''un expert, d''une institution ou d''un texte de référence pour valider une thèse. Il peut être légitime (citation d''un spécialiste reconnu) ou fallacieux (citation hors contexte ou d''une source peu fiable). Au CRPE, reconnaître ce type d''argument est attendu dans l''analyse rhétorique des textes.', 'Confondre avec l''argument par les faits qui s''appuie sur des données observables et vérifiables, non sur des opinions.', 'valide', 'CRPE Français V3', 'free', true),

('c3090000-0000-0000-0000-000000000004', 'Francais', 'comprehension_texte', 'texte_argumentatif', 'Le texte argumentatif', 'Difficile', 'reponse_courte', 'Quel connecteur logique est caractéristique de la réfutation concessive ?', NULL, NULL, '{"mode":"text","acceptableAnswers":["certes... mais","mais","cependant","il est vrai que... mais","sans doute... mais"]}'::jsonb, 'La réfutation concessive reconnaît d''abord la part de vérité de la thèse adverse avant de la dépasser : «Certes, les élèves utilisent les réseaux sociaux... mais cette pratique peut aussi développer des compétences numériques.» Le connecteur certes... mais (ou il est vrai que... cependant) est le marqueur canonique de la concession rhétorique.', 'Citer uniquement «mais» sans mentionner la structure concessive complète qui inclut une reconnaissance de la thèse adverse.', 'valide', 'CRPE Français V3', 'free', true),

('c3090000-0000-0000-0000-000000000005', 'Francais', 'comprehension_texte', 'texte_argumentatif', 'Le texte argumentatif', 'Difficile', 'qcm', 'Qu''est-ce qu''un argument a contrario ?', NULL, '[{"id":"a","label":"Un argument qui cite un exemple contraire à la thèse pour la réfuter"},{"id":"b","label":"Un argument qui établit la vérité d''une thèse en montrant les conséquences négatives de son contraire"},{"id":"c","label":"Un argument qui s''oppose à la thèse principale"},{"id":"d","label":"Un argument ironique qui contredit l''auteur lui-même"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'L''argument a contrario (ou par la négative) établit la thèse en montrant ce qui se passerait si son contraire était vrai. Exemple : «Sans règles, la société sombrait dans le chaos» pour justifier la nécessité des lois. Ce type d''argument est puissant car il rend la thèse adverse indéfendable. Ne pas le confondre avec la réfutation ou la concession.', 'Croire que a contrario signifie simplement «au contraire» et l''assimiler à une simple réfutation.', 'valide', 'CRPE Français V3', 'free', true),

('c3090000-0000-0000-0000-000000000006', 'Francais', 'comprehension_texte', 'texte_argumentatif', 'Le texte argumentatif', 'Difficile', 'vrai_faux', 'Vrai ou faux : dans un texte argumentatif, une opinion se distingue d''un fait par sa vérifiabilité.', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'Un fait est une proposition vérifiable et potentiellement prouvable : «La France compte 67 millions d''habitants.» Une opinion est une position subjective non directement vérifiable : «La France est un beau pays.» Une valeur est un jugement éthique ou esthétique : «La solidarité est une vertu.» Distinguer fait, opinion et valeur est une compétence critique fondamentale, enseignée dès le cycle 3.', 'Croire que les opinions ne peuvent pas être argumentées ou défendues, ce qui confondrait opinion et préférence purement subjective.', 'valide', 'CRPE Français V3', 'free', true),

('c3090000-0000-0000-0000-000000000007', 'Francais', 'comprehension_texte', 'texte_argumentatif', 'Le texte argumentatif', 'Difficile', 'qcm', 'Lequel de ces marqueurs indique que l''énonciateur présente quelque chose comme une certitude partagée ?', NULL, '[{"id":"a","label":"Il me semble que"},{"id":"b","label":"À mon avis"},{"id":"c","label":"Il est indéniable que"},{"id":"d","label":"Je crois que"}]'::jsonb, '{"mode":"single_choice","value":"c"}'::jsonb, 'L''expression «il est indéniable que» est un modalisateur de certitude forte qui présente la thèse comme une évidence partagée par tous. C''est une stratégie rhétorique : l''énonciateur feint de rappeler un fait connu pour éviter la contestation. Les options A, B et D sont des marqueurs d''opinion subjective qui présentent la thèse comme un point de vue personnel.', 'Choisir «à mon avis» qui exprime au contraire une opinion subjective et non une certitude présentée comme universelle.', 'valide', 'CRPE Français V3', 'free', true),

('c3090000-0000-0000-0000-000000000008', 'Francais', 'comprehension_texte', 'texte_argumentatif', 'Le texte argumentatif', 'Difficile', 'reponse_courte', 'Citez un genre littéraire relevant de l''argumentation indirecte et expliquez brièvement pourquoi.', NULL, NULL, '{"mode":"text","acceptableAnswers":["fable","conte philosophique","utopie","roman à thèse","satire"]}'::jsonb, 'La fable (La Fontaine) est le genre emblématique de l''argumentation indirecte : le récit animalier met en scène une situation fictive dont la morale (thèse implicite) est tirée à la fin. Le lecteur doit faire le transfert entre la fiction et la réalité. Le conte philosophique (Voltaire, Candide) utilise le même procédé à plus grande échelle pour critiquer des idéologies.', 'Citer le roman en général sans préciser la sous-catégorie «roman à thèse» ou «conte philosophique» qui sont les formes d''argumentation indirecte.', 'valide', 'CRPE Français V3', 'free', true),

('c3090000-0000-0000-0000-000000000009', 'Francais', 'comprehension_texte', 'texte_argumentatif', 'Le texte argumentatif', 'Difficile', 'vrai_faux', 'Vrai ou faux : l''ironie est un procédé de réfutation qui consiste à feindre d''approuver la thèse adverse pour mieux la ridiculiser.', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'L''ironie rhétorique (ou antiphrase) consiste à dire le contraire de ce qu''on pense, de façon à ridiculiser ou réfuter la thèse adverse. C''est un procédé polémique. Exemple : «Oui, c''est une excellente idée de supprimer les bibliothèques !» dit par quelqu''un qui les défend. L''ironie repose sur la complicité du lecteur qui doit décoder le second degré.', 'Confondre ironie et sarcasme (qui est une forme d''ironie blessante) ou avec la concession (qui reconnaît sincèrement la thèse adverse).', 'valide', 'CRPE Français V3', 'free', true),

('c3090000-0000-0000-0000-00000000000a', 'Francais', 'comprehension_texte', 'texte_argumentatif', 'Le texte argumentatif', 'Difficile', 'qcm', 'Quelle est la différence entre un exemple et un argument dans un texte argumentatif ?', NULL, '[{"id":"a","label":"L''exemple prouve la thèse ; l''argument illustre l''exemple"},{"id":"b","label":"L''argument soutient la thèse par une raison générale ; l''exemple illustre concrètement l''argument"},{"id":"c","label":"L''argument et l''exemple sont synonymes dans le texte argumentatif"},{"id":"d","label":"L''exemple contredit l''argument pour créer un effet dialectique"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'L''argument est une raison générale qui justifie la thèse : il répond à «pourquoi». L''exemple est un cas particulier, concret ou historique, qui illustre l''argument et le rend crédible : il répond à «par exemple». La structure canonique est : thèse → argument → exemple. Confondre les deux affaiblit l''analyse argumentative car un exemple seul ne prouve pas une thèse générale.', 'Croire que citer des exemples suffit à constituer une argumentation solide, en oubliant la nécessité d''une raison générale (argument).', 'valide', 'CRPE Français V3', 'free', true),

-- ─── Batch C — Série 10 : Conscience phonologique ────────────────────────────
('c30a0000-0000-0000-0000-000000000001', 'Francais', 'didactique_francais', 'conscience_phonologique', 'Conscience phonologique', 'Intermediaire', 'qcm', 'Qu''est-ce que la conscience phonologique ?', NULL, '[{"id":"a","label":"La capacité à reconnaître les lettres de l''alphabet"},{"id":"b","label":"La capacité à identifier, segmenter et manipuler les unités sonores de la langue orale"},{"id":"c","label":"La connaissance des règles orthographiques du français"},{"id":"d","label":"La capacité à lire des mots à voix haute de façon fluente"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'La conscience phonologique est la capacité métalinguistique qui permet de prendre les sons de la langue pour objets de réflexion et de manipulation. Elle comprend la conscience syllabique (identifier et manipuler les syllabes), la conscience phonémique (identifier et manipuler les phonèmes) et la conscience des rimes. Elle est distincte de la connaissance des lettres (option A) et de la fluence (option D).', 'Confondre conscience phonologique et conscience grapho-phonémique : la conscience phonologique concerne le son (oral), pas la lettre (écrit).', 'valide', 'CRPE Français V3', 'free', true),

('c30a0000-0000-0000-0000-000000000002', 'Francais', 'didactique_francais', 'conscience_phonologique', 'Conscience phonologique', 'Intermediaire', 'vrai_faux', 'Vrai ou faux : la conscience syllabique se développe avant la conscience phonémique chez l''enfant.', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'Le développement de la conscience phonologique suit une progression : la conscience des syllabes (unités plus larges, plus facilement perceptibles) précède la conscience des phonèmes (unités minimales, plus abstraites). Un enfant de 4-5 ans peut généralement compter les syllabes d''un mot avant d''être capable d''isoler les phonèmes. C''est pourquoi l''enseignement commence par les syllabes avant de passer aux phonèmes.', 'Croire que la conscience phonémique est innée ou qu''elle se développe au même rythme que la conscience syllabique.', 'valide', 'CRPE Français V3', 'free', true),

('c30a0000-0000-0000-0000-000000000003', 'Francais', 'didactique_francais', 'conscience_phonologique', 'Conscience phonologique', 'Intermediaire', 'qcm', 'Qu''est-ce que le principe alphabétique ?', NULL, '[{"id":"a","label":"Le fait que le français s''écrit de gauche à droite"},{"id":"b","label":"La correspondance systématique entre les phonèmes (sons) et les graphèmes (lettres ou groupes de lettres)"},{"id":"c","label":"Le nombre de lettres dans l''alphabet français"},{"id":"d","label":"La règle selon laquelle chaque mot s''écrit d''une seule façon"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'Le principe alphabétique est la compréhension que les lettres ou groupes de lettres (graphèmes) représentent des sons (phonèmes). Comprendre ce principe est une étape cruciale dans l''apprentissage de la lecture : l''élève comprend qu''il peut décoder un mot inconnu en appliquant les correspondances phonème-graphème. Ce principe est au cœur de l''enseignement phonique systématique recommandé par les programmes.', 'Confondre principe alphabétique et connaissance de l''alphabet : savoir réciter l''alphabet ne signifie pas avoir compris le principe alphabétique.', 'valide', 'CRPE Français V3', 'free', true),

('c30a0000-0000-0000-0000-000000000004', 'Francais', 'didactique_francais', 'conscience_phonologique', 'Conscience phonologique', 'Intermediaire', 'reponse_courte', 'Combien de phonèmes le français possède-t-il approximativement ?', NULL, NULL, '{"mode":"text","acceptableAnswers":["36","environ 36","36 phonèmes","35","37"]}'::jsonb, 'Le français oral possède environ 36 phonèmes (selon les linguistes et les variétés régionales, ce nombre peut varier de 35 à 37) : 16 voyelles (dont les nasales, les semi-voyelles) et environ 20 consonnes. Ce chiffre contraste avec les 26 lettres de l''alphabet, illustrant la complexité du système phonème-graphème du français où un même phonème peut avoir plusieurs graphies.', 'Répondre «26» en confondant le nombre de lettres de l''alphabet et le nombre de phonèmes.', 'valide', 'CRPE Français V3', 'free', true),

('c30a0000-0000-0000-0000-000000000005', 'Francais', 'didactique_francais', 'conscience_phonologique', 'Conscience phonologique', 'Intermediaire', 'qcm', 'Lequel de ces exercices développe spécifiquement la conscience phonémique ?', NULL, '[{"id":"a","label":"Compter le nombre de syllabes dans le mot «papillon»"},{"id":"b","label":"Trouver des mots qui riment avec «maison»"},{"id":"c","label":"Dire quel mot on obtient si on supprime le phonème /t/ dans «train»"},{"id":"d","label":"Frapper les syllabes d''une chanson en rythme"}]'::jsonb, '{"mode":"single_choice","value":"c"}'::jsonb, 'La suppression de phonème («train» sans /t/ → «rain») est un exercice de manipulation phonémique : il exige d''isoler un phonème et de le supprimer mentalement pour produire un nouveau mot. C''est une tâche de conscience phonémique (niveau du phonème). Les options A et D relèvent de la conscience syllabique ; l''option B relève de la conscience des rimes.', 'Choisir l''option B (rimes) en la confondant avec la conscience phonémique, alors que les rimes relèvent de la conscience de la rime, un niveau intermédiaire.', 'valide', 'CRPE Français V3', 'free', true),

('c30a0000-0000-0000-0000-000000000006', 'Francais', 'didactique_francais', 'conscience_phonologique', 'Conscience phonologique', 'Intermediaire', 'vrai_faux', 'Vrai ou faux : l''approche syllabique (méthode phonique) est préconisée par les programmes officiels français pour l''enseignement de la lecture au cycle 2.', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'Les programmes de 2016 et les recommandations du Conseil Scientifique de l''Éducation Nationale (CSEN) préconisent explicitement un enseignement systématique et progressif des correspondances grapho-phonémiques (méthode phonique ou syllabique). Cette recommandation est fondée sur les recherches en sciences cognitives et en psychologie de l''apprentissage. L''approche globale (reconnaissance de mots entiers) n''est pas recommandée comme méthode principale.', 'Croire que les programmes laissent le libre choix entre toutes les méthodes sans recommandation claire.', 'valide', 'CRPE Français V3', 'free', true),

('c30a0000-0000-0000-0000-000000000007', 'Francais', 'didactique_francais', 'conscience_phonologique', 'Conscience phonologique', 'Intermediaire', 'qcm', 'Quelle est la principale difficulté de la dyslexie phonologique ?', NULL, '[{"id":"a","label":"La mémorisation du vocabulaire"},{"id":"b","label":"Le traitement des correspondances phonème-graphème et la conscience phonémique"},{"id":"c","label":"La compréhension des textes lus"},{"id":"d","label":"L''écriture des lettres en miroir"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'La dyslexie phonologique est la forme la plus fréquente de dyslexie. Elle se caractérise par un déficit du traitement phonologique : l''élève a du mal à décoder des mots nouveaux en appliquant les correspondances phonème-graphème. Cette difficulté est liée à une conscience phonémique déficitaire. La dyslexie de surface (option D partielle) touche davantage la mémorisation orthographique.', 'Choisir l''écriture en miroir, qui est un symptôme fréquemment cité mais non spécifique : de nombreux jeunes enfants sans dyslexie écrivent en miroir.', 'valide', 'CRPE Français V3', 'free', true),

('c30a0000-0000-0000-0000-000000000008', 'Francais', 'didactique_francais', 'conscience_phonologique', 'Conscience phonologique', 'Intermediaire', 'reponse_courte', 'Donnez un exemple d''exercice de conscience syllabique adapté à des élèves de grande section de maternelle.', NULL, NULL, '{"mode":"text","acceptableAnswers":["segmenter","compter les syllabes","frapper les syllabes","trouver des mots avec la même syllabe","supprimer une syllabe","jeu des prénoms"]}'::jsonb, 'Un exercice de conscience syllabique en GS : frapper dans les mains le nombre de syllabes d''un prénom (Ma-rie = 2 frappes), segmenter des mots en syllabes orales, trouver d''autres mots qui commencent ou finissent par la même syllabe, ou supprimer une syllabe (ba-teau sans ba → teau). Ces activités développent la capacité à percevoir les syllabes comme des unités discrètes.', 'Proposer un exercice de reconnaissance de lettres ou de phonèmes qui relève d''un autre niveau de conscience phonologique.', 'valide', 'CRPE Français V3', 'free', true),

('c30a0000-0000-0000-0000-000000000009', 'Francais', 'didactique_francais', 'conscience_phonologique', 'Conscience phonologique', 'Intermediaire', 'vrai_faux', 'Vrai ou faux : en français, un même phonème peut s''écrire avec des graphèmes différents (ex : le son /o/ peut s''écrire «o», «au», «eau»).', NULL, NULL, '{"mode":"boolean","value":true}'::jsonb, 'Le français est une langue à orthographe profonde (ou opaque) : les correspondances phonème-graphème ne sont pas biunivoques. Le phonème /o/ peut être représenté par les graphèmes o, au, eau, ô (beau, chaud, dos). Inversement, le graphème «e» peut représenter plusieurs phonèmes (/e/, /ε/, /ə/ ou rester muet). C''est cette complexité qui rend l''apprentissage du code alphabétique difficile en français.', 'Confondre avec l''anglais ou d''autres langues à orthographe encore plus opaque, en minimisant la complexité du français.', 'valide', 'CRPE Français V3', 'free', true),

('c30a0000-0000-0000-0000-00000000000a', 'Francais', 'didactique_francais', 'conscience_phonologique', 'Conscience phonologique', 'Intermediaire', 'qcm', 'Quelle est la principale critique adressée à la méthode globale d''apprentissage de la lecture ?', NULL, '[{"id":"a","label":"Elle est trop lente et ne permet pas d''acquérir un vocabulaire suffisant"},{"id":"b","label":"Elle ne développe pas le décodage phonémique et surcharge la mémoire visuelle"},{"id":"c","label":"Elle favorise les élèves issus de milieux favorisés"},{"id":"d","label":"Elle exige trop de matériel pédagogique coûteux"}]'::jsonb, '{"mode":"single_choice","value":"b"}'::jsonb, 'La méthode globale (ou idéovisuelle) apprend aux élèves à reconnaître les mots comme des images visuelles, sans passer par le décodage phonémique. La critique principale fondée sur la recherche en sciences cognitives est qu''elle ne permet pas de développer le mécanisme de décodage (voie phonologique) essentiel pour lire des mots nouveaux. Elle surcharge la mémoire visuelle et pénalise les élèves qui n''ont pas une conscience phonémique forte.', 'Choisir l''option C (inégalités sociales) qui est un argument politique, non la critique scientifique principale de la méthode globale.', 'valide', 'CRPE Français V3', 'free', true)
;
